// === Collapsible Navigation Sections ===
function toggleNavSection(headerBtn) {
  const section = headerBtn.closest('.nav-section-collapsible');
  const body = section.querySelector('.nav-section-body');
  const isOpen = body.classList.contains('open');
  
  if (isOpen) {
    body.classList.remove('open');
    headerBtn.setAttribute('aria-expanded', 'false');
  } else {
    body.classList.add('open');
    headerBtn.setAttribute('aria-expanded', 'true');
  }
  
  const sectionKey = section.dataset.section;
  if (sectionKey) {
    try {
      const state = JSON.parse(localStorage.getItem('sidebarSections') || '{}');
      state[sectionKey] = !isOpen;
      localStorage.setItem('sidebarSections', JSON.stringify(state));
    } catch(e) {}
  }
}

function restoreSidebarSections() {
  try {
    const state = JSON.parse(localStorage.getItem('sidebarSections') || '{}');
    document.querySelectorAll('.nav-section-collapsible').forEach(section => {
      const key = section.dataset.section;
      const body = section.querySelector('.nav-section-body');
      const header = section.querySelector('.nav-section-header');
      if (!body || !header) return;
      
      if (key && state[key] === false) {
        body.classList.remove('open');
        header.setAttribute('aria-expanded', 'false');
      } else {
        body.classList.add('open');
        header.setAttribute('aria-expanded', 'true');
      }
    });
  } catch(e) {}
}

// === Sidebar Search ===
function initSidebarSearch() {
  const searchInput = document.getElementById('sidebar-search');
  if (!searchInput) return;
  
  searchInput.addEventListener('input', function() {
    const query = this.value.toLowerCase().trim();
    
    if (!query) {
      document.querySelectorAll('.nav-item').forEach(item => {
        item.classList.remove('search-hidden');
        const span = item.querySelector('span');
        if (span) span.innerHTML = span.textContent;
      });
      document.querySelectorAll('.nav-section-collapsible').forEach(s => {
        s.classList.remove('search-hidden');
      });
      restoreSidebarSections();
      return;
    }
    
    document.querySelectorAll('.nav-section-collapsible').forEach(section => {
      const items = section.querySelectorAll('.nav-item');
      let hasVisible = false;
      
      items.forEach(item => {
        const span = item.querySelector('span');
        if (!span) return;
        const text = span.textContent.toLowerCase();
        
        if (text.includes(query)) {
          item.classList.remove('search-hidden');
          hasVisible = true;
          const regex = new RegExp('(' + query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + ')', 'gi');
          span.innerHTML = span.textContent.replace(regex, '<mark class="sidebar-search-highlight">$1</mark>');
        } else {
          item.classList.add('search-hidden');
          span.innerHTML = span.textContent;
        }
      });
      
      if (hasVisible) {
        section.classList.remove('search-hidden');
        const body = section.querySelector('.nav-section-body');
        if (body) body.classList.add('open');
        const header = section.querySelector('.nav-section-header');
        if (header) header.setAttribute('aria-expanded', 'true');
      } else {
        section.classList.add('search-hidden');
      }
    });
    
    const dashboardItem = document.querySelector('.nav-item[data-page="dashboard"]');
    if (dashboardItem) {
      const text = dashboardItem.querySelector('span')?.textContent.toLowerCase() || '';
      if (text.includes(query)) {
        dashboardItem.classList.remove('search-hidden');
      } else {
        dashboardItem.classList.add('search-hidden');
      }
    }
  });
  
  document.addEventListener('keydown', function(e) {
    if (e.key === '/' && !['INPUT', 'TEXTAREA', 'SELECT'].includes(document.activeElement?.tagName)) {
      e.preventDefault();
      searchInput.focus();
    }
    if (e.key === 'Escape' && document.activeElement === searchInput) {
      searchInput.value = '';
      searchInput.dispatchEvent(new Event('input'));
      searchInput.blur();
    }
  });
}

window.toggleNavSection = toggleNavSection;

function togglePasswordVisibility() {
  const pwInput = document.getElementById('password');
  const eyeIcon = document.getElementById('eye-icon');
  const eyeOffIcon = document.getElementById('eye-off-icon');
  if (pwInput.type === 'password') {
    pwInput.type = 'text';
    eyeIcon.style.display = 'none';
    eyeOffIcon.style.display = 'block';
  } else {
    pwInput.type = 'password';
    eyeIcon.style.display = 'block';
    eyeOffIcon.style.display = 'none';
  }
}

