let currentUser = null;
let selectedOrgFilter = localStorage.getItem('selectedOrgFilter') || '';
let availableOrganizations = [];

function adminFetch(url, options = {}) {
  const opts = { ...options};
  if (adminAuthToken) {
    opts.headers = { ...(opts.headers || {}), 'Authorization': `Bearer ${adminAuthToken}` };
  }
  if (selectedOrgFilter && currentUserInfo?.isFullAdmin) {
    const separator = url.includes('?') ? '&' : '?';
    url = `${url}${separator}organizationFilter=${encodeURIComponent(selectedOrgFilter)}`;
  }
  return fetch(url, opts);
}
