// Open Partner Proposal page on port 5000
function openPartnerProposalPage() {
  const currentHost = window.location.hostname;
  let targetUrl;
  
  if (currentHost.includes('.replit.dev') || currentHost.includes('.repl.co')) {
    targetUrl = window.location.origin.replace(/:\d+/, '') + ':5000/partner-proposal';
    if (!targetUrl.includes(':5000')) {
      const protocol = window.location.protocol;
      targetUrl = `${protocol}//${currentHost}:5000/partner-proposal`;
    }
  } else {
    targetUrl = 'http://localhost:5000/partner-proposal';
  }
  
  window.open(targetUrl, '_blank');
  return false;
}
window.openPartnerProposalPage = openPartnerProposalPage;

