function renderInvitedUsersSection(invitedUsers) {
  const section = document.getElementById('invited-users-section');
  if (!section) return;

  if (!invitedUsers || invitedUsers.length === 0) {
    section.innerHTML = '';
    return;
  }

  const statusConfig = {
    pending: { label: 'In attesa', bg: '#FEF3C7', color: '#92400E', border: '#F59E0B' },
    accepted: { label: 'Accettato', bg: '#D1FAE5', color: '#065F46', border: '#10B981' },
    expired: { label: 'Scaduto', bg: '#FEE2E2', color: '#991B1B', border: '#EF4444' },
  };

  let html = `
    <div class="credentials-location-group">
      <div class="credentials-location-header">
        <div class="credentials-location-title">
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="8.5" cy="7" r="4"/><line x1="20" y1="8" x2="20" y2="14"/><line x1="23" y1="11" x2="17" y2="11"/></svg>
          <span>Utenti Invitati</span>
          <span class="credentials-location-count">${invitedUsers.length} utenti</span>
        </div>
        <button class="btn btn-sm btn-outline" onclick="downloadAllInvitedUsersPDF()">
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
          Scarica Tutti
        </button>
      </div>
      <div class="credentials-vehicle-list">`;

  for (const u of invitedUsers) {
    const st = statusConfig[u.status] || statusConfig.pending;
    const createdDate = u.createdAt ? new Date(u.createdAt).toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric' }) : '-';
    const safeName = (u.name || '').replace(/'/g, "\\'");
    const safeEmail = (u.email || '').replace(/'/g, "\\'");

    html += `<div class="credentials-vehicle-card">
      <div class="credentials-vehicle-info">
        <div class="credentials-vehicle-code" style="display: flex; align-items: center; gap: 10px;">
          ${safeName}
          <span style="display:inline-block;padding:2px 8px;border-radius:6px;font-size:11px;font-weight:600;background:${st.bg};color:${st.color};border:1px solid ${st.border};">${st.label}</span>
        </div>
        <div class="credentials-vehicle-details">
          <span class="credentials-label">Email:</span> <span class="credentials-value">${u.email}</span>
        </div>
        <div class="credentials-vehicle-details">
          <span class="credentials-label">Password:</span> <span class="credentials-value credentials-password">${u.temporaryPassword}</span>
        </div>
        <div class="credentials-vehicle-details">
          <span class="credentials-label">Ruolo:</span> <span class="credentials-value" style="color:${u.roleColor || '#6B7280'};font-weight:600;">${u.roleName}</span>
        </div>
        <div class="credentials-vehicle-details">
          <span class="credentials-label">Creato il:</span> <span class="credentials-value">${createdDate}</span>
        </div>
      </div>
      <div class="credentials-actions">
        <button class="btn btn-sm btn-ghost" onclick="downloadInvitedUserPDF('${u.id}', '${safeName}')" title="Scarica PDF">
          <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/></svg>
        </button>
      </div>
    </div>`;
  }

  html += '</div></div>';
  section.innerHTML = html;
}

function downloadInvitedUserPDF(invitationId, userName) {
  showNotification('Generazione PDF...', 'info');
  adminFetch(`/api/reports/invited-user-credentials-pdf?invitationId=${invitationId}`)
    .then(response => {
      if (!response.ok) throw new Error('Errore nella generazione del PDF');
      return response.blob();
    })
    .then(blob => {
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      const safeName = (userName || 'utente').replace(/\s+/g, '_');
      a.download = `credenziale_${safeName}_${getItalianDate()}.pdf`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      a.remove();
      showNotification('PDF scaricato!', 'success');
    })
    .catch(error => {
      showNotification('Errore: ' + error.message, 'error');
    });
}
window.downloadInvitedUserPDF = downloadInvitedUserPDF;

