function openCredentialModal() {
  document.getElementById('credential-modal-title').textContent = 'Nuovo Account Veicolo';
  document.getElementById('cred-email').value = '';
  document.getElementById('cred-password').value = '';
  document.getElementById('cred-name').value = '';
  document.getElementById('cred-edit-user-id').value = '';
  
  const select = document.getElementById('cred-vehicle-select');
  select.innerHTML = '<option value="">Seleziona veicolo...</option>';
  select.disabled = false;
  for (const v of _credVehiclesData) {
    select.innerHTML += `<option value="${v.id}" data-code="${v.code}" data-plate="${v.licensePlate || ''}">${v.code} - ${v.licensePlate || 'Senza targa'} (${v.locationName})</option>`;
  }
  
  document.getElementById('credential-modal').classList.remove('hidden');
}
window.openCredentialModal = openCredentialModal;

function openEditCredentialModal(userId, vehicleId, email, password, name) {
  document.getElementById('credential-modal-title').textContent = 'Modifica Account';
  document.getElementById('cred-email').value = email;
  document.getElementById('cred-password').value = password;
  document.getElementById('cred-name').value = name;
  document.getElementById('cred-edit-user-id').value = userId;
  
  const select = document.getElementById('cred-vehicle-select');
  select.innerHTML = '<option value="">Seleziona veicolo...</option>';
  
  const allVehicles = [..._credVehiclesData];
  let found = false;
  for (const loc of _credLocationsData) {
    for (const v of loc.vehicles) {
      if (v.vehicleId === vehicleId) {
        allVehicles.push({ id: v.vehicleId, code: v.vehicleCode, licensePlate: v.licensePlate, locationName: loc.name });
        found = true;
      }
    }
  }
  
  for (const v of allVehicles) {
    const selected = v.id === vehicleId ? 'selected' : '';
    select.innerHTML += `<option value="${v.id}" data-code="${v.code}" data-plate="${v.licensePlate || ''}" ${selected}>${v.code} - ${v.licensePlate || 'Senza targa'} (${v.locationName})</option>`;
  }
  
  document.getElementById('credential-modal').classList.remove('hidden');
}
window.openEditCredentialModal = openEditCredentialModal;

function closeCredentialModal() {
  document.getElementById('credential-modal').classList.add('hidden');
}
window.closeCredentialModal = closeCredentialModal;

function onCredVehicleChange() {
  const select = document.getElementById('cred-vehicle-select');
  const opt = select.selectedOptions[0];
  if (opt && opt.value) {
    const code = opt.dataset.code || '';
    const codeClean = code.replace(/\s+/g, '').toLowerCase();
    const emailDomain = (currentUserInfo && currentUserInfo.email) ? currentUserInfo.email.split('@')[1] : 'soccorsodigitale.app';
    document.getElementById('cred-email').value = `${codeClean}@${emailDomain}`;
    document.getElementById('cred-name').value = `Equipaggio ${code}`;
  }
}
window.onCredVehicleChange = onCredVehicleChange;

function generateCredPassword() {
  const select = document.getElementById('cred-vehicle-select');
  const opt = select.selectedOptions[0];
  const code = opt && opt.value ? opt.dataset.code.replace(/\s+/g, '') : 'Veicolo';
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789!@#';
  let suffix = '';
  for (let i = 0; i < 4; i++) suffix += chars[Math.floor(Math.random() * chars.length)];
  document.getElementById('cred-password').value = `${code}${suffix}!`;
}
window.generateCredPassword = generateCredPassword;

function saveCredential() {
  const vehicleId = document.getElementById('cred-vehicle-select').value;
  const email = document.getElementById('cred-email').value.trim();
  const password = document.getElementById('cred-password').value.trim();
  const name = document.getElementById('cred-name').value.trim();
  const editUserId = document.getElementById('cred-edit-user-id').value;
  
  if (!vehicleId || !email || !password) {
    showNotification('Compila tutti i campi obbligatori (veicolo, email, password)', 'error');
    return;
  }
  
  const payload = { vehicleId, email, password, name: name || `Equipaggio ${email.split('@')[0].toUpperCase()}` };
  
  if (editUserId) {
    adminFetch(`/api/admin/credentials/${editUserId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
    .then(r => r.json())
    .then(data => {
      if (data.error) throw new Error(data.error);
      showNotification('Account aggiornato con successo!', 'success');
      closeCredentialModal();
      loadCredentialsPage();
    })
    .catch(err => showNotification('Errore: ' + err.message, 'error'));
  } else {
    adminFetch('/api/admin/credentials', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    })
    .then(r => r.json())
    .then(data => {
      if (data.error) throw new Error(data.error);
      showNotification('Account creato con successo!', 'success');
      closeCredentialModal();
      loadCredentialsPage();
    })
    .catch(err => showNotification('Errore: ' + err.message, 'error'));
  }
}
