// Toast notification system
function showNotification(message, type = 'info') {
  // Remove existing notification if any
  const existing = document.querySelector('.toast-notification');
  if (existing) existing.remove();
  
  const toast = document.createElement('div');
  toast.className = `toast-notification toast-${type}`;
  toast.innerHTML = `
    <span class="toast-message">${message}</span>
    <button class="toast-close" onclick="this.parentElement.remove()">&times;</button>
  `;
  
  // Add styles if not already present
  if (!document.getElementById('toast-styles')) {
    const style = document.createElement('style');
    style.id = 'toast-styles';
    style.textContent = `
      .toast-notification {
        position: fixed;
        bottom: 20px;
        right: 20px;
        padding: 14px 24px;
        border-radius: 12px;
        color: white;
        font-weight: 600;
        display: flex;
        align-items: center;
        gap: 12px;
        z-index: 999999;
        animation: slideIn 0.3s ease;
        box-shadow: 0 8px 32px rgba(0,0,0,0.3);
        backdrop-filter: blur(8px);
        max-width: 400px;
      }
      .toast-success { background: #22c55e; }
      .toast-error { background: #ef4444; }
      .toast-warning { background: #f59e0b; }
      .toast-info { background: #3b82f6; }
      .toast-close {
        background: none;
        border: none;
        color: white;
        font-size: 18px;
        cursor: pointer;
        opacity: 0.8;
      }
      .toast-close:hover { opacity: 1; }
      @keyframes slideIn {
        from { transform: translateX(100%); opacity: 0; }
        to { transform: translateX(0); opacity: 1; }
      }
    `;
    document.head.appendChild(style);
  }
  
  document.body.appendChild(toast);
  
  // Auto-remove after 4 seconds
  setTimeout(() => {
    if (toast.parentElement) {
      toast.style.animation = 'slideIn 0.3s ease reverse';
      setTimeout(() => toast.remove(), 300);
    }
  }, 4000);
}

// Animated counter with easing
function animateCounter(element, targetValue, duration = 1500, prefix = '', suffix = '') {
  if (!element) return;
  
  const startValue = parseInt(element.dataset.currentValue) || 0;
  const startTime = performance.now();
  const difference = targetValue - startValue;
  
  function easeOutQuart(t) {
    return 1 - Math.pow(1 - t, 4);
  }
  
  function update(currentTime) {
    const elapsed = currentTime - startTime;
    const progress = Math.min(elapsed / duration, 1);
    const easedProgress = easeOutQuart(progress);
    const currentValue = Math.round(startValue + (difference * easedProgress));
    
    element.textContent = prefix + currentValue.toLocaleString('it-IT') + suffix;
    element.dataset.currentValue = currentValue;
    
    if (progress < 1) {
      requestAnimationFrame(update);
    } else {
      element.classList.add('counter-complete');
      setTimeout(() => element.classList.remove('counter-complete'), 300);
    }
  }
  
  requestAnimationFrame(update);
}

// Create mini sparkline chart
function createSparkline(containerId, data, color = '#0066CC') {
  const container = document.getElementById(containerId);
  if (!container) return null;
  
  // Clear existing
  container.innerHTML = '';
  
  const canvas = document.createElement('canvas');
  canvas.style.width = '100%';
  canvas.style.height = '100%';
  container.appendChild(canvas);
  
  const ctx = canvas.getContext('2d');
  if (!ctx) return null;
  
  // High DPI support
  const dpr = window.devicePixelRatio || 1;
  const rect = container.getBoundingClientRect();
  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.scale(dpr, dpr);
  
  const width = rect.width;
  const height = rect.height;
  const padding = 2;
  
  if (data.length < 2) return null;
  
  const max = Math.max(...data);
  const min = Math.min(...data);
  const range = max - min || 1;
  
  const stepX = (width - padding * 2) / (data.length - 1);
  
  // Draw gradient fill
  const gradient = ctx.createLinearGradient(0, 0, 0, height);
  gradient.addColorStop(0, color + '40');
  gradient.addColorStop(1, color + '00');
  
  ctx.beginPath();
  ctx.moveTo(padding, height - padding);
  
  data.forEach((value, i) => {
    const x = padding + i * stepX;
    const y = height - padding - ((value - min) / range) * (height - padding * 2);
    ctx.lineTo(x, y);
  });
  
  ctx.lineTo(width - padding, height - padding);
  ctx.closePath();
  ctx.fillStyle = gradient;
  ctx.fill();
  
  // Draw line
  ctx.beginPath();
  data.forEach((value, i) => {
    const x = padding + i * stepX;
    const y = height - padding - ((value - min) / range) * (height - padding * 2);
    if (i === 0) ctx.moveTo(x, y);
    else ctx.lineTo(x, y);
  });
  
  ctx.strokeStyle = color;
  ctx.lineWidth = 2;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.stroke();
  
  // Draw end point
  const lastX = width - padding;
  const lastY = height - padding - ((data[data.length - 1] - min) / range) * (height - padding * 2);
  ctx.beginPath();
  ctx.arc(lastX, lastY, 3, 0, Math.PI * 2);
  ctx.fillStyle = color;
  ctx.fill();
  ctx.beginPath();
  ctx.arc(lastX, lastY, 5, 0, Math.PI * 2);
  ctx.strokeStyle = color + '60';
  ctx.lineWidth = 2;
  ctx.stroke();
  
  return canvas;
}

// Calculate trend data for sparklines
function calculateTrendData(trips, days = 7) {
  const now = new Date();
  const data = [];
  
  for (let i = days - 1; i >= 0; i--) {
    const date = new Date(now);
    date.setDate(date.getDate() - i);
    const dayStart = new Date(date.setHours(0, 0, 0, 0));
    const dayEnd = new Date(date.setHours(23, 59, 59, 999));
    
    const dayTrips = trips.filter(t => {
      const tripDate = new Date(t.serviceDate || t.createdAt);
      return tripDate >= dayStart && tripDate <= dayEnd;
    });
    
    data.push(dayTrips.length);
  }
  
  return data;
}

function calculateKmTrendData(trips, days = 7) {
  const now = new Date();
  const data = [];
  
  for (let i = days - 1; i >= 0; i--) {
    const date = new Date(now);
    date.setDate(date.getDate() - i);
    const dayStart = new Date(date.setHours(0, 0, 0, 0));
    const dayEnd = new Date(date.setHours(23, 59, 59, 999));
    
    const dayKm = trips
      .filter(t => {
        const tripDate = new Date(t.serviceDate || t.createdAt);
        return tripDate >= dayStart && tripDate <= dayEnd;
      })
      .reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
    
    data.push(dayKm);
  }
  
  return data;
}

// Calculate percentage change
function calculateChange(current, previous) {
  if (previous === 0) return current > 0 ? 100 : 0;
  return Math.round(((current - previous) / previous) * 100);
}

document.addEventListener('DOMContentLoaded', () => {
  initApp();
});

function initApp() {
  setupEventListeners();

  const urlParams = new URLSearchParams(window.location.search);
  if (urlParams.get('payment') === 'success') {
    const moduleKey = urlParams.get('module');
    showNotification(`Modulo ${moduleKey || ''} attivato con successo! La pagina si aggiornerà.`, 'success');
    window.history.replaceState({}, document.title, window.location.pathname);
    setTimeout(() => window.location.reload(), 2000);
  }

  const navEntries = performance.getEntriesByType('navigation');
  const navType = navEntries.length > 0 ? navEntries[0].type : 'navigate';

  if (navType !== 'reload') {
    localStorage.removeItem('adminUser');
    localStorage.removeItem('adminAuthToken');
    localStorage.removeItem('selectedOrgFilter');
    localStorage.removeItem('adminCurrentPage');
    localStorage.removeItem('userInfo');
    currentUser = null;
    currentUserInfo = null;
    adminAuthToken = null;
    selectedOrgFilter = '';
    showLogin();
    return;
  }

  checkAuthState();
}

