function populateFilters() {
  const locationSelects = ['filter-location', 'utif-location'];
  const vehicleSelects = ['filter-vehicle', 'utif-vehicle'];

  locationSelects.forEach(id => {
    const select = document.getElementById(id);
    if (select) {
      select.innerHTML = '<option value="">Tutte le sedi</option>';
      locations.forEach(loc => {
        select.innerHTML += `<option value="${loc.id}">${loc.name}</option>`;
      });
    }
  });

  vehicleSelects.forEach(id => {
    const select = document.getElementById(id);
    if (select) {
      select.innerHTML = '<option value="">Tutti i veicoli</option>';
      vehicles.forEach(veh => {
        select.innerHTML += `<option value="${veh.id}">${veh.code}</option>`;
      });
    }
  });
}

function buildFleetTree() {
  const container = document.getElementById('fleet-tree');
  if (!container) return;
  
  const vehiclesByLocation = {};
  locations.forEach(loc => {
    vehiclesByLocation[loc.id] = vehicles.filter(v => v.locationId === loc.id);
  });
  
  let activeCount = 0;
  let idleCount = 0;
  
  container.innerHTML = locations.map(loc => {
    const locVehicles = vehiclesByLocation[loc.id] || [];
    const vehiclesHtml = locVehicles.map(v => {
      const vTrips = trips.filter(t => t.vehicleId === v.id);
      const lastTrip = vTrips.length > 0 ? new Date(vTrips[0].createdAt) : null;
      const isActive = lastTrip && (Date.now() - lastTrip.getTime()) < 86400000;
      if (isActive) activeCount++; else idleCount++;
      
      return `
        <div class="fleet-vehicle" data-vehicle-id="${v.id}">
          <span class="vehicle-status-dot ${isActive ? 'active' : 'inactive'}"></span>
          <span class="vehicle-code">${v.code}</span>
          <span class="vehicle-km">${(v.currentKm || 0).toLocaleString('it-IT')} km</span>
        </div>
      `;
    }).join('');
    
    return `
      <div class="fleet-location" data-location-id="${loc.id}">
        <div class="fleet-location-header">
          <div class="fleet-location-icon">
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="m9 18 6-6-6-6"/></svg>
          </div>
          <span class="fleet-location-name">${loc.name}</span>
          <span class="fleet-location-count">${locVehicles.length}</span>
        </div>
        <div class="fleet-vehicles">${vehiclesHtml}</div>
      </div>
    `;
  }).join('');
  
  document.getElementById('active-count').textContent = activeCount;
  document.getElementById('idle-count').textContent = idleCount;
  
  container.querySelectorAll('.fleet-location-header').forEach(header => {
    header.addEventListener('click', () => {
      header.parentElement.classList.toggle('expanded');
    });
  });
  
  container.querySelectorAll('.fleet-vehicle').forEach(veh => {
    veh.addEventListener('click', (e) => {
      e.stopPropagation();
      const vehicleId = veh.dataset.vehicleId;
      showVehicleDetail(vehicleId);
    });
  });
}

function filterFleetTree() {
  const query = document.getElementById('fleet-search').value.toLowerCase();
  document.querySelectorAll('.fleet-vehicle').forEach(veh => {
    const code = veh.querySelector('.vehicle-code').textContent.toLowerCase();
    veh.style.display = code.includes(query) ? 'flex' : 'none';
  });
  
  if (query) {
    document.querySelectorAll('.fleet-location').forEach(loc => {
      loc.classList.add('expanded');
    });
  }
}

// Dashboard state
let dashboardPeriod = 90;
let dashboardLocationId = '';
let dashboardCustomDateFrom = '';
let dashboardCustomDateTo = '';
let trendChart = null;
let locationChart = null;
let dashboardDailyData = []; // Store for chart tab switching

async function updateDashboard() {
  // Populate location filter dropdown
  const locationSelect = document.getElementById('dash-location-filter');
  if (locationSelect && locations.length > 0) {
    locationSelect.innerHTML = '<option value="">Tutte le Sedi</option>' +
      locations.map(loc => `<option value="${loc.id}">${loc.name}</option>`).join('');
    locationSelect.value = dashboardLocationId;
  }
  
  // Setup filter event listeners (only once)
  if (!window.dashFilterSetup) {
    window.dashFilterSetup = true;
    
    const dateRangeEl = document.getElementById('dash-date-range');
    const dateFromEl = document.getElementById('dash-date-from');
    const dateToEl = document.getElementById('dash-date-to');
    const dateApplyBtn = document.getElementById('dash-date-apply');
    
    // Set default dates for custom range
    const today = new Date();
    const thirtyDaysAgo = new Date(today);
    thirtyDaysAgo.setDate(today.getDate() - 30);
    if (dateFromEl) dateFromEl.value = thirtyDaysAgo.toISOString().split('T')[0];
    if (dateToEl) dateToEl.value = today.toISOString().split('T')[0];
    
    document.querySelectorAll('.dash-filter-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('.dash-filter-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        
        const period = btn.dataset.period;
        if (period === 'custom') {
          // Show custom date range inputs
          dateRangeEl?.classList.remove('hidden');
          dashboardPeriod = 0;
        } else {
          // Hide custom date range, use preset period
          dateRangeEl?.classList.add('hidden');
          dashboardPeriod = parseInt(period) || 7;
          dashboardCustomDateFrom = '';
          dashboardCustomDateTo = '';
          loadDashboardMetrics();
        }
      });
    });
    
    // Apply custom date range
    dateApplyBtn?.addEventListener('click', () => {
      dashboardCustomDateFrom = dateFromEl?.value || '';
      dashboardCustomDateTo = dateToEl?.value || '';
      if (dashboardCustomDateFrom && dashboardCustomDateTo) {
        dashboardPeriod = 0; // Custom mode
        loadDashboardMetrics();
      }
    });
    
    locationSelect?.addEventListener('change', () => {
      dashboardLocationId = locationSelect.value;
      loadDashboardMetrics();
    });
    
    // Chart view tabs (Giorno/Settimana/Mese)
    document.querySelectorAll('.chart-tab').forEach(tab => {
      tab.addEventListener('click', () => {
        document.querySelectorAll('.chart-tab').forEach(t => t.classList.remove('active'));
        tab.classList.add('active');
        const view = tab.dataset.view;
        updateTrendChartView(view);
      });
    });
  }
  
  await loadDashboardMetrics();
  loadEnvironmentalIntelligence(); // Non-blocking: runs in parallel

  // Keep legacy elements updated for backwards compatibility
  const totalTrips = trips.length;
  const totalKm = trips.reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
  const totalVehicles = vehicles.length;
  const totalLocations = locations.length;
  animateCounter(document.getElementById('total-trips'), totalTrips);
  animateCounter(document.getElementById('total-km'), totalKm);
  animateCounter(document.getElementById('total-vehicles'), totalVehicles);
  animateCounter(document.getElementById('total-locations'), totalLocations);
  previousStats = { trips: totalTrips, km: totalKm, vehicles: totalVehicles, locations: totalLocations };
}

async function loadDashboardMetrics() {
  try {
    const params = new URLSearchParams();
    
    // Use custom date range if set, otherwise use period
    if (dashboardCustomDateFrom && dashboardCustomDateTo) {
      params.append('dateFrom', dashboardCustomDateFrom);
      params.append('dateTo', dashboardCustomDateTo);
    } else {
      params.append('days', dashboardPeriod.toString());
    }
    
    if (dashboardLocationId) params.append('locationId', dashboardLocationId);
    
    const response = await adminFetch(`/api/dashboard/metrics?${params}`);
    if (!response.ok) throw new Error('Failed to load dashboard metrics');
    
    const data = await response.json();
    
    // Update KPIs
    updateKpiCard('kpi-total-services', data.kpis.totalServices);
    updateKpiTrend('kpi-services-trend', data.kpis.servicesChange);
    updateKpiCard('kpi-total-km', data.kpis.totalKm);
    updateKpiTrend('kpi-km-trend', data.kpis.kmChange);
    
    const avgDurationDisplay = data.kpis.avgDuration > 0 
      ? `${Math.floor(data.kpis.avgDuration / 60)}:${String(data.kpis.avgDuration % 60).padStart(2, '0')}`
      : '00:00';
    document.getElementById('kpi-avg-duration').textContent = avgDurationDisplay;
    updateKpiTrend('kpi-duration-trend', data.kpis.durationChange);
    
    document.getElementById('kpi-avg-km').textContent = data.kpis.avgKmPerService.toFixed(1);
    updateKpiTrend('kpi-avgkm-trend', data.kpis.avgKmChange);
    
    document.getElementById('kpi-active-vehicles').textContent = data.kpis.activeVehicles;
    document.getElementById('kpi-active-crews').textContent = data.kpis.activeCrews;
    
    // Store and update trend chart
    dashboardDailyData = data.dailyTrend;
    renderTrendChart(data.dailyTrend);
    
    // Update hourly heatmap
    renderHourlyHeatmap(data.hourlyHeatmap);
    
    // Update fleet table
    renderFleetTable(data.fleetStatus);
    
    // Update location performance chart
    renderLocationChart(data.locationPerformance);
    
    // Update data quality metrics
    document.getElementById('quality-complete').textContent = `${data.dataQuality.completionRate}%`;
    document.getElementById('quality-missing').textContent = `${data.dataQuality.missingRate}%`;
    document.getElementById('quality-anomalies').textContent = data.dataQuality.anomalyCount;
    document.getElementById('quality-avg-time').textContent = data.dataQuality.avgEntryTime;
    
    // Update new quality score elements if they exist
    const overallScoreEl = document.getElementById('quality-overall-score');
    const coherenceScoreEl = document.getElementById('quality-coherence-score');
    if (overallScoreEl) overallScoreEl.textContent = `${data.dataQuality.overallScore || 0}`;
    if (coherenceScoreEl) coherenceScoreEl.textContent = `${data.dataQuality.coherenceScore || 0}%`;
    
    // Update KPIs in location panel
    document.getElementById('kpi-completion-rate').textContent = `+${data.dataQuality.completionRate}%`;
    document.getElementById('kpi-missing-rate').textContent = `-${data.dataQuality.missingRate}%`;
    document.getElementById('kpi-anomaly-rate').textContent = 
      data.dataQuality.anomalyCount === 0 ? '+100%' : `-${Math.min(data.dataQuality.anomalyCount * 5, 100)}%`;
    
    // Update last update time
    const updateTime = new Date(data.lastUpdate);
    document.getElementById('dash-last-update').textContent = 
      updateTime.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
    
  } catch (error) {
    console.error('Dashboard metrics error:', error);
  }
}

// ============================================================
// SUPER ADMIN — PLATFORM MODE / SUPPORT MODE
// ============================================================

function applySuperAdminMode(orgFilter, selectedOrg) {
  const isFullAdmin = currentUserInfo?.isFullAdmin;
  if (!isFullAdmin) return;

  const opNav = document.getElementById('operational-nav');
  const platNav = document.getElementById('platform-nav');
  const banner = document.getElementById('support-mode-banner');
  const brandSubtitle = document.getElementById('brand-subtitle');

  if (orgFilter && selectedOrg) {
    // SUPPORT MODE: specific org selected
    if (opNav) opNav.style.display = '';
    if (platNav) platNav.style.display = 'none';
    if (banner) {
      banner.style.display = '';
      const orgNameEl = document.getElementById('smb-org-name');
      if (orgNameEl) orgNameEl.textContent = selectedOrg.name;
    }
    document.body.classList.remove('sa-platform-mode');
    document.body.classList.add('sa-support-mode');
    if (brandSubtitle) brandSubtitle.textContent = selectedOrg.name;
  } else {
    // PLATFORM MODE: all orgs
    if (opNav) opNav.style.display = 'none';
    if (platNav) platNav.style.display = '';
    if (banner) banner.style.display = 'none';
    document.body.classList.add('sa-platform-mode');
    document.body.classList.remove('sa-support-mode');
    if (brandSubtitle) brandSubtitle.textContent = 'Platform Admin';
  }
}

function exitSupportMode() {
  const select = document.getElementById('org-filter-select');
  if (select) {
    select.value = '';
    onOrgFilterChange();
  }
}

