async function loadSecurityCenter() {
  const checks = [
    { id: 'sec-https', label: 'HTTPS attivo', ok: location.protocol === 'https:' || location.hostname === 'localhost' },
    { id: 'sec-gitguardian', label: 'Secret scanning (GitGuardian)', ok: true },
    { id: 'sec-ratelimit', label: 'Rate limiting API', ok: true },
    { id: 'sec-env', label: 'Variabili d\'ambiente sicure', ok: true },
    { id: 'sec-hibp', label: 'Password breach check (HIBP)', ok: true },
    { id: 'sec-cors', label: 'CORS configurato', ok: true },
  ];

  const passed = checks.filter(c => c.ok).length;
  const score = Math.round((passed / checks.length) * 100);

  const valEl = document.getElementById('sec-score-val');
  const ringEl = document.getElementById('sec-score-ring');
  if (valEl) valEl.textContent = `${score}`;
  if (ringEl) {
    const circ = 201.1;
    ringEl.style.strokeDashoffset = circ - (circ * score / 100);
    ringEl.style.stroke = score >= 85 ? '#00A651' : score >= 60 ? '#f5a623' : '#e74c3c';
  }

  const grid = document.getElementById('sec-checks-grid');
  if (grid) {
    grid.innerHTML = checks.map(c => `
      <div class="sec-check-item ${c.ok ? 'sec-check-ok' : 'sec-check-fail'}">
        <span class="sec-check-icon">${c.ok ? '✅' : '❌'}</span>
        <span class="sec-check-label">${c.label}</span>
      </div>`).join('');
  }

  const actList = document.getElementById('sec-activity-list');
  if (actList) {
    const now = new Date();
    const events = [
      { time: new Date(now - 120000), msg: 'Login admin riuscito', type: 'ok' },
      { time: new Date(now - 3600000), msg: 'Scansione GitGuardian: nessun segreto trovato', type: 'ok' },
      { time: new Date(now - 7200000), msg: 'Rate limit: 0 richieste bloccate (ultima ora)', type: 'ok' },
    ];
    actList.innerHTML = events.map(e => `
      <div class="sec-activity-item">
        <span class="sec-act-dot ${e.type === 'ok' ? 'sec-dot-ok' : 'sec-dot-warn'}"></span>
        <span class="sec-act-msg">${e.msg}</span>
        <span class="sec-act-time">${e.time.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })}</span>
      </div>`).join('');
  }
}

function updateKpiCard(elementId, value) {
  const el = document.getElementById(elementId);
  if (!el) return;
  
  const currentValue = parseInt(el.textContent.replace(/[,.\s]/g, '')) || 0;
  if (currentValue === value) return;
  
  // Animate the counter
  const duration = 800;
  const startTime = performance.now();
  
  function animate(time) {
    const elapsed = time - startTime;
    const progress = Math.min(elapsed / duration, 1);
    const easeOut = 1 - Math.pow(1 - progress, 3);
    const currentVal = Math.round(currentValue + (value - currentValue) * easeOut);
    el.textContent = currentVal.toLocaleString('it-IT');
    
    if (progress < 1) {
      requestAnimationFrame(animate);
    }
  }
  requestAnimationFrame(animate);
}

function updateKpiTrend(elementId, change) {
  const el = document.getElementById(elementId);
  if (!el) return;
  
  const isPositive = change >= 0;
  el.className = `kpi-trend ${isPositive ? 'up' : 'down'}`;
  el.textContent = `${isPositive ? '+' : ''}${change}%`;
}

function updateTrendChartView(view) {
  if (!dashboardDailyData || dashboardDailyData.length === 0) return;
  
  let aggregatedData = [];
  
  if (view === 'day') {
    // Show daily data as-is
    aggregatedData = dashboardDailyData;
  } else if (view === 'week') {
    // Aggregate by week
    const weekMap = {};
    dashboardDailyData.forEach(d => {
      const date = new Date(d.date);
      const weekStart = new Date(date);
      weekStart.setDate(date.getDate() - date.getDay() + 1); // Monday
      const weekKey = weekStart.toISOString().split('T')[0];
      if (!weekMap[weekKey]) {
        weekMap[weekKey] = { date: weekKey, services: 0, km: 0 };
      }
      weekMap[weekKey].services += d.services;
      weekMap[weekKey].km += d.km;
    });
    aggregatedData = Object.values(weekMap).sort((a, b) => a.date.localeCompare(b.date));
  } else if (view === 'month') {
    // Aggregate by month
    const monthMap = {};
    dashboardDailyData.forEach(d => {
      const monthKey = d.date.substring(0, 7); // YYYY-MM
      if (!monthMap[monthKey]) {
        monthMap[monthKey] = { date: monthKey + '-01', services: 0, km: 0 };
      }
      monthMap[monthKey].services += d.services;
      monthMap[monthKey].km += d.km;
    });
    aggregatedData = Object.values(monthMap).sort((a, b) => a.date.localeCompare(b.date));
  }
  
  renderTrendChart(aggregatedData, view);
}

function renderTrendChart(dailyData, view = 'day') {
  const ctx = document.getElementById('trend-chart');
  if (!ctx) return;
  
  if (!dailyData || dailyData.length === 0) {
    if (trendChart) {
      trendChart.destroy();
      trendChart = null;
    }
    return;
  }
  
  const labels = dailyData.map(d => {
    const date = new Date(d.date + 'T12:00:00');
    if (view === 'week') {
      return 'Sett. ' + date.toLocaleDateString('it-IT', { day: '2-digit', month: 'short' });
    } else if (view === 'month') {
      return date.toLocaleDateString('it-IT', { month: 'short', year: '2-digit' });
    }
    return date.toLocaleDateString('it-IT', { day: '2-digit', month: 'short' });
  });
  const servicesData = dailyData.map(d => d.services || 0);
  const kmData = dailyData.map(d => d.km || 0);
  
  // Find max for km to scale appropriately
  const maxKm = Math.max(...kmData, 1);
  const scaleFactor = Math.max(...servicesData, 1) / maxKm;
  const scaledKmData = kmData.map(k => k * scaleFactor);
  
  // Always destroy and recreate chart for view changes
  if (trendChart) {
    trendChart.destroy();
    trendChart = null;
  }
  
  trendChart = new Chart(ctx, {
    type: 'line',
    data: {
      labels,
      datasets: [
        {
          label: 'Servizi',
          data: servicesData,
          borderColor: '#0066CC',
          backgroundColor: 'rgba(0, 102, 204, 0.08)',
          fill: true,
          tension: 0.4,
          borderWidth: 2,
          pointRadius: 0,
          pointHoverRadius: 5
        },
        {
          label: 'Km (scaled)',
          data: scaledKmData,
          borderColor: '#00A651',
          backgroundColor: 'rgba(0, 166, 81, 0.05)',
          fill: true,
          tension: 0.4,
          borderWidth: 2,
          pointRadius: 0,
          pointHoverRadius: 5
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { intersect: false, mode: 'index' },
      plugins: {
        legend: { display: false },
        tooltip: {
          backgroundColor: '#fff',
          borderColor: '#e5e9f0',
          borderWidth: 1,
          titleColor: '#1a2744',
          bodyColor: '#697386',
          padding: 12,
          callbacks: {
            label: function(ctx) {
              if (ctx.datasetIndex === 1) {
                return `Km: ${kmData[ctx.dataIndex]}`;
              }
              return `Servizi: ${ctx.raw}`;
            }
          }
        }
      },
      scales: {
        x: {
          grid: { color: '#f0f4f8', drawBorder: false },
          ticks: { color: '#697386', font: { size: 10 } }
        },
        y: {
          grid: { color: '#f0f4f8', drawBorder: false },
          ticks: { color: '#697386', font: { size: 10 } },
          beginAtZero: true
        }
      }
    }
  });
}

function renderHourlyHeatmap(heatmapData) {
  const container = document.getElementById('hourly-heatmap');
  if (!container) return;
  
  // Validate heatmap data - should be 7 days x 24 hours
  if (!heatmapData || !Array.isArray(heatmapData) || heatmapData.length !== 7) {
    container.innerHTML = '<div style="color:#697386;text-align:center;padding:40px;">Dati mappa non disponibili</div>';
    return;
  }
  
  const days = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'];
  const hours = Array.from({ length: 24 }, (_, i) => i);
  
  // Find max value for intensity (with safe flat)
  const flatData = heatmapData.flatMap(row => Array.isArray(row) ? row : []);
  const maxVal = Math.max(...flatData, 1);
  
  let html = '<div class="heatmap-grid">';
  
  // Header row with all 24 hours
  html += '<div class="heatmap-row header"><div class="heatmap-label"></div>';
  hours.forEach(h => {
    html += `<div class="heatmap-hour">${String(h).padStart(2, '0')}</div>`;
  });
  html += '</div>';
  
  // Data rows
  days.forEach((day, dayIdx) => {
    html += `<div class="heatmap-row"><div class="heatmap-label">${day}</div>`;
    hours.forEach(hour => {
      const value = heatmapData[dayIdx]?.[hour] || 0;
      const intensity = value / maxVal;
      const bgColor = intensity > 0 
        ? `rgba(0, 102, 204, ${0.1 + intensity * 0.7})` 
        : '#f0f4f8';
      html += `<div class="heatmap-cell" style="background:${bgColor}" title="${day} ${hour}:00 - ${value} servizi"></div>`;
    });
    html += '</div>';
  });
  
  html += '</div>';
  container.innerHTML = html;
}

