// Vehicle Modal Functions
function openVehicleModal() {
  const modal = document.getElementById('vehicle-modal');
  const locationSelect = document.getElementById('vehicle-location');
  
  // Populate locations dropdown
  locationSelect.innerHTML = '<option value="">-- Seleziona sede --</option>' +
    locations.map(l => `<option value="${l.id}">${l.name}</option>`).join('');
  
  // Reset form
  document.getElementById('vehicle-form').reset();
  
  modal.classList.remove('hidden');
}

function closeVehicleModal() {
  document.getElementById('vehicle-modal').classList.add('hidden');
}

async function handleVehicleSubmit(e) {
  e.preventDefault();
  
  const form = e.target;
  const brand = document.getElementById('vehicle-brand').value.trim();
  const modelName = document.getElementById('vehicle-model').value.trim();
  const fullModel = brand && modelName ? `${brand} ${modelName}` : (brand || modelName);
  
  const vehicleData = {
    code: document.getElementById('vehicle-code').value.trim(),
    licensePlate: document.getElementById('vehicle-plate').value.trim() || null,
    model: fullModel || null,
    fuelType: document.getElementById('vehicle-fuel').value,
    kw: parseInt(document.getElementById('vehicle-kw').value) || null,
    currentKm: parseInt(document.getElementById('vehicle-km').value) || 0,
    locationId: document.getElementById('vehicle-location').value
  };
  
  if (!vehicleData.code || !vehicleData.locationId) {
    alert('Compila i campi obbligatori: Sigla Veicolo e Sede');
    return;
  }
  
  try {
    const res = await adminFetch(`${API_BASE}/api/vehicles`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(vehicleData)
    });
    
    if (!res.ok) {
      const error = await res.json();
      alert(error.error || 'Errore durante la creazione del veicolo');
      return;
    }
    
    const newVehicle = await res.json();
    vehicles.push(newVehicle);
    
    closeVehicleModal();
    buildFleetTree();
    updateVehiclesGrid();
    updateDashboard();
    
    alert('Veicolo aggiunto con successo!');
  } catch (error) {
    console.error('Error creating vehicle:', error);
    alert('Errore di connessione');
  }
}

// Vehicle Service History with Pagination
let currentServicePage = 1;
const SERVICES_PER_PAGE = 5;

function showVehicleDetail(vehicleId) {
  const vehicle = vehicles.find(v => v.id === vehicleId);
  if (!vehicle) return;
  
  selectedVehicle = vehicle;
  currentServicePage = 1;
  
  const location = locations.find(l => l.id === vehicle.locationId);
  const vTrips = trips.filter(t => t.vehicleId === vehicle.id)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  const totalKm = vTrips.reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
  const avgKm = vTrips.length > 0 ? Math.round(totalKm / vTrips.length) : 0;
  
  const detailPanel = document.getElementById('detail-panel');
  const detailContent = document.getElementById('detail-content');
  
  document.getElementById('detail-title').textContent = vehicle.code;
  
  // Build vehicle info
  let infoHTML = `
    <div class="detail-section">
      <div class="detail-section-title">Informazioni Veicolo</div>
      <div class="detail-row"><span class="detail-label">Codice</span><span class="detail-value">${vehicle.code}</span></div>
      <div class="detail-row"><span class="detail-label">Targa</span><span class="detail-value">${vehicle.licensePlate || 'N/A'}</span></div>
      <div class="detail-row"><span class="detail-label">Marca</span><span class="detail-value">${vehicle.brand || 'N/A'}</span></div>
      <div class="detail-row"><span class="detail-label">Modello</span><span class="detail-value">${vehicle.model || 'N/A'}</span></div>
      <div class="detail-row"><span class="detail-label">Alimentazione</span><span class="detail-value">${vehicle.fuelType || 'N/A'}</span></div>
      <div class="detail-row"><span class="detail-label">Classe</span><span class="detail-value"><span style="padding:2px 8px;border-radius:6px;font-size:11px;font-weight:600;${vehicle.vehicleClass === 'tipo_a' ? 'background:#FEF2F2;color:#DC2626;' : 'background:#EFF6FF;color:#0066CC;'}">${vehicle.vehicleClass === 'tipo_a' ? 'TIPO A - Soccorso' : 'TIPO B - Trasporto'}</span>${vehicle.isReserve ? ' <span style="padding:2px 8px;border-radius:6px;font-size:11px;font-weight:600;background:#FFF7ED;color:#D97706;">RISERVA</span>' : ''}</span></div>
      <div class="detail-row"><span class="detail-label">Sede</span><span class="detail-value">${location?.name || 'N/A'}</span></div>
    </div>
    <div class="detail-section">
      <div class="detail-section-title">Chilometraggio</div>
      <div class="detail-row"><span class="detail-label">Km Attuali</span><span class="detail-value">${(vehicle.currentKm || 0).toLocaleString('it-IT')} km</span></div>
      <div class="detail-row"><span class="detail-label">Km Percorsi Totali</span><span class="detail-value">${totalKm.toLocaleString('it-IT')} km</span></div>
      <div class="detail-row"><span class="detail-label">Media Km/Viaggio</span><span class="detail-value">${avgKm.toLocaleString('it-IT')} km</span></div>
    </div>
    <div class="detail-section">
      <div class="detail-section-title">Statistiche</div>
      <div class="detail-row"><span class="detail-label">Viaggi Totali</span><span class="detail-value">${vTrips.length}</span></div>
      <div class="detail-row"><span class="detail-label">Ultimo Servizio</span><span class="detail-value">${vTrips.length > 0 ? new Date(vTrips[0].createdAt).toLocaleDateString('it-IT') : 'N/A'}</span></div>
    </div>
    <div class="detail-section service-history-section" id="service-history-container">
      ${renderServiceHistory(vTrips, 1)}
    </div>
  `;
  
  detailContent.innerHTML = infoHTML;
  
  detailPanel.classList.remove('hidden');
  
  document.querySelectorAll('.vehicle-card').forEach(c => c.classList.remove('selected'));
  document.querySelector(`.vehicle-card[data-vehicle-id="${vehicleId}"]`)?.classList.add('selected');
  
  document.querySelectorAll('.fleet-vehicle').forEach(v => v.classList.remove('selected'));
  document.querySelector(`.fleet-vehicle[data-vehicle-id="${vehicleId}"]`)?.classList.add('selected');
}

function renderServiceHistory(vTrips, page) {
  const totalPages = Math.ceil(vTrips.length / SERVICES_PER_PAGE);
  const startIndex = (page - 1) * SERVICES_PER_PAGE;
  const pageTrips = vTrips.slice(startIndex, startIndex + SERVICES_PER_PAGE);
  
  if (vTrips.length === 0) {
    return `
      <div class="detail-section-title">Storico Servizi</div>
      <div class="empty-services">Nessun servizio registrato per questo veicolo</div>
    `;
  }
  
  let html = `
    <div class="service-history-header">
      <h4>Storico Servizi</h4>
      <span class="pagination-info">${vTrips.length} servizi totali</span>
    </div>
    <table class="service-history-table">
      <thead>
        <tr>
          <th>N.</th>
          <th>Data</th>
          <th>Percorso</th>
          <th>Km</th>
          <th>Durata</th>
        </tr>
      </thead>
      <tbody>
  `;
  
  pageTrips.forEach(trip => {
    const dateStr = trip.serviceDate ? new Date(trip.serviceDate).toLocaleDateString('it-IT') : 'N/A';
    const departTime = trip.departureTime ? trip.departureTime.substring(0, 5) : '';
    const returnTime = trip.returnTime ? trip.returnTime.substring(0, 5) : '';
    const timeStr = departTime && returnTime ? `${departTime} - ${returnTime}` : '';
    const duration = calculateDuration(trip.departureTime, trip.returnTime);
    const origin = trip.originName || trip.originAddress || 'N/A';
    const dest = trip.destinationName || trip.destinationAddress || 'N/A';
    
    html += `
      <tr>
        <td>${trip.isReturnTrip && !trip.progressiveNumber 
          ? '<span style="display:inline-block;text-align:center;font-size:10px;font-weight:700;line-height:1.2;color:#D97706;text-transform:uppercase;background:#FEF3C7;padding:2px 6px;border-radius:4px;">SENZA<br>PAZIENTE</span>'
          : `<strong>${trip.progressiveNumber || 'N/A'}</strong>`}</td>
        <td>
          <div>${dateStr}</div>
          <div style="font-size:10px;color:var(--text-muted)">${timeStr}</div>
        </td>
        <td>
          <div class="service-row-origin">${origin}</div>
          <div class="service-row-dest">${dest}</div>
        </td>
        <td><span class="service-km-badge">${trip.kmTraveled || 0}</span></td>
        <td>${duration}</td>
      </tr>
    `;
  });
  
  html += '</tbody></table>';
  
  // Pagination
  if (totalPages > 1) {
    html += `<div class="pagination">`;
    
    // Previous button
    html += `<button class="pagination-btn" onclick="changeServicePage(${page - 1})" ${page === 1 ? 'disabled' : ''}>
      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="m15 18-6-6 6-6"/></svg>
    </button>`;
    
    // Page numbers
    for (let i = 1; i <= totalPages; i++) {
      if (totalPages <= 5 || i === 1 || i === totalPages || Math.abs(i - page) <= 1) {
        html += `<button class="pagination-btn ${i === page ? 'active' : ''}" onclick="changeServicePage(${i})">${i}</button>`;
      } else if (i === 2 && page > 3) {
        html += `<span class="pagination-info">...</span>`;
      } else if (i === totalPages - 1 && page < totalPages - 2) {
        html += `<span class="pagination-info">...</span>`;
      }
    }
    
    // Next button
    html += `<button class="pagination-btn" onclick="changeServicePage(${page + 1})" ${page === totalPages ? 'disabled' : ''}>
      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="m9 18 6-6-6-6"/></svg>
    </button>`;
    
    html += `</div>`;
  }
  
  return html;
}

function changeServicePage(page) {
  if (!selectedVehicle) return;
  
  const vTrips = trips.filter(t => t.vehicleId === selectedVehicle.id)
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  
  const totalPages = Math.ceil(vTrips.length / SERVICES_PER_PAGE);
  if (page < 1 || page > totalPages) return;
  
  currentServicePage = page;
  
  const container = document.getElementById('service-history-container');
  if (container) {
    container.innerHTML = renderServiceHistory(vTrips, page);
  }
}

// ========================================
// STATISTICS FUNCTIONS
// ========================================

let statsCharts = {};
let statsPeriodDays = 30;

function setupStatisticsListeners() {
  // Populate location filter
  const locationSelect = document.getElementById('stats-location-filter');
  if (locationSelect && locations.length > 0) {
    locationSelect.innerHTML = '<option value="">Tutte le Sedi</option>' +
      locations.map(loc => `<option value="${loc.id}">${loc.name}</option>`).join('');
  }
  
  // Location filter change
  locationSelect?.addEventListener('change', () => {
    updateStatistics();
  });
  
  document.getElementById('stats-period')?.addEventListener('change', (e) => {
    const value = e.target.value;
    const customInputs = document.getElementById('custom-period-inputs');
    if (value === 'custom') {
      customInputs?.classList.remove('hidden');
    } else {
      customInputs?.classList.add('hidden');
      statsPeriodDays = parseInt(value);
    }
  });
  
  document.getElementById('apply-stats-period')?.addEventListener('click', () => {
    const periodSelect = document.getElementById('stats-period');
    if (periodSelect.value === 'custom') {
      const from = document.getElementById('stats-date-from').value;
      const to = document.getElementById('stats-date-to').value;
      if (from && to) {
        const diffTime = Math.abs(new Date(to) - new Date(from));
        statsPeriodDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      }
    } else {
      statsPeriodDays = parseInt(periodSelect.value);
    }
    updateStatistics();
  });
  
  // Stats tab switching
  document.querySelectorAll('.stats-tab').forEach(tab => {
    tab.addEventListener('click', () => {
      const tabName = tab.dataset.statsTab;
      
      // Update active tab button
      document.querySelectorAll('.stats-tab').forEach(t => t.classList.remove('active'));
      tab.classList.add('active');
      
      // Update active tab content
      document.querySelectorAll('.stats-tab-content').forEach(c => c.classList.remove('active'));
      document.getElementById(`stats-tab-${tabName}`)?.classList.add('active');
      
      // Re-render charts for the active tab (charts need to be re-rendered when becoming visible)
      setTimeout(() => {
        const currentTrips = getFilteredTrips();
        const previousTrips = getPreviousTrips();
        
        if (tabName === 'operativa') {
          renderHeatmap(currentTrips);
          renderWeeklyServicesChart(currentTrips);
          renderWeeklyTrendChart(currentTrips);
          renderTopOriginsList(currentTrips);
          renderTopDestinationsList(currentTrips);
        } else if (tabName === 'efficienza') {
          updateEfficiencyKPIs(currentTrips);
          renderVehicleUsageChart(currentTrips);
          updateMostUsedVehicles(currentTrips);
          updateLeastUsedVehicles(currentTrips);
        } else if (tabName === 'strategica') {
          renderPeriodComparisonCharts(currentTrips, previousTrips);
          renderBudgetProjectionsChart(currentTrips);
          renderSankeyDiagram(currentTrips);
          updateAIPredictions(currentTrips);
        } else if (tabName === 'persede') {
          updateSedeStatistics();
        }
      }, 50);
    });
  });
}

function getFilteredTrips() {
  const now = new Date();
  const periodStart = new Date(now);
  periodStart.setDate(periodStart.getDate() - statsPeriodDays);
  const locationFilter = document.getElementById('stats-location-filter')?.value || '';
  
  return trips.filter(t => {
    const date = new Date(t.serviceDate || t.createdAt);
    const inDateRange = date >= periodStart && date <= now;
    
    if (locationFilter) {
      const vehicle = vehicles.find(v => v.id === t.vehicleId);
      return inDateRange && vehicle && vehicle.locationId === locationFilter;
    }
    return inDateRange;
  });
}

function getPreviousTrips() {
  const now = new Date();
  const periodStart = new Date(now);
  periodStart.setDate(periodStart.getDate() - statsPeriodDays);
  const previousPeriodEnd = new Date(periodStart);
  const previousPeriodStart = new Date(previousPeriodEnd);
  previousPeriodStart.setDate(previousPeriodStart.getDate() - statsPeriodDays);
  return trips.filter(t => {
    const date = new Date(t.serviceDate || t.createdAt);
    return date >= previousPeriodStart && date < periodStart;
  });
}

// Export Analytics CSV
function exportAnalyticsCSV() {
  const filteredTrips = getFilteredTrips();
  const locationFilter = document.getElementById('stats-location-filter')?.value || '';
  const locationName = locationFilter ? locations.find(l => l.id === parseInt(locationFilter))?.name : 'Tutte le Sedi';
  
  // Calculate statistics
  const totalServices = filteredTrips.length;
  const totalKm = filteredTrips.reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
  const avgKm = totalServices > 0 ? Math.round(totalKm / totalServices) : 0;
  
  let totalDuration = 0;
  let durationCount = 0;
  filteredTrips.forEach(t => {
    if (t.departureTime && t.arrivalTime) {
      const [dh, dm] = t.departureTime.split(':').map(Number);
      const [ah, am] = t.arrivalTime.split(':').map(Number);
      const duration = (ah * 60 + am) - (dh * 60 + dm);
      if (duration > 0) {
        totalDuration += duration;
        durationCount++;
      }
    }
  });
  const avgDuration = durationCount > 0 ? Math.round(totalDuration / durationCount) : 0;
  
  // Build CSV content
  let csv = '\uFEFF'; // BOM for Excel UTF-8
  csv += 'REPORT STATISTICHE OPERATIVE - SOCCORSO DIGITALE\n';
  csv += `Periodo: Ultimi ${statsPeriodDays} giorni\n`;
  csv += `Sede: ${locationName}\n`;
  csv += `Data generazione: ${new Date().toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' })}\n\n`;
  
  // Summary KPIs
  csv += 'RIEPILOGO KPI\n';
  csv += 'Metrica,Valore\n';
  csv += `Servizi Totali,${totalServices}\n`;
  csv += `Km Totali,${totalKm.toLocaleString('it-IT')}\n`;
  csv += `Tempo Medio Servizio,${avgDuration} min\n`;
  csv += `Km Medi per Servizio,${avgKm}\n\n`;
  
  // Top Origins
  const originCounts = {};
  filteredTrips.forEach(t => {
    const origin = t.originStructureName || t.originAddress || 'Domicilio';
    originCounts[origin] = (originCounts[origin] || 0) + 1;
  });
  const topOrigins = Object.entries(originCounts).sort((a, b) => b[1] - a[1]).slice(0, 10);
  
  csv += 'TOP 10 PARTENZE\n';
  csv += 'Posizione,Origine,Servizi\n';
  topOrigins.forEach(([name, count], i) => {
    csv += `${i + 1},${name.replace(/,/g, ' ')},${count}\n`;
  });
  csv += '\n';
  
  // Top Destinations
  const destCounts = {};
  filteredTrips.forEach(t => {
    const dest = t.destinationStructureName || t.destinationAddress || 'Domicilio';
    destCounts[dest] = (destCounts[dest] || 0) + 1;
  });
  const topDests = Object.entries(destCounts).sort((a, b) => b[1] - a[1]).slice(0, 10);
  
  csv += 'TOP 10 DESTINAZIONI\n';
  csv += 'Posizione,Destinazione,Servizi\n';
  topDests.forEach(([name, count], i) => {
    csv += `${i + 1},${name.replace(/,/g, ' ')},${count}\n`;
  });
  csv += '\n';
  
  // Vehicle Usage
  const vehicleStats = {};
  filteredTrips.forEach(t => {
    const vehicle = vehicles.find(v => v.id === t.vehicleId);
    const vCode = vehicle?.code || 'Sconosciuto';
    if (!vehicleStats[vCode]) vehicleStats[vCode] = { services: 0, km: 0 };
    vehicleStats[vCode].services++;
    vehicleStats[vCode].km += t.kmTraveled || 0;
  });
  
  csv += 'UTILIZZO VEICOLI\n';
  csv += 'Veicolo,Servizi,Km Totali\n';
  Object.entries(vehicleStats).sort((a, b) => b[1].services - a[1].services).forEach(([code, stats]) => {
    csv += `${code},${stats.services},${stats.km.toLocaleString('it-IT')}\n`;
  });
  csv += '\n';
  
  // Detailed trips list
  csv += 'ELENCO SERVIZI\n';
  csv += 'Data,Veicolo,Origine,Destinazione,Km,Partenza,Arrivo\n';
  filteredTrips.sort((a, b) => new Date(b.serviceDate || b.createdAt) - new Date(a.serviceDate || a.createdAt)).forEach(t => {
    const vehicle = vehicles.find(v => v.id === t.vehicleId);
    const date = new Date(t.serviceDate || t.createdAt).toLocaleDateString('it-IT');
    const origin = (t.originStructureName || t.originAddress || 'Domicilio').replace(/,/g, ' ');
    const dest = (t.destinationStructureName || t.destinationAddress || 'Domicilio').replace(/,/g, ' ');
    csv += `${date},${vehicle?.code || '-'},${origin},${dest},${t.kmTraveled || 0},${t.departureTime || '-'},${t.arrivalTime || '-'}\n`;
  });
  
  // Download CSV
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `statistiche_operative_${new Date().toISOString().split('T')[0]}.csv`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
  
  showNotification('CSV esportato con successo', 'success');
}

