function updateQuarterlyStats() {
  const container = document.getElementById('quarterly-stats');
  if (!container) return;
  
  const now = new Date();
  const currentYear = now.getFullYear();
  
  const quarters = [
    { label: 'Q1 ' + currentYear, start: new Date(currentYear, 0, 1), end: new Date(currentYear, 2, 31) },
    { label: 'Q2 ' + currentYear, start: new Date(currentYear, 3, 1), end: new Date(currentYear, 5, 30) },
    { label: 'Q3 ' + currentYear, start: new Date(currentYear, 6, 1), end: new Date(currentYear, 8, 30) },
    { label: 'Q4 ' + currentYear, start: new Date(currentYear, 9, 1), end: new Date(currentYear, 11, 31) },
  ];
  
  const quarterStats = quarters.map(q => {
    const qTrips = trips.filter(t => {
      const date = new Date(t.serviceDate || t.createdAt);
      return date >= q.start && date <= q.end;
    });
    const services = qTrips.length;
    const km = qTrips.reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
    return { label: q.label, services, km };
  });
  
  container.innerHTML = quarterStats.map(q => `
    <div class="quarterly-item">
      <div class="quarterly-label">${q.label}</div>
      <div class="quarterly-values">
        <div class="quarterly-stat">
          <div class="quarterly-stat-value">${q.services.toLocaleString('it-IT')}</div>
          <div class="quarterly-stat-label">servizi</div>
        </div>
        <div class="quarterly-stat">
          <div class="quarterly-stat-value">${q.km.toLocaleString('it-IT')}</div>
          <div class="quarterly-stat-label">km</div>
        </div>
      </div>
    </div>
  `).join('');
}

