function truncateName(name, maxLen) {
  if (name.length <= maxLen) return name;
  return name.substring(0, maxLen - 3) + '...';
}

function updateEfficiencyKPIs(filteredTrips) {
  const totalServices = filteredTrips.length;
  const totalKm = filteredTrips.reduce((sum, t) => sum + (t.kmTraveled || 0), 0);
  const avgKm = totalServices > 0 ? Math.round(totalKm / totalServices) : 0;
  
  // Calculate average duration using departureTime and returnTime
  let totalDuration = 0;
  let durationCount = 0;
  filteredTrips.forEach(trip => {
    if (trip.departureTime && trip.returnTime) {
      const [dh, dm] = trip.departureTime.split(':').map(Number);
      const [rh, rm] = trip.returnTime.split(':').map(Number);
      const duration = (rh * 60 + rm) - (dh * 60 + dm);
      if (duration > 0) {
        totalDuration += duration;
        durationCount++;
      }
    }
  });
  const avgTime = durationCount > 0 ? Math.round(totalDuration / durationCount) : 0;
  
  // Calculate vehicle usage stats
  const vehicleStats = {};
  vehicles.forEach(v => {
    vehicleStats[v.id] = 0;
  });
  filteredTrips.forEach(trip => {
    if (vehicleStats[trip.vehicleId] !== undefined) {
      vehicleStats[trip.vehicleId]++;
    }
  });
  
  const usageCounts = Object.values(vehicleStats);
  const activeVehicles = usageCounts.filter(c => c > 0).length;
  const maxUsage = Math.max(...usageCounts) || 0;
  const minUsage = Math.min(...usageCounts.filter(c => c > 0)) || 0;
  const avgUsage = vehicles.length > 0 ? Math.round((activeVehicles / vehicles.length) * 100) : 0;
  const usageGap = maxUsage > 0 ? Math.round(((maxUsage - minUsage) / maxUsage) * 100) : 0;
  
  // Update DOM
  const avgKmEl = document.getElementById('eff-avg-km');
  const avgTimeEl = document.getElementById('eff-avg-time');
  const vehicleUsageEl = document.getElementById('eff-vehicle-usage');
  const usageGapEl = document.getElementById('eff-usage-gap');
  
  if (avgKmEl) avgKmEl.textContent = avgKm.toLocaleString('it-IT');
  if (avgTimeEl) avgTimeEl.textContent = avgTime;
  if (vehicleUsageEl) vehicleUsageEl.textContent = avgUsage;
  if (usageGapEl) usageGapEl.textContent = usageGap;
}

