function renderBudgetProjectionsChart(filteredTrips) {
  const ctx = document.getElementById('budget-projections-chart');
  if (!ctx) return;
  
  if (statsCharts.budgetProjections) {
    statsCharts.budgetProjections.destroy();
  }
  
  // Calculate monthly averages from historical data
  const monthlyData = {};
  filteredTrips.forEach(trip => {
    const date = new Date(trip.serviceDate || trip.createdAt);
    const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    if (!monthlyData[monthKey]) {
      monthlyData[monthKey] = { services: 0, km: 0 };
    }
    monthlyData[monthKey].services++;
    monthlyData[monthKey].km += trip.kmTraveled || 0;
  });
  
  const months = Object.keys(monthlyData).sort();
  const avgServicesPerMonth = months.length > 0 
    ? Math.round(months.reduce((sum, m) => sum + monthlyData[m].services, 0) / months.length)
    : 0;
  
  // Project next 6 months
  const now = new Date();
  const projectionLabels = [];
  const projectionData = [];
  
  for (let i = 1; i <= 6; i++) {
    const futureDate = new Date(now.getFullYear(), now.getMonth() + i, 1);
    const monthNames = ['Gen', 'Feb', 'Mar', 'Apr', 'Mag', 'Giu', 'Lug', 'Ago', 'Set', 'Ott', 'Nov', 'Dic'];
    projectionLabels.push(monthNames[futureDate.getMonth()] + ' ' + futureDate.getFullYear());
    // Simple linear projection with slight growth
    projectionData.push(Math.round(avgServicesPerMonth * (1 + i * 0.02)));
  }
  
  statsCharts.budgetProjections = new Chart(ctx, {
    type: 'line',
    data: {
      labels: projectionLabels,
      datasets: [{
        label: 'Servizi Previsti',
        data: projectionData,
        borderColor: '#1a365d',
        backgroundColor: 'rgba(26, 54, 93, 0.1)',
        fill: true,
        tension: 0.4,
        borderDash: [5, 5]
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { 
        legend: { display: true, position: 'top' }
      },
      scales: {
        y: { beginAtZero: true, grid: { color: 'rgba(0,0,0,0.05)' } },
        x: { grid: { display: false } }
      }
    }
  });
}

function renderSankeyDiagram(filteredTrips) {
  const container = document.getElementById('sankey-diagram');
  if (!container) return;
  
  // Create simple flow visualization
  const flows = {};
  filteredTrips.forEach(trip => {
    const origin = truncateName(trip.originName || trip.originAddress || 'Origine', 20);
    const dest = truncateName(trip.destinationName || trip.destinationAddress || 'Destinazione', 20);
    const key = `${origin}|${dest}`;
    flows[key] = (flows[key] || 0) + 1;
  });
  
  const sorted = Object.entries(flows)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 8);
  
  if (sorted.length === 0) {
    container.innerHTML = '<div class="empty-services">Nessun flusso disponibile</div>';
    return;
  }
  
  const maxFlow = sorted[0][1];
  
  container.innerHTML = `
    <div class="flow-diagram">
      ${sorted.map(([key, count]) => {
        const [origin, dest] = key.split('|');
        const width = Math.max(20, Math.round((count / maxFlow) * 100));
        return `
          <div class="flow-item">
            <div class="flow-origin">${origin}</div>
            <div class="flow-line" style="width: ${width}%">
              <span class="flow-count">${count}</span>
            </div>
            <div class="flow-dest">${dest}</div>
          </div>
        `;
      }).join('')}
    </div>
  `;
}

function updateAIPredictions(filteredTrips) {
  // Calculate 7-day and 30-day averages
  const now = new Date();
  
  const last7Days = filteredTrips.filter(t => {
    const date = new Date(t.serviceDate || t.createdAt);
    const diffDays = (now - date) / (1000 * 60 * 60 * 24);
    return diffDays <= 7;
  });
  
  const last30Days = filteredTrips.filter(t => {
    const date = new Date(t.serviceDate || t.createdAt);
    const diffDays = (now - date) / (1000 * 60 * 60 * 24);
    return diffDays <= 30;
  });
  
  const avg7 = Math.round(last7Days.length / 7 * 10) / 10;
  const avg30 = Math.round(last30Days.length / 30 * 10) / 10;
  
  // Update UI
  const pred7El = document.getElementById('pred-daily-7');
  const pred30El = document.getElementById('pred-daily-30');
  const bar7El = document.getElementById('pred-bar-7');
  const bar30El = document.getElementById('pred-bar-30');
  
  if (pred7El) pred7El.textContent = avg7.toFixed(1);
  if (pred30El) pred30El.textContent = avg30.toFixed(1);
  
  const maxAvg = Math.max(avg7, avg30, 1);
  if (bar7El) bar7El.style.width = `${(avg7 / maxAvg) * 100}%`;
  if (bar30El) bar30El.style.width = `${(avg30 / maxAvg) * 100}%`;
  
  // Weekly forecast
  const forecastContainer = document.getElementById('weekly-forecast');
  if (forecastContainer) {
    const dayNames = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'];
    const dayAverages = new Array(7).fill(0);
    const dayCounts = new Array(7).fill(0);
    
    filteredTrips.forEach(trip => {
      const date = new Date(trip.serviceDate || trip.createdAt);
      let day = date.getDay() - 1;
      if (day < 0) day = 6;
      dayAverages[day]++;
      dayCounts[day] = 1;
    });
    
    const weeks = Math.max(1, Math.ceil(filteredTrips.length > 0 ? statsPeriodDays / 7 : 1));
    
    forecastContainer.innerHTML = dayNames.map((name, i) => {
      const avg = Math.round(dayAverages[i] / weeks);
      return `
        <div class="ai-forecast-day">
          <div class="ai-forecast-day-name">${name}</div>
          <div class="ai-forecast-value">${avg}</div>
        </div>
      `;
    }).join('');
  }
}

