async function saveEditedTrip(event) {
  event.preventDefault();
  
  const tripId = document.getElementById('edit-trip-id').value;
  const kmInitial = parseInt(document.getElementById('edit-trip-km-initial').value) || 0;
  const kmFinal = parseInt(document.getElementById('edit-trip-km-final').value) || 0;
  
  const updateData = {
    vehicleId: document.getElementById('edit-trip-vehicle').value,
    serviceDate: document.getElementById('edit-trip-date').value,
    departureTime: document.getElementById('edit-trip-departure').value,
    returnTime: document.getElementById('edit-trip-return').value,
    originAddress: document.getElementById('edit-trip-origin').value,
    destinationAddress: document.getElementById('edit-trip-destination').value,
    kmInitial: kmInitial,
    kmFinal: kmFinal,
    kmTraveled: kmFinal - kmInitial,
    serviceType: document.getElementById('edit-trip-service-type').value,
    notes: document.getElementById('edit-trip-notes').value
  };
  
  try {
    const response = await adminFetch(`/api/trips/${tripId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(updateData)
    });
    
    if (!response.ok) throw new Error('Failed to update trip');
    
    closeEditTripModal();
    await loadInitialData();
    
    // Refresh dashboard metrics to update anomaly counts
    updateDashboard();
    
    // Also refresh data quality page if visible
    if (typeof loadDataQualityDashboard === 'function') {
      loadDataQualityDashboard();
    }
    
    alert('Viaggio aggiornato con successo!');
  } catch (error) {
    console.error('Error updating trip:', error);
    alert('Errore durante l\'aggiornamento del viaggio');
  }
}

