async function verifyTripIntegrity(tripId) {
  try {
    showNotification('Verifica integrità in corso...', 'info');
    
    const response = await adminFetch(`/api/trips/${tripId}/verify-integrity?format=json`, {
      headers: { 'Accept': 'application/json' }
    });
    
    if (!response.ok) {
      throw new Error('Errore nella verifica');
    }
    
    const result = await response.json();
    
    if (result.status === 'VALID') {
      const signedAt = result.signedAt ? new Date(result.signedAt).toLocaleString('it-IT') : 'N/A';
      showNotification(`Integrità VERIFICATA - Firmato il ${signedAt} con ${result.algorithm}`, 'success');
    } else if (result.status === 'BROKEN') {
      const lastModified = result.lastModifiedAt ? new Date(result.lastModifiedAt).toLocaleString('it-IT') : 'N/A';
      showNotification(`ATTENZIONE: Integrità COMPROMESSA - ${result.reason}. Ultima modifica: ${lastModified}`, 'error');
    } else {
      showNotification('Viaggio non ancora firmato', 'info');
    }
  } catch (error) {
    console.error('Error verifying trip integrity:', error);
    showNotification('Errore nella verifica integrità: ' + error.message, 'error');
  }
}

