// Financial Parameters CRUD
async function loadFinanceParameters(profileId) {
  try {
    const res = await adminFetch(`${API_BASE}/api/financial-profiles/${profileId}/parameters`);
    if (!res.ok) throw new Error('Failed to load parameters');
    financeParameters = await res.json();
    renderFinanceParameters(financeParameters);
  } catch (error) {
    console.error('Error loading parameters:', error);
    renderFinanceParameters([]);
  }
}

function renderFinanceParameters(params) {
  const tbody = document.getElementById('finance-parameters-tbody');
  if (!tbody) return;
  
  if (params.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty-state">Seleziona un profilo per vedere i parametri</td></tr>';
    return;
  }
  
  const keyLabels = {
    fuel_cost_per_km: 'Carburante/km',
    maintenance_cost_per_km: 'Manutenzione/km',
    insurance_monthly: 'Assicurazione mensile',
    depreciation_monthly: 'Ammortamento mensile',
    tire_cost_per_km: 'Pneumatici/km',
    toll_avg_per_trip: 'Pedaggi medi',
    overhead_percentage: 'Spese generali %',
    admin_cost_per_trip: 'Costi admin/viaggio'
  };
  
  tbody.innerHTML = params.map(p => `
    <tr>
      <td><strong>${keyLabels[p.paramKey] || p.paramKey}</strong></td>
      <td>${parseFloat(p.paramValue).toLocaleString('it-IT', { minimumFractionDigits: 2 })}</td>
      <td>${escapeHtml(p.unit || '-')}</td>
      <td>${escapeHtml(p.description || '-')}</td>
      <td>${p.effectiveFrom ? new Date(p.effectiveFrom).toLocaleDateString('it-IT') : '-'}</td>
      <td>${p.effectiveTo ? new Date(p.effectiveTo).toLocaleDateString('it-IT') : '-'}</td>
      <td>
        <div class="action-buttons">
          <button class="btn-icon-sm" onclick="openFinanceParamModal('${p.id}')" title="Modifica">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
          </button>
          <button class="btn-icon-sm danger" onclick="deleteFinanceParam('${p.id}')" title="Elimina">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M3 6h18"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
          </button>
        </div>
      </td>
    </tr>
  `).join('');
}

