// ============================================
// HANDOFFS MANAGEMENT FUNCTIONS - Consegne Digitali
// ============================================

let adminHandoffsData = [];

async function loadAdminHandoffs() {
  try {
    // Populate filter dropdowns
    populateHandoffFilters();
    
    // Get filter values
    const locationId = document.getElementById('handoff-location-filter')?.value || '';
    const vehicleId = document.getElementById('handoff-vehicle-filter')?.value || '';
    const status = document.getElementById('handoff-status-filter')?.value || '';
    const startDate = document.getElementById('handoff-start-date')?.value || '';
    const endDate = document.getElementById('handoff-end-date')?.value || '';
    
    // Build query string
    const params = new URLSearchParams();
    if (locationId) params.append('locationId', locationId);
    if (vehicleId) params.append('vehicleId', vehicleId);
    if (status) params.append('status', status);
    if (startDate) params.append('startDate', startDate);
    if (endDate) params.append('endDate', endDate);
    
    const queryString = params.toString() ? `?${params.toString()}` : '';
    
    const response = await adminFetch(`${API_BASE}/api/admin/handoffs${queryString}`);
    
    if (!response.ok) throw new Error('Errore caricamento consegne');
    
    adminHandoffsData = await response.json();
    renderHandoffsTable(adminHandoffsData);
    updateHandoffsStats(adminHandoffsData);
    
  } catch (error) {
    console.error('Error loading admin handoffs:', error);
    showNotification('Errore nel caricamento consegne', 'error');
  }
}

function populateHandoffFilters() {
  const locationSelect = document.getElementById('handoff-location-filter');
  const vehicleSelect = document.getElementById('handoff-vehicle-filter');
  
  if (locationSelect && locationSelect.options.length <= 1) {
    locations.forEach(loc => {
      const option = document.createElement('option');
      option.value = loc.id;
      option.textContent = loc.name;
      locationSelect.appendChild(option);
    });
    
    // Update vehicle filter when location changes
    locationSelect.addEventListener('change', () => {
      updateHandoffVehicleFilter(locationSelect.value);
    });
  }
  
  if (vehicleSelect && vehicleSelect.options.length <= 1) {
    vehicles.forEach(v => {
      const option = document.createElement('option');
      option.value = v.id;
      option.textContent = v.code;
      vehicleSelect.appendChild(option);
    });
  }
}

function updateHandoffVehicleFilter(locationId) {
  const vehicleSelect = document.getElementById('handoff-vehicle-filter');
  if (!vehicleSelect) return;
  
  vehicleSelect.innerHTML = '<option value="">Tutti i veicoli</option>';
  
  const filteredVehicles = locationId 
    ? vehicles.filter(v => v.locationId === locationId)
    : vehicles;
  
  filteredVehicles.forEach(v => {
    const option = document.createElement('option');
    option.value = v.id;
    option.textContent = v.code;
    vehicleSelect.appendChild(option);
  });
}

function updateHandoffsStats(data) {
  const totalEl = document.getElementById('handoffs-total-count');
  const pendingEl = document.getElementById('handoffs-pending-count');
  const readEl = document.getElementById('handoffs-read-count');
  const urgentEl = document.getElementById('handoffs-urgent-count');
  
  if (totalEl) totalEl.textContent = data.length;
  if (pendingEl) pendingEl.textContent = data.filter(h => h.status === 'pending').length;
  if (readEl) readEl.textContent = data.filter(h => h.status === 'read').length;
  if (urgentEl) urgentEl.textContent = data.filter(h => h.priority === 'urgent').length;
}

function renderHandoffsTable(data) {
  const tbody = document.getElementById('handoffs-tbody');
  const emptyState = document.getElementById('handoffs-empty');
  
  if (!tbody) return;
  
  if (!data || data.length === 0) {
    tbody.innerHTML = '';
    if (emptyState) emptyState.classList.remove('hidden');
    return;
  }
  
  if (emptyState) emptyState.classList.add('hidden');
  
  tbody.innerHTML = data.map(h => {
    const createdDate = new Date(h.createdAt);
    const readDate = h.readAt ? new Date(h.readAt) : null;
    
    const priorityBadge = getPriorityBadge(h.priority);
    const statusBadge = getStatusBadge(h.status);
    
    const messagePreview = h.message 
      ? (h.message.length > 60 ? h.message.substring(0, 60) + '...' : h.message)
      : '<em style="color: #94A3B8;">Nessun messaggio</em>';
    
    return `
      <tr>
        <td>
          <div style="font-weight: 500;">${createdDate.toLocaleDateString('it-IT')}</div>
          <div style="font-size: 12px; color: #64748B;">${createdDate.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })}</div>
        </td>
        <td>
          <div class="vehicle-code-badge">${h.vehicleCode || '-'}</div>
        </td>
        <td>${h.locationName || '-'}</td>
        <td>
          <div style="font-weight: 500;">${h.createdByName || '-'}</div>
        </td>
        <td>
          <div class="message-preview" title="${h.message || ''}">${messagePreview}</div>
        </td>
        <td>${priorityBadge}</td>
        <td>${statusBadge}</td>
        <td>${h.readByName || '<span style="color: #94A3B8;">-</span>'}</td>
        <td>
          ${readDate ? `
            <div style="font-size: 12px;">${readDate.toLocaleDateString('it-IT')}</div>
            <div style="font-size: 11px; color: #64748B;">${readDate.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })}</div>
          ` : '<span style="color: #94A3B8;">-</span>'}
        </td>
      </tr>
    `;
  }).join('');
}

function getPriorityBadge(priority) {
  const priorities = {
    'urgent': { label: 'Urgente', color: '#EF4444', bg: 'rgba(239, 68, 68, 0.1)' },
    'high': { label: 'Alta', color: '#F97316', bg: 'rgba(249, 115, 22, 0.1)' },
    'normal': { label: 'Normale', color: '#3B82F6', bg: 'rgba(59, 130, 246, 0.1)' },
    'low': { label: 'Bassa', color: '#6B7280', bg: 'rgba(107, 114, 128, 0.1)' }
  };
  
  const p = priorities[priority] || priorities['normal'];
  return `<span class="priority-badge" style="background: ${p.bg}; color: ${p.color}; padding: 4px 8px; border-radius: 4px; font-size: 12px; font-weight: 500;">${p.label}</span>`;
}

function getStatusBadge(status) {
  const statuses = {
    'pending': { label: 'In Attesa', color: '#F59E0B', bg: 'rgba(245, 158, 11, 0.1)' },
    'read': { label: 'Letta', color: '#22C55E', bg: 'rgba(34, 197, 94, 0.1)' },
    'archived': { label: 'Archiviata', color: '#6B7280', bg: 'rgba(107, 114, 128, 0.1)' }
  };
  
  const s = statuses[status] || statuses['pending'];
  return `<span class="status-badge" style="background: ${s.bg}; color: ${s.color}; padding: 4px 8px; border-radius: 4px; font-size: 12px; font-weight: 500;">${s.label}</span>`;
}

function exportHandoffsCSV() {
  if (!adminHandoffsData || adminHandoffsData.length === 0) {
    showNotification('Nessun dato da esportare', 'warning');
    return;
  }
  
  const headers = ['Data', 'Ora', 'Veicolo', 'Sede', 'Creata da', 'Messaggio', 'Priorita', 'Stato', 'Letta da', 'Data Lettura'];
  
  const rows = adminHandoffsData.map(h => {
    const createdDate = new Date(h.createdAt);
    const readDate = h.readAt ? new Date(h.readAt) : null;
    
    return [
      createdDate.toLocaleDateString('it-IT'),
      createdDate.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' }),
      h.vehicleCode || '',
      h.locationName || '',
      h.createdByName || '',
      (h.message || '').replace(/"/g, '""'),
      h.priority || 'normal',
      h.status || 'pending',
      h.readByName || '',
      readDate ? readDate.toLocaleDateString('it-IT') + ' ' + readDate.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' }) : ''
    ];
  });
  
  const csvContent = [headers.join(';'), ...rows.map(r => r.map(c => `"${c}"`).join(';'))].join('\n');
  
  const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = `consegne_${new Date().toISOString().split('T')[0]}.csv`;
  link.click();
  
  showNotification('Export CSV completato', 'success');
}

// Make functions globally available
window.loadAdminHandoffs = loadAdminHandoffs;
window.exportHandoffsCSV = exportHandoffsCSV;

// ============================================
// CHAT MANAGEMENT FUNCTIONS
// ============================================

let chatMessages = [];
let chatWebSocket = null;
let chatRefreshInterval = null;

async function loadChatMessages() {
  try {
    const container = document.getElementById('chat-messages-container');
    if (!container) return;
    
    container.innerHTML = '<div class="chat-loading">Caricamento messaggi...</div>';
    
    const response = await adminFetch(`${API_BASE}/api/chat/messages?limit=100`);
    
    if (!response.ok) throw new Error('Errore caricamento');
    
    chatMessages = await response.json();
    renderChatMessages();
    updateChatStats();
    connectChatWebSocket();
    
    // Set up auto-refresh
    if (chatRefreshInterval) clearInterval(chatRefreshInterval);
    chatRefreshInterval = setInterval(loadChatMessages, 30000);
    
  } catch (error) {
    console.error('Error loading chat messages:', error);
    const container = document.getElementById('chat-messages-container');
    if (container) {
      container.innerHTML = '<div class="chat-error">Errore nel caricamento dei messaggi</div>';
    }
  }
}

function renderChatMessages() {
  const container = document.getElementById('chat-messages-container');
  if (!container) return;
  
  if (chatMessages.length === 0) {
    container.innerHTML = '<div class="chat-empty">Nessun messaggio. Inizia una conversazione!</div>';
    return;
  }
  
  // Sort by date ascending (oldest first)
  const sorted = [...chatMessages].sort((a, b) => 
    new Date(a.createdAt) - new Date(b.createdAt)
  );
  
  let currentDate = null;
  let html = '';
  
  sorted.forEach(msg => {
    const msgDate = new Date(msg.createdAt).toLocaleDateString('it-IT');
    
    // Add date separator
    if (msgDate !== currentDate) {
      currentDate = msgDate;
      html += `<div class="chat-date-separator">${formatChatDate(msg.createdAt)}</div>`;
    }
    
    const time = new Date(msg.createdAt).toLocaleTimeString('it-IT', { 
      hour: '2-digit', 
      minute: '2-digit' 
    });
    
    const senderInfo = msg.senderVehicleCode 
      ? `<span class="chat-vehicle-badge">${msg.senderVehicleCode}</span>` 
      : msg.senderLocationName 
        ? `<span class="chat-location-badge">${msg.senderLocationName}</span>` 
        : '';
    
    const priorityClass = msg.isPriority ? 'priority-message' : '';
    
    html += `
      <div class="chat-message ${priorityClass}">
        <div class="chat-message-header">
          <span class="chat-sender">${escapeHtml(msg.senderName)}</span>
          ${senderInfo}
          <span class="chat-time">${time}</span>
        </div>
        <div class="chat-message-body">${escapeHtml(msg.message)}</div>
      </div>
    `;
  });
  
  container.innerHTML = html;
  container.scrollTop = container.scrollHeight;
}

function formatChatDate(dateStr) {
  const date = new Date(dateStr);
  const today = new Date();
  const yesterday = new Date(today);
  yesterday.setDate(yesterday.getDate() - 1);
  
  if (date.toDateString() === today.toDateString()) {
    return 'Oggi';
  } else if (date.toDateString() === yesterday.toDateString()) {
    return 'Ieri';
  } else {
    return date.toLocaleDateString('it-IT', { day: 'numeric', month: 'long' });
  }
}

function updateChatStats() {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  
  const weekAgo = new Date(today);
  weekAgo.setDate(weekAgo.getDate() - 7);
  
  const todayCount = chatMessages.filter(m => new Date(m.createdAt) >= today).length;
  const weekCount = chatMessages.filter(m => new Date(m.createdAt) >= weekAgo).length;
  
  // Get unique senders
  const uniqueSenders = new Set(chatMessages.map(m => m.senderId));
  
  document.getElementById('chat-today-count').textContent = todayCount;
  document.getElementById('chat-week-count').textContent = weekCount;
  document.getElementById('chat-active-users').textContent = uniqueSenders.size;
  
  // Update recent senders
  const recentMessages = [...chatMessages]
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
    .slice(0, 5);
  
  const recentSendersContainer = document.getElementById('recent-senders');
  if (recentSendersContainer) {
    if (recentMessages.length === 0) {
      recentSendersContainer.innerHTML = '<div class="sender-placeholder">Nessun messaggio recente</div>';
    } else {
      const uniqueRecentSenders = [];
      const seenSenders = new Set();
      
      for (const msg of recentMessages) {
        if (!seenSenders.has(msg.senderId)) {
          seenSenders.add(msg.senderId);
          uniqueRecentSenders.push(msg);
          if (uniqueRecentSenders.length >= 5) break;
        }
      }
      
      recentSendersContainer.innerHTML = uniqueRecentSenders.map(msg => `
        <div class="recent-sender-item">
          <div class="sender-avatar">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="8" r="5"/><path d="M20 21a8 8 0 1 0-16 0"/></svg>
          </div>
          <div class="sender-info">
            <span class="sender-name">${escapeHtml(msg.senderName)}</span>
            ${msg.senderVehicleCode ? `<span class="sender-vehicle">${msg.senderVehicleCode}</span>` : ''}
          </div>
        </div>
      `).join('');
    }
  }
}

function connectChatWebSocket() {
  if (chatWebSocket && chatWebSocket.readyState === WebSocket.OPEN) return;
  
  try {
    const wsUrl = API_BASE.replace(/^http/, 'ws') + '/ws/chat';
    chatWebSocket = new WebSocket(wsUrl);
    
    chatWebSocket.onopen = () => {
      console.log('[CHAT] WebSocket connected');
      updateChatConnectionStatus(true);
    };
    
    chatWebSocket.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.type === 'new_message') {
          loadChatMessages();
        }
      } catch (e) {
        console.error('[CHAT] Error parsing WebSocket message:', e);
      }
    };
    
    chatWebSocket.onclose = () => {
      console.log('[CHAT] WebSocket disconnected');
      updateChatConnectionStatus(false);
      // Try to reconnect after 5 seconds
      setTimeout(connectChatWebSocket, 5000);
    };
    
    chatWebSocket.onerror = (error) => {
      console.error('[CHAT] WebSocket error:', error);
      updateChatConnectionStatus(false);
    };
  } catch (error) {
    console.error('[CHAT] Failed to connect WebSocket:', error);
    updateChatConnectionStatus(false);
  }
}

function updateChatConnectionStatus(connected) {
  const dot = document.getElementById('chat-status-dot');
  const text = document.getElementById('chat-status-text');
  
  if (dot) {
    dot.style.backgroundColor = connected ? '#10B981' : '#F59E0B';
  }
  if (text) {
    text.textContent = connected ? 'In tempo reale' : 'Riconnessione...';
  }
}

async function sendChatMessage() {
  const input = document.getElementById('chat-message-input');
  const message = input?.value?.trim();
  
  if (!message) return;
  
  const sendBtn = document.getElementById('chat-send-btn');
  sendBtn.disabled = true;
  
  try {
    const response = await adminFetch(`${API_BASE}/api/chat/messages`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ message })
    });
    
    if (!response.ok) throw new Error('Errore invio');
    
    input.value = '';
    await loadChatMessages();
    
  } catch (error) {
    console.error('[CHAT] Error sending message:', error);
    showNotification('Errore nell\'invio del messaggio', 'error');
  } finally {
    sendBtn.disabled = false;
  }
}

// Chat input enter key handler
document.addEventListener('DOMContentLoaded', () => {
  const chatInput = document.getElementById('chat-message-input');
  if (chatInput) {
    chatInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendChatMessage();
      }
    });
  }
});

// ========================================
// COMPLIANCE & AUDIT TRAIL FUNCTIONS
// ========================================

let auditCurrentPage = 1;
const AUDIT_PAGE_SIZE = 25;
let auditLogs = [];
let gdprStats = {};

async function loadComplianceData() {
  console.log('[COMPLIANCE] Loading compliance data...');
  
  try {
    const [auditRes, gdprRes, exportsRes, erasuresRes] = await Promise.all([
      adminFetch(`${API_BASE}/api/audit-logs?limit=100`),
      adminFetch(`${API_BASE}/api/compliance/stats`),
      adminFetch(`${API_BASE}/api/compliance/gdpr/exports/pending`),
      adminFetch(`${API_BASE}/api/compliance/gdpr/erasures/pending`)
    ]);
    
    if (auditRes.ok) {
      const auditData = await auditRes.json();
      // API returns array directly, not object with logs property
      auditLogs = Array.isArray(auditData) ? auditData : (auditData.logs || []);
      console.log('[COMPLIANCE] Audit logs loaded:', auditLogs.length);
      updateAuditStats({ logs: auditLogs, total: auditLogs.length });
      renderAuditLogs();
    }
    
    if (gdprRes.ok) {
      gdprStats = await gdprRes.json();
      updateGdprStats();
    }
    
    // Load and render pending GDPR requests
    const pendingExports = exportsRes.ok ? await exportsRes.json() : [];
    const pendingErasures = erasuresRes.ok ? await erasuresRes.json() : [];
    renderGdprRequests(pendingExports, pendingErasures);
    
  } catch (error) {
    console.error('[COMPLIANCE] Error loading data:', error);
    showNotification('Errore nel caricamento dati compliance', 'error');
  }
}

function renderGdprRequests(exports, erasures) {
  const container = document.getElementById('gdpr-requests-list');
  if (!container) return;
  
  const allRequests = [
    ...exports.map(e => ({ ...e, type: 'export' })),
    ...erasures.map(e => ({ ...e, type: 'erasure' }))
  ].sort((a, b) => new Date(b.requestedAt) - new Date(a.requestedAt));
  
  if (allRequests.length === 0) {
    container.innerHTML = '<div class="gdpr-request-empty">Nessuna richiesta pendente</div>';
    return;
  }
  
  container.innerHTML = allRequests.map(req => {
    const date = new Date(req.requestedAt);
    const formattedDate = date.toLocaleDateString('it-IT') + ' ' + date.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
    const typeBadge = req.type === 'export' ? 'export' : 'erasure';
    const typeLabel = req.type === 'export' ? 'Export Dati' : 'Cancellazione';
    const requesterName = req.requesterFullName || req.userName || 'Utente';
    
    return `
      <div class="gdpr-request-item">
        <div class="gdpr-request-info">
          <div class="gdpr-request-type">
            <span class="badge ${typeBadge}">${typeLabel}</span>
            ${requesterName}
          </div>
          <div class="gdpr-request-meta">
            Richiesta il ${formattedDate}
          </div>
        </div>
        <div class="gdpr-request-actions">
          ${req.type === 'erasure' ? `
            <button class="btn btn-primary btn-sm" onclick="processErasureRequest('${req.id}')">
              Elabora
            </button>
          ` : `
            <button class="btn btn-primary btn-sm" onclick="processExportRequest('${req.id}')">
              Genera Export
            </button>
          `}
        </div>
      </div>
    `;
  }).join('');
}

async function processErasureRequest(requestId) {
  if (!confirm('Sei sicuro di voler elaborare questa richiesta di cancellazione? I dati personali verranno anonimizzati.')) {
    return;
  }
  
  try {
    const res = await adminFetch(`${API_BASE}/api/compliance/gdpr/erasures/${requestId}/process`, {
      method: 'POST'
    });
    
    if (res.ok) {
      const result = await res.json();
      showNotification(result.message || 'Richiesta elaborata con successo', 'success');
      loadComplianceData();
    } else {
      const error = await res.json();
      showNotification(error.error || 'Errore nell\'elaborazione', 'error');
    }
  } catch (error) {
    console.error('Error processing erasure:', error);
    showNotification('Errore nell\'elaborazione della richiesta', 'error');
  }
}

async function processExportRequest(requestId) {
  showNotification('Generazione export in corso...', 'info');
  
  try {
    const res = await adminFetch(`${API_BASE}/api/compliance/gdpr/exports/${requestId}/process`, {
      method: 'POST'
    });
    
    if (res.ok) {
      showNotification('Export generato con successo', 'success');
      loadComplianceData();
    } else {
      const error = await res.json();
      showNotification(error.error || 'Errore nella generazione export', 'error');
    }
  } catch (error) {
    console.error('Error processing export:', error);
    showNotification('Errore nella generazione dell\'export', 'error');
  }
}

function updateAuditStats(data) {
  const totalEl = document.getElementById('audit-total-count');
  const todayEl = document.getElementById('audit-today-count');
  
  if (totalEl) totalEl.textContent = data.total || auditLogs.length;
  
  const today = new Date().toDateString();
  const todayCount = auditLogs.filter(log => {
    const logDate = new Date(log.createdAt || log.timestamp);
    return !isNaN(logDate.getTime()) && logDate.toDateString() === today;
  }).length;
  if (todayEl) todayEl.textContent = todayCount;
}

function updateGdprStats() {
  const consentsEl = document.getElementById('gdpr-active-consents');
  const pendingEl = document.getElementById('gdpr-pending-requests');
  const completedExportsEl = document.getElementById('gdpr-completed-exports');
  const pendingExportsEl = document.getElementById('gdpr-pending-exports');
  const pendingErasuresEl = document.getElementById('gdpr-pending-erasures');
  const usersWithoutConsentEl = document.getElementById('gdpr-users-without-consent');
  
  if (consentsEl) consentsEl.textContent = gdprStats.activeConsents || 0;
  if (pendingEl) pendingEl.textContent = (gdprStats.pendingExports || 0) + (gdprStats.pendingErasures || 0);
  if (completedExportsEl) completedExportsEl.textContent = gdprStats.completedExports || 0;
  if (pendingExportsEl) pendingExportsEl.textContent = gdprStats.pendingExports || 0;
  if (pendingErasuresEl) pendingErasuresEl.textContent = gdprStats.pendingErasures || 0;
  if (usersWithoutConsentEl) usersWithoutConsentEl.textContent = gdprStats.usersWithoutConsent || 0;
}

function renderAuditLogs() {
  const tbody = document.getElementById('audit-log-tbody');
  if (!tbody) return;
  
  const filter = document.getElementById('audit-filter-action')?.value || '';
  const filteredLogs = filter 
    ? auditLogs.filter(log => log.action === filter)
    : auditLogs;
  
  const start = (auditCurrentPage - 1) * AUDIT_PAGE_SIZE;
  const end = start + AUDIT_PAGE_SIZE;
  const pageData = filteredLogs.slice(start, end);
  
  if (pageData.length === 0) {
    tbody.innerHTML = '<tr><td colspan="6" class="empty-state">Nessun log trovato</td></tr>';
    return;
  }
  
  tbody.innerHTML = pageData.map(log => {
    const date = new Date(log.createdAt || log.timestamp);
    const formattedDate = !isNaN(date.getTime()) 
      ? date.toLocaleDateString('it-IT') + ' ' + date.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' })
      : '-';
    const actionLabel = getActionLabel(log.action);
    
    return `
      <tr>
        <td>${formattedDate}</td>
        <td>${log.actorName || log.actorId || 'Sistema'}</td>
        <td><span class="action-badge ${log.action}">${actionLabel}</span></td>
        <td>${log.entityType || '-'}</td>
        <td>${truncateText(log.description || '-', 50)}</td>
        <td>${log.ipAddress || '-'}</td>
      </tr>
    `;
  }).join('');
  
  renderAuditPagination(filteredLogs.length);
}

function getActionLabel(action) {
  const labels = {
    'login': 'Login',
    'logout': 'Logout',
    'create': 'Creazione',
    'update': 'Modifica',
    'delete': 'Eliminazione',
    'trip_submit': 'Viaggio',
    'checklist_submit': 'Checklist',
    'consent_granted': 'Consenso',
    'consent_revoked': 'Revoca Cons.',
    'data_export': 'Export Dati',
    'data_erasure': 'Cancellazione'
  };
  return labels[action] || action;
}

function truncateText(text, maxLength) {
  if (!text || text.length <= maxLength) return text;
  return text.substring(0, maxLength) + '...';
}

function renderAuditPagination(total) {
  const container = document.getElementById('audit-pagination');
  if (!container) return;
  
  const totalPages = Math.ceil(total / AUDIT_PAGE_SIZE);
  if (totalPages <= 1) {
    container.innerHTML = '';
    return;
  }
  
  let html = '';
  
  if (auditCurrentPage > 1) {
    html += `<button class="btn btn-secondary btn-sm" onclick="goToAuditPage(${auditCurrentPage - 1})">Prec</button>`;
  }
  
  for (let i = 1; i <= totalPages; i++) {
    if (i === auditCurrentPage) {
      html += `<button class="btn btn-primary btn-sm">${i}</button>`;
    } else if (i === 1 || i === totalPages || (i >= auditCurrentPage - 2 && i <= auditCurrentPage + 2)) {
      html += `<button class="btn btn-secondary btn-sm" onclick="goToAuditPage(${i})">${i}</button>`;
    } else if (i === auditCurrentPage - 3 || i === auditCurrentPage + 3) {
      html += `<span style="padding: 0 8px;">...</span>`;
    }
  }
  
  if (auditCurrentPage < totalPages) {
    html += `<button class="btn btn-secondary btn-sm" onclick="goToAuditPage(${auditCurrentPage + 1})">Succ</button>`;
  }
  
  container.innerHTML = html;
}

function goToAuditPage(page) {
  auditCurrentPage = page;
  renderAuditLogs();
}

function filterAuditLogs() {
  auditCurrentPage = 1;
  renderAuditLogs();
}

async function verifyAuditChain() {
  const statusEl = document.getElementById('chain-integrity-status');
  const textEl = document.getElementById('chain-status-text');
  
  if (textEl) textEl.textContent = 'Verifica in corso...';
  
  try {
    const response = await adminFetch(`${API_BASE}/api/compliance/verify-chain`, {
      method: 'POST'
    });
    
    if (!response.ok) throw new Error('Verifica fallita');
    
    const result = await response.json();
    const entriesChecked = result.entriesChecked || 0;
    
    if (entriesChecked === 0) {
      statusEl?.classList.remove('invalid');
      if (textEl) textEl.textContent = 'Nessun log audit presente - Sistema pronto';
      showNotification('Nessun log audit presente. Il sistema e pronto per registrare le operazioni.', 'info');
    } else if (result.isValid) {
      statusEl?.classList.remove('invalid');
      if (textEl) textEl.textContent = `Verificata - Nessuna manomissione rilevata (${entriesChecked} record)`;
      showNotification('Integrita hash chain verificata con successo', 'success');
    } else {
      statusEl?.classList.add('invalid');
      if (textEl) textEl.textContent = `ATTENZIONE: Rilevata possibile manomissione (${result.issues?.length || 0} anomalie)`;
      showNotification('ATTENZIONE: Rilevata anomalia nella catena audit', 'error');
    }
    
  } catch (error) {
    console.error('[COMPLIANCE] Chain verification error:', error);
    if (textEl) textEl.textContent = 'Errore durante la verifica';
    showNotification('Errore durante la verifica dell\'integrita', 'error');
  }
}

async function repairAuditChain() {
  const statusEl = document.getElementById('chain-integrity-status');
  const textEl = document.getElementById('chain-status-text');
  
  if (textEl) textEl.textContent = 'Riparazione in corso...';
  
  try {
    const response = await adminFetch(`${API_BASE}/api/compliance/repair-chain`, {
      method: 'POST'
    });
    
    if (!response.ok) throw new Error('Riparazione fallita');
    
    const result = await response.json();
    
    if (result.success) {
      statusEl?.classList.remove('invalid');
      if (textEl) textEl.textContent = `Catena riparata - ${result.repairedCount} record aggiornati`;
      showNotification(`Catena hash riparata con successo: ${result.repairedCount} record aggiornati`, 'success');
      // Verify after repair
      setTimeout(() => verifyAuditChain(), 1000);
    } else {
      throw new Error(result.error || 'Riparazione fallita');
    }
    
  } catch (error) {
    console.error('[COMPLIANCE] Chain repair error:', error);
    if (textEl) textEl.textContent = 'Errore durante la riparazione';
    showNotification('Errore durante la riparazione della catena', 'error');
  }
}

function exportAuditLogs() {
  const filter = document.getElementById('audit-filter-action')?.value || '';
  const filteredLogs = filter 
    ? auditLogs.filter(log => log.action === filter)
    : auditLogs;
  
  if (filteredLogs.length === 0) {
    showNotification('Nessun log da esportare', 'warning');
    return;
  }
  
  const headers = ['Data/Ora', 'Utente', 'Azione', 'Entita', 'Descrizione', 'IP'];
  const rows = filteredLogs.map(log => {
    const date = new Date(log.timestamp);
    return [
      date.toISOString(),
      log.actorName || log.actorId || 'Sistema',
      log.action,
      log.entityType || '',
      (log.description || '').replace(/"/g, '""'),
      log.ipAddress || ''
    ];
  });
  
  const csv = [headers.join(','), ...rows.map(row => row.map(cell => `"${cell}"`).join(','))].join('\n');
  
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = `audit_log_${new Date().toISOString().split('T')[0]}.csv`;
  link.click();
  
  showNotification(`Esportati ${filteredLogs.length} record`, 'success');
}

// SLA & Backup Data Functions
async function loadSlaData() {
  console.log('[SLA] Loading SLA data...');
  try {
    const response = await adminFetch(`${API_BASE}/api/health`);
    if (response.ok) {
      const data = await response.json();
      updateSlaDisplay(data);
    }
  } catch (error) {
    console.error('[SLA] Error loading SLA data:', error);
  }
}

function updateSlaDisplay(data) {
  const uptimeEl = document.getElementById('sla-uptime');
  const responseTimeEl = document.getElementById('sla-response-time');
  const requestsEl = document.getElementById('sla-requests');
  const errorRateEl = document.getElementById('sla-error-rate');
  const statusTextEl = document.getElementById('sla-status-text');
  const statusBanner = document.getElementById('sla-status-banner');
  
  if (uptimeEl) uptimeEl.textContent = (data.uptime?.percentage || 100).toFixed(1) + '%';
  if (responseTimeEl) responseTimeEl.textContent = (data.performance?.averageResponseTimeMs || 0).toFixed(0) + 'ms';
  if (requestsEl) requestsEl.textContent = (data.performance?.requestCount || 0).toLocaleString('it-IT');
  if (errorRateEl) errorRateEl.textContent = (data.performance?.errorRate || 0).toFixed(2) + '%';
  
  const status = data.status || 'healthy';
  const indicator = statusBanner?.querySelector('.status-indicator');
  
  if (status === 'healthy') {
    if (indicator) indicator.className = 'status-indicator healthy';
    if (statusTextEl) statusTextEl.textContent = 'Sistema operativo - Tutti i servizi funzionanti';
  } else if (status === 'degraded') {
    if (indicator) indicator.className = 'status-indicator warning';
    if (statusTextEl) statusTextEl.textContent = 'Sistema degradato - Alcune funzionalita limitate';
  } else {
    if (indicator) indicator.className = 'status-indicator critical';
    if (statusTextEl) statusTextEl.textContent = 'Sistema non operativo - Intervento richiesto';
  }
}

async function loadBackupData() {
  console.log('[BACKUP] Loading backup data...');
  try {
    const response = await adminFetch(`${API_BASE}/api/backups/statistics`);
    if (response.ok) {
      const data = await response.json();
      updateBackupDisplay(data);
    }
  } catch (error) {
    console.error('[BACKUP] Error loading backup data:', error);
  }
}

function updateBackupDisplay(data) {
  const lastTimeEl = document.getElementById('backup-last-time');
  const totalCountEl = document.getElementById('backup-total-count');
  const verifiedEl = document.getElementById('backup-verified');
  const policiesEl = document.getElementById('backup-policies');
  const statusTextEl = document.getElementById('backup-status-text');
  const statusBanner = document.getElementById('backup-status-banner');
  
  if (lastTimeEl) {
    if (data.lastBackupAt) {
      const date = new Date(data.lastBackupAt);
      lastTimeEl.textContent = date.toLocaleString('it-IT', { dateStyle: 'short', timeStyle: 'short' });
    } else {
      lastTimeEl.textContent = 'Mai';
    }
  }
  
  if (totalCountEl) totalCountEl.textContent = (data.total || 0).toLocaleString('it-IT');
  if (verifiedEl) verifiedEl.textContent = (data.completed || 0).toLocaleString('it-IT');
  if (policiesEl) policiesEl.textContent = (data.successRate || 0) + '%';
  
  const indicator = statusBanner?.querySelector('.status-indicator');
  
  const isHealthy = data.lastBackupAgeHours === null || data.lastBackupAgeHours < 24;
  const isWarning = data.lastBackupAgeHours !== null && data.lastBackupAgeHours >= 24 && data.lastBackupAgeHours < 72;
  
  if (isHealthy && data.successRate >= 90) {
    if (indicator) indicator.className = 'status-indicator healthy';
    if (statusTextEl) statusTextEl.textContent = 'Sistema di backup configurato correttamente';
  } else if (isWarning || data.successRate >= 70) {
    if (indicator) indicator.className = 'status-indicator warning';
    if (statusTextEl) statusTextEl.textContent = 'Attenzione: Backup non recente';
  } else {
    if (indicator) indicator.className = 'status-indicator critical';
    if (statusTextEl) statusTextEl.textContent = 'Errore: Verificare sistema di backup';
  }
}

async function triggerBackup() {
  console.log('[BACKUP] Triggering manual backup...');
  try {
    const response = await adminFetch(`${API_BASE}/api/backups/trigger`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ type: 'full' })
    });
    
    if (response.ok) {
      showNotification('Backup avviato con successo', 'success');
      loadBackupData();
    } else {
      showNotification('Errore durante il backup', 'error');
    }
  } catch (error) {
    console.error('[BACKUP] Error triggering backup:', error);
    showNotification('Errore durante il backup', 'error');
  }
}

