// Navigate to location detail page from map
function navigateToLocation(locationId, locationName) {
  console.log('[VenetoMap] Navigating to location:', locationName, locationId);
  
  // Store current location for back navigation
  sessionStorage.setItem('previousPage', 'dashboard');
  sessionStorage.setItem('selectedLocationId', locationId);
  sessionStorage.setItem('selectedLocationName', locationName);
  
  // Show notification
  showNotification(`Accesso alla sede: ${locationName}`, 'info');
  
  // Navigate to locations page and filter for this location
  setTimeout(() => {
    // Simulate clicking on the locations nav item
    const locationsNav = document.querySelector('[data-page="locations"]');
    if (locationsNav) {
      locationsNav.click();
      
      // After navigation, open the location details
      setTimeout(() => {
        openLocationFromMap(locationId, locationName);
      }, 300);
    }
  }, 500);
}

// Open location details modal from map navigation
async function openLocationFromMap(locationId, locationName) {
  try {
    // Fetch location details
    const response = await adminFetch(`${API_BASE}/api/locations/${locationId}`);
    
    if (response.ok) {
      const location = await response.json();
      // Use existing showLocationDetails function or create modal
      if (typeof showLocationDetails === 'function') {
        showLocationDetails(location);
      } else {
        showLocationDetailModal(location);
      }
    } else {
      showNotification('Impossibile caricare i dettagli della sede', 'error');
    }
  } catch (error) {
    console.error('[VenetoMap] Error loading location:', error);
    showNotification('Errore nel caricamento della sede', 'error');
  }
}

