// Load location statistics
async function loadLocationStats(locationId) {
  try {
    // Get vehicles count
    const vehiclesRes = await adminFetch(`${API_BASE}/api/vehicles?locationId=${locationId}`);
    if (vehiclesRes.ok) {
      const vehicles = await vehiclesRes.json();
      const vehicleCount = document.querySelector('.enterprise-kpi-card:nth-child(1) > div:first-child');
      if (vehicleCount) vehicleCount.textContent = vehicles.length;
    }
    
    // Get trips count for current month
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString();
    const tripsRes = await adminFetch(`${API_BASE}/api/trips?locationId=${locationId}&startDate=${startOfMonth}`);
    if (tripsRes.ok) {
      const trips = await tripsRes.json();
      const tripsCount = document.querySelector('.enterprise-kpi-card:nth-child(2) > div:first-child');
      if (tripsCount) tripsCount.textContent = trips.length;
    }
  } catch (error) {
    console.error('[VenetoMap] Error loading location stats:', error);
  }
}

