function handleScannerTyping(e) {
  const now = Date.now();
  const timeDiff = now - lastInputTime;
  
  if (timeDiff < 50) {
    const statusEl = document.getElementById('scanner-status');
    if (statusEl) {
      statusEl.innerHTML = `
        <span style="display: inline-flex; align-items: center; gap: 6px; color: #7c3aed; font-size: 12px;">
          <span style="width: 8px; height: 8px; background: #7c3aed; border-radius: 50%; animation: pulse 0.3s infinite;"></span>
          Scansione...
        </span>
      `;
    }
  }
  lastInputTime = now;
}

function handleScannerInput(e) {
  if (e.key === 'Enter') {
    e.preventDefault();
    const input = e.target;
    const barcode = input.value.trim();
    
    if (barcode.length >= 3) {
      processScannedBarcode(barcode);
      input.value = '';
    }
    
    const statusEl = document.getElementById('scanner-status');
    if (statusEl) {
      statusEl.innerHTML = `
        <span class="scanner-ready-indicator" style="display: inline-flex; align-items: center; gap: 6px; color: #22c55e; font-size: 12px;">
          <span style="width: 8px; height: 8px; background: #22c55e; border-radius: 50%; animation: pulse 1.5s infinite;"></span>
          In attesa
        </span>
      `;
    }
  }
}

async function processScannedBarcode(barcode) {
  const existingItem = inventoryItems.find(item => item.barcode === barcode);
  const alreadyScanned = scannedItems.find(s => s.barcode === barcode);
  
  if (alreadyScanned) {
    alreadyScanned.quantity += 1;
    updateScannedItemsList();
  } else {
    const newItem = {
      barcode: barcode,
      name: existingItem?.name || null,
      itemId: existingItem?.id || null,
      isNew: !existingItem,
      quantity: 1,
      category: existingItem?.category || 'altro',
      isSearching: !existingItem
    };
    scannedItems.push(newItem);
    updateScannedItemsList();
    
    if (!existingItem) {
      const productInfo = await lookupBarcodeOnline(barcode);
      const idx = scannedItems.findIndex(s => s.barcode === barcode);
      if (idx !== -1 && productInfo) {
        scannedItems[idx].name = productInfo.name;
        scannedItems[idx].brand = productInfo.brand;
        scannedItems[idx].isSearching = false;
        if (productInfo.category) {
          scannedItems[idx].category = productInfo.category;
        }
      } else if (idx !== -1) {
        scannedItems[idx].isSearching = false;
      }
      updateScannedItemsList();
    }
  }
  
  const audio = new Audio('data:audio/wav;base64,');
  audio.volume = 0.3;
  audio.play().catch(() => {});
}

async function lookupBarcodeOnline(barcode) {
  const statusEl = document.getElementById('scanner-status');
  if (statusEl) {
    statusEl.innerHTML = `
      <span style="display: inline-flex; align-items: center; gap: 6px; color: #3b82f6; font-size: 12px;">
        <span class="spinner" style="width: 12px; height: 12px;"></span>
        Ricerca prodotto online...
      </span>
    `;
  }
  
  try {
    const response = await adminFetch(`${API_BASE}/api/inventory/barcode/${barcode}`);
    
    if (response.ok) {
      const data = await response.json();
      if (data.found && data.product?.name) {
        const source = data.source || 'database';
        const sourceLabel = source === 'internal' ? 'database interno' : 
                           source === 'fda_gudid' ? 'FDA GUDID' :
                           source === 'upcitemdb' ? 'UPC Database' :
                           source === 'openfoodfacts' ? 'Open Food Facts' : 'online';
        if (statusEl) {
          statusEl.innerHTML = `
            <span style="display: inline-flex; align-items: center; gap: 6px; color: #22c55e; font-size: 12px;">
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 6L9 17l-5-5"/></svg>
              Trovato in ${sourceLabel}!
            </span>
          `;
        }
        return { 
          name: data.product.name, 
          brand: data.product.brand || data.product.manufacturer, 
          category: mapExternalCategory(data.product.category)
        };
      }
    }
  } catch (error) {
    console.log('Barcode lookup error:', error);
  }
  
  if (statusEl) {
    statusEl.innerHTML = `
      <span style="display: inline-flex; align-items: center; gap: 6px; color: #f59e0b; font-size: 12px;">
        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 8v4"/><path d="M12 16h.01"/></svg>
        Prodotto non trovato - inserisci il nome
      </span>
    `;
  }
  return null;
}

function mapExternalCategory(externalCategory) {
  if (!externalCategory) return 'altro';
  const cat = externalCategory.toLowerCase();
  if (cat.includes('medic') || cat.includes('bandage') || cat.includes('gauze') || cat.includes('dressing')) return 'medicazione';
  if (cat.includes('farm') || cat.includes('drug') || cat.includes('pharma')) return 'farmaco';
  if (cat.includes('device') || cat.includes('dispositivo') || cat.includes('presidi')) return 'dispositivo';
  if (cat.includes('consum') || cat.includes('supply')) return 'consumabile';
  if (cat.includes('protez') || cat.includes('protect') || cat.includes('glove') || cat.includes('mask')) return 'protezione';
  return 'altro';
}

function updateScannedItemsList() {
  const container = document.getElementById('scanned-items-container');
  const countEl = document.getElementById('scanned-count');
  const saveBtn = document.getElementById('save-scanned-btn');
  
  if (!container) return;
  
  const totalItems = scannedItems.reduce((sum, item) => sum + item.quantity, 0);
  if (countEl) countEl.textContent = `(${totalItems})`;
  if (saveBtn) saveBtn.disabled = scannedItems.length === 0;
  
  if (scannedItems.length === 0) {
    container.innerHTML = `
      <div class="empty-scan-state" style="text-align: center; padding: 30px; color: #9ca3af; background: #f9fafb; border-radius: 8px; border: 1px dashed #e5e7eb;">
        <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" style="margin-bottom: 8px;"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M7 7h10v10H7z"/></svg>
        <p style="margin: 0; font-size: 14px;">Nessun articolo scansionato</p>
      </div>
    `;
    return;
  }
  
  container.innerHTML = scannedItems.map((item, idx) => `
    <div class="scanned-item" style="display: flex; flex-direction: column; gap: 8px; padding: 12px 16px; background: ${item.isNew ? '#fef3c7' : '#f0fdf4'}; border-radius: 8px; border: 1px solid ${item.isNew ? '#fcd34d' : '#86efac'};">
      <div style="display: flex; align-items: center; gap: 12px;">
        <div style="width: 40px; height: 40px; background: ${item.isNew ? '#f59e0b' : '#22c55e'}; border-radius: 8px; display: flex; align-items: center; justify-content: center; flex-shrink: 0;">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2">
            ${item.isNew ? '<path d="M12 5v14"/><path d="M5 12h14"/>' : '<path d="M20 6L9 17l-5-5"/>'}
          </svg>
        </div>
        <div style="flex: 1; min-width: 0;">
          <div style="font-weight: 600; color: #1f2937; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;">
            ${item.name || 'Nuovo Articolo'}
          </div>
          <div style="font-size: 12px; color: #6b7280; font-family: monospace;">
            ${item.barcode}
          </div>
        </div>
        <div style="display: flex; align-items: center; gap: 8px;">
          <button type="button" onclick="adjustScannedQty(${idx}, -1)" style="width: 28px; height: 28px; border: 1px solid #e5e7eb; border-radius: 6px; background: white; cursor: pointer; display: flex; align-items: center; justify-content: center;">-</button>
          <span style="min-width: 30px; text-align: center; font-weight: 600; color: #7c3aed;">${item.quantity}</span>
          <button type="button" onclick="adjustScannedQty(${idx}, 1)" style="width: 28px; height: 28px; border: 1px solid #e5e7eb; border-radius: 6px; background: white; cursor: pointer; display: flex; align-items: center; justify-content: center;">+</button>
        </div>
        <button type="button" onclick="removeScannedItem(${idx})" style="width: 32px; height: 32px; border: none; background: transparent; cursor: pointer; color: #ef4444; display: flex; align-items: center; justify-content: center;">
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
        </button>
        ${item.isNew ? `<span style="background: #f59e0b; color: white; font-size: 10px; padding: 2px 8px; border-radius: 10px; font-weight: 600;">NUOVO</span>` : ''}
      </div>
      ${item.isNew ? `
        <div style="display: flex; gap: 8px; margin-top: 4px;">
          <input type="text" 
            id="item-name-${idx}"
            placeholder="Inserisci nome articolo..." 
            value="${item.name || ''}"
            onchange="updateScannedItemName(${idx}, this.value)"
            style="flex: 1; padding: 8px 12px; border: 1px solid #e5e7eb; border-radius: 6px; font-size: 13px; background: white;">
          <select onchange="updateScannedItemCategory(${idx}, this.value)" style="padding: 8px 12px; border: 1px solid #e5e7eb; border-radius: 6px; font-size: 13px; background: white;">
            <option value="altro" ${item.category === 'altro' ? 'selected' : ''}>Altro</option>
            <option value="medicazione" ${item.category === 'medicazione' ? 'selected' : ''}>Medicazione</option>
            <option value="farmaco" ${item.category === 'farmaco' ? 'selected' : ''}>Farmaco</option>
            <option value="dispositivo" ${item.category === 'dispositivo' ? 'selected' : ''}>Dispositivo</option>
            <option value="consumabile" ${item.category === 'consumabile' ? 'selected' : ''}>Consumabile</option>
          </select>
        </div>
      ` : ''}
    </div>
  `).join('');
}

function adjustScannedQty(idx, delta) {
  if (scannedItems[idx]) {
    scannedItems[idx].quantity = Math.max(1, scannedItems[idx].quantity + delta);
    updateScannedItemsList();
  }
}

function removeScannedItem(idx) {
  scannedItems.splice(idx, 1);
  updateScannedItemsList();
}

function clearScannedItems() {
  scannedItems = [];
  updateScannedItemsList();
}

function updateScannedItemName(idx, name) {
  if (scannedItems[idx]) {
    scannedItems[idx].name = name;
  }
}

function updateScannedItemCategory(idx, category) {
  if (scannedItems[idx]) {
    scannedItems[idx].category = category;
  }
}

window.updateScannedItemName = updateScannedItemName;
window.updateScannedItemCategory = updateScannedItemCategory;

async function saveScannedItems() {
  if (scannedItems.length === 0) return;
  
  const saveBtn = document.getElementById('save-scanned-btn');
  if (saveBtn) {
    saveBtn.disabled = true;
    saveBtn.innerHTML = '<span class="spinner" style="width:16px;height:16px;"></span> Salvataggio...';
  }
  
  let savedCount = 0;
  let newCount = 0;
  
  for (const item of scannedItems) {
    try {
      if (item.isNew) {
        const response = await adminFetch(`${API_BASE}/api/inventory/items`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: item.name || `Articolo ${item.barcode}`,
            barcode: item.barcode,
            category: item.category || 'altro',
            unit: 'pz',
            minStockLevel: 5,
            hasExpiry: true,
            expiryAlertDays: 30
          })
        });
        if (response.ok) {
          newCount++;
          savedCount++;
        }
      } else {
        savedCount++;
      }
    } catch (error) {
      console.error('Error saving scanned item:', error);
    }
  }
  
  showNotification(`${savedCount} articoli elaborati (${newCount} nuovi creati)`, 'success');
  closeScannerModal();
  loadInventoryData();
}

function closeScannerModal() {
  scannerModalOpen = false;
  scannedItems = [];
  
  const scannerInput = document.getElementById('scanner-input');
  if (scannerInput && scannerKeydownHandler) {
    scannerInput.removeEventListener('keydown', scannerKeydownHandler);
  }
  if (scannerInput && scannerInputHandler) {
    scannerInput.removeEventListener('input', scannerInputHandler);
  }
  scannerKeydownHandler = null;
  scannerInputHandler = null;
  
  const overlay = document.getElementById('scanner-modal-overlay');
  if (overlay) {
    overlay.classList.remove('active');
    setTimeout(() => overlay.remove(), 300);
  }
}

