async function addEventAssignment(eventId) {
  const staffId = document.getElementById('add-event-staff-select')?.value;
  if (!staffId) {
    showNotification('Seleziona un membro del personale', 'error');
    return;
  }
  
  try {
    const res = await adminFetch(`${API_BASE}/api/sporting-events/${eventId}/assignments`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ staffMemberId: staffId, assignedRole: 'soccorritore' })
    });
    
    if (res.ok) {
      showNotification('Personale assegnato', 'success');
      await loadSportingEvents();
      loadEventDetails(eventId);
    } else {
      const err = await res.json().catch(() => ({}));
      showNotification(err.error || 'Errore nell\'assegnazione', 'error');
    }
  } catch (error) {
    showNotification('Errore di connessione', 'error');
  }
}

async function quickAssignStaff(eventId, staffId, role) {
  const card = event.currentTarget;
  card.classList.add('assigning');
  
  try {
    const res = await adminFetch(`${API_BASE}/api/sporting-events/${eventId}/assignments`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ staffMemberId: staffId, assignedRole: role || 'soccorritore' })
    });
    
    if (res.ok) {
      card.classList.add('assigned-success');
      setTimeout(async () => {
        await loadSportingEvents();
        loadEventDetails(eventId);
      }, 300);
    } else {
      card.classList.remove('assigning');
      const err = await res.json().catch(() => ({}));
      showNotification(err.error || 'Errore nell\'assegnazione', 'error');
    }
  } catch (error) {
    card.classList.remove('assigning');
    showNotification('Errore di connessione', 'error');
  }
}

function filterAvailableStaff() {
  const searchInput = document.getElementById('event-staff-search-input');
  const searchTerm = (searchInput?.value || '').toLowerCase().trim();
  const container = document.getElementById('available-staff-container');
  
  if (!container) return;
  
  const cards = container.querySelectorAll('.staff-card.available');
  
  cards.forEach(card => {
    const name = card.dataset.name || '';
    const matches = searchTerm === '' || name.includes(searchTerm);
    card.style.display = matches ? 'flex' : 'none';
  });
}

function setupEventStaffSearch() {
  const searchInput = document.getElementById('event-staff-search-input');
  if (searchInput) {
    searchInput.addEventListener('input', filterAvailableStaff);
    searchInput.addEventListener('keyup', filterAvailableStaff);
  }
}

function filterStaffByRole(eventId, role, btn) {
  const container = document.getElementById('available-staff-container');
  if (!container) return;
  
  document.querySelectorAll('.role-filter-tabs .role-tab').forEach(t => t.classList.remove('active'));
  btn.classList.add('active');
  
  const cards = container.querySelectorAll('.staff-card');
  cards.forEach(card => {
    const cardRole = card.dataset.role || '';
    const matches = role === 'all' || cardRole === role;
    card.style.display = matches ? '' : 'none';
  });
}

async function removeEventAssignment(eventId, assignmentId) {
  if (!confirm('Rimuovere questo membro dall\'evento?')) return;
  
  try {
    const res = await adminFetch(`${API_BASE}/api/sporting-events/${eventId}/assignments/${assignmentId}`, {
      method: 'DELETE'
    });
    
    if (res.ok) {
      showNotification('Assegnazione rimossa', 'success');
      await loadSportingEvents();
      loadEventDetails(eventId);
    } else {
      const err = await res.json().catch(() => ({}));
      showNotification(err.error || 'Errore nella rimozione', 'error');
    }
  } catch (error) {
    showNotification('Errore di connessione', 'error');
  }
}
window.viewInventoryLog = viewInventoryLog;
window.closeModal = closeModal;

// ========================================
// SCADENZE MATERIALI FUNCTIONS
// ========================================

let scadenzeReports = [];

async function loadScadenzeData() {
  const monthFilter = document.getElementById('scadenze-month-filter')?.value;
  const yearFilter = document.getElementById('scadenze-year-filter')?.value || new Date().getFullYear();
  
  try {
    // Build query params
    const params = new URLSearchParams();
    if (monthFilter) params.append('month', monthFilter);
    params.append('year', yearFilter);
    
    const response = await adminFetch(`${API_BASE}/api/scadenze?${params}`);
    if (!response.ok) throw new Error('Failed to load scadenze data');
    
    scadenzeReports = await response.json();
    updateScadenzeStats();
    renderScadenzeTable();
  } catch (error) {
    console.error('Error loading scadenze:', error);
    showNotification('Errore nel caricamento scadenze', 'error');
  }
}

function updateScadenzeStats() {
  const completedCount = scadenzeReports.length;
  
  let totalExpired = 0;
  let totalExpiring = 0;
  let totalItems = 0;
  const expiringItems = [];
  const expiredItems = [];
  
  scadenzeReports.forEach(report => {
    const items = report.items || [];
    const vehicle = vehicles.find(v => v.id === report.vehicleId);
    items.forEach(item => {
      totalItems++;
      if (item.status === 'expired') {
        totalExpired++;
        expiredItems.push({ ...item, vehicle: vehicle?.code || 'N/A', reportId: report.id });
      }
      if (item.status === 'expiring') {
        totalExpiring++;
        expiringItems.push({ ...item, vehicle: vehicle?.code || 'N/A', reportId: report.id });
      }
    });
  });
  
  const completedEl = document.getElementById('scadenze-completed-count');
  const expiringSoonEl = document.getElementById('scadenze-expiring-soon');
  const expiredEl = document.getElementById('scadenze-expired-count');
  const totalEl = document.getElementById('scadenze-total-items');
  const urgencyCountEl = document.getElementById('urgency-count');
  
  if (completedEl) completedEl.textContent = completedCount;
  if (expiringSoonEl) expiringSoonEl.textContent = totalExpiring;
  if (expiredEl) expiredEl.textContent = totalExpired;
  if (totalEl) totalEl.textContent = totalItems;
  if (urgencyCountEl) urgencyCountEl.textContent = totalExpired + totalExpiring;
  
  updateScadenzeAlertBanner(totalExpired, totalExpiring);
  renderScadenzeTimeline(expiringItems, expiredItems);
  renderScadenzeUrgencies(expiredItems, expiringItems);
}

function renderScadenzeTimeline(expiringItems, expiredItems) {
  const container = document.getElementById('scadenze-timeline');
  if (!container) return;
  
  const allItems = [...expiredItems, ...expiringItems].slice(0, 10);
  
  if (allItems.length === 0) {
    container.innerHTML = `
      <div class="timeline-empty">
        <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
        <p>Nessuna scadenza da visualizzare</p>
        <span>Le scadenze appariranno qui quando verranno rilevate</span>
      </div>`;
    return;
  }
  
  container.innerHTML = allItems.map((item, idx) => {
    const isExpired = item.status === 'expired';
    const statusClass = isExpired ? 'critical' : 'warning';
    const statusText = isExpired ? 'Scaduto' : 'In Scadenza';
    
    return `
      <div class="timeline-item ${statusClass}" style="animation-delay: ${idx * 0.1}s">
        <div class="timeline-marker ${statusClass}"></div>
        <div class="timeline-content">
          <div class="timeline-header">
            <span class="timeline-title">${item.name || 'Articolo'}</span>
            <span class="timeline-badge ${statusClass}">${statusText}</span>
          </div>
          <div class="timeline-meta">
            <span>Veicolo: ${item.vehicle}</span>
            ${item.expiryDate ? `<span>Scadenza: ${new Date(item.expiryDate).toLocaleDateString('it-IT')}</span>` : ''}
          </div>
        </div>
      </div>`;
  }).join('');
}

function renderScadenzeUrgencies(expiredItems, expiringItems) {
  const container = document.getElementById('scadenze-urgencies');
  if (!container) return;
  
  const urgentItems = [...expiredItems, ...expiringItems.slice(0, 5)];
  
  if (urgentItems.length === 0) {
    container.innerHTML = `
      <div class="urgency-empty">
        <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
        <p>Tutto in ordine!</p>
        <span>Nessuna azione urgente richiesta</span>
      </div>`;
    return;
  }
  
  container.innerHTML = urgentItems.map((item, idx) => {
    const isExpired = item.status === 'expired';
    const priorityClass = isExpired ? 'critical' : 'warning';
    
    return `
      <div class="urgency-item ${priorityClass}" style="animation-delay: ${idx * 0.1}s">
        <div class="urgency-priority ${priorityClass}">
          ${isExpired ? 
            '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="m15 9-6 6"/><path d="m9 9 6 6"/></svg>' : 
            '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>'
          }
        </div>
        <div class="urgency-info">
          <span class="urgency-name">${item.name || 'Articolo'}</span>
          <span class="urgency-vehicle">${item.vehicle}</span>
        </div>
        <button class="urgency-action" onclick="navigateTo('inventory')" title="Vai al magazzino">
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"/></svg>
        </button>
      </div>`;
  }).join('');
}

function renderScadenzeTable() {
  const tbody = document.getElementById('scadenze-tbody');
  if (!tbody) return;
  
  if (scadenzeReports.length === 0) {
    tbody.innerHTML = '<tr><td colspan="9" class="empty-state">Nessun report scadenze trovato</td></tr>';
    return;
  }
  
  const monthNames = ['Gennaio', 'Febbraio', 'Marzo', 'Aprile', 'Maggio', 'Giugno', 
                      'Luglio', 'Agosto', 'Settembre', 'Ottobre', 'Novembre', 'Dicembre'];
  
  tbody.innerHTML = scadenzeReports.map(report => {
    const vehicle = vehicles.find(v => v.id === report.vehicleId);
    const location = locations.find(l => l.id === report.locationId);
    const items = report.items || [];
    
    const expiredCount = items.filter(i => i.status === 'expired').length;
    const expiringCount = items.filter(i => i.status === 'expiring').length;
    
    const monthYear = `${monthNames[report.month - 1]} ${report.year}`;
    const submittedDate = report.submittedAt ? new Date(report.submittedAt).toLocaleDateString('it-IT') : '-';
    
    return `
      <tr>
        <td><strong>${vehicle?.code || 'N/A'}</strong></td>
        <td>${location?.name || 'N/A'}</td>
        <td>${monthYear}</td>
        <td>${report.submittedBy || '-'}</td>
        <td>${submittedDate}</td>
        <td><span class="badge ${expiredCount > 0 ? 'badge-error' : 'badge-success'}">${expiredCount}</span></td>
        <td><span class="badge ${expiringCount > 0 ? 'badge-warning' : 'badge-success'}">${expiringCount}</span></td>
        <td>${items.length}</td>
        <td>
          <button class="btn btn-sm btn-secondary" onclick="downloadScadenzePdf(${report.id})" title="Scarica PDF">
            <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
          </button>
        </td>
      </tr>
    `;
  }).join('');
}

async function downloadScadenzePdf(reportId) {
  try {
    const response = await adminFetch(`${API_BASE}/api/scadenze/${reportId}/pdf`);
    if (!response.ok) throw new Error('Failed to download PDF');
    
    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `scadenze-report-${reportId}.pdf`;
    document.body.appendChild(a);
    a.click();
    window.URL.revokeObjectURL(url);
    a.remove();
    
    showNotification('PDF scaricato', 'success');
  } catch (error) {
    console.error('Error downloading PDF:', error);
    showNotification('Errore nel download PDF', 'error');
  }
}

