function closeScadenzeSettingsModal() {
  const modal = document.getElementById('scadenze-settings-modal');
  if (modal) modal.remove();
}

function saveScadenzeSettings() {
  localStorage.setItem('scadenzeSettings', JSON.stringify(scadenzeSettings));
  showNotification('Impostazioni salvate con successo', 'success');
  closeScadenzeSettingsModal();
}

function hideAlertBanner() {
  const banner = document.getElementById('scadenze-alert-banner');
  if (banner) banner.classList.remove('visible');
}

function showExpiringItems() {
  navigateTo('inventory');
  showNotification('Naviga alla sezione Magazzino per vedere gli articoli in scadenza', 'info');
}

function updateScadenzeAlertBanner(expiredCount, expiringCount) {
  const banner = document.getElementById('scadenze-alert-banner');
  const title = document.getElementById('alert-banner-title');
  const message = document.getElementById('alert-banner-message');
  
  if (!banner) return;
  
  if (expiredCount > 0) {
    title.textContent = 'URGENTE - Materiali Scaduti!';
    message.textContent = `Ci sono ${expiredCount} materiali scaduti e ${expiringCount} in scadenza. Azione immediata richiesta.`;
    banner.classList.add('visible');
  } else if (expiringCount > 0) {
    title.textContent = 'Attenzione';
    message.textContent = `Ci sono ${expiringCount} materiali in scadenza nei prossimi 30 giorni.`;
    banner.classList.add('visible');
  } else {
    banner.classList.remove('visible');
  }
}

function exportScadenzeExcel() {
  if (scadenzeReports.length === 0) {
    showNotification('Nessun dato da esportare', 'warning');
    return;
  }
  
  const monthNames = ['Gennaio', 'Febbraio', 'Marzo', 'Aprile', 'Maggio', 'Giugno', 
                      'Luglio', 'Agosto', 'Settembre', 'Ottobre', 'Novembre', 'Dicembre'];
  
  let csvContent = 'Veicolo,Sede,Periodo,Compilato da,Data,Scaduti,In Scadenza,Totale Articoli\n';
  
  scadenzeReports.forEach(report => {
    const vehicle = vehicles.find(v => v.id === report.vehicleId);
    const location = locations.find(l => l.id === report.locationId);
    const items = report.items || [];
    const expiredCount = items.filter(i => i.status === 'expired').length;
    const expiringCount = items.filter(i => i.status === 'expiring').length;
    const monthYear = `${monthNames[report.month - 1]} ${report.year}`;
    const submittedDate = report.submittedAt ? new Date(report.submittedAt).toLocaleDateString('it-IT') : '-';
    
    csvContent += `"${vehicle?.code || 'N/A'}","${location?.name || 'N/A'}","${monthYear}","${report.submittedBy || '-'}","${submittedDate}",${expiredCount},${expiringCount},${items.length}\n`;
  });
  
  const blob = new Blob(['\ufeff' + csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `scadenze-report-${new Date().toISOString().split('T')[0]}.csv`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
  
  showNotification('Report esportato in CSV', 'success');
}

function printScadenzeReport() {
  window.print();
}

// Initialize scadenze tabs
document.addEventListener('DOMContentLoaded', () => {
  const savedSettings = localStorage.getItem('scadenzeSettings');
  if (savedSettings) {
    scadenzeSettings = JSON.parse(savedSettings);
  }
  
  document.querySelectorAll('.panel-tab[data-view]').forEach(tab => {
    tab.addEventListener('click', function() {
      const parent = this.closest('.panel-header-premium');
      parent.querySelectorAll('.panel-tab').forEach(t => t.classList.remove('active'));
      this.classList.add('active');
      
      const view = this.dataset.view;
      if (view === 'calendar') {
        showCalendarView();
      } else {
        loadScadenzeData();
      }
    });
  });
});

function showCalendarView() {
  const container = document.getElementById('scadenze-timeline');
  if (!container) return;
  
  const today = new Date();
  const month = today.getMonth();
  const year = today.getFullYear();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay();
  
  const monthNames = ['Gennaio', 'Febbraio', 'Marzo', 'Aprile', 'Maggio', 'Giugno',
                      'Luglio', 'Agosto', 'Settembre', 'Ottobre', 'Novembre', 'Dicembre'];
  
  let calendarHtml = `
    <div class="scadenze-calendar">
      <div class="calendar-header-premium">
        <h4 style="color:#f8fafc;margin:0;">${monthNames[month]} ${year}</h4>
      </div>
      <div class="calendar-grid">
        <div class="calendar-day-header">Lun</div>
        <div class="calendar-day-header">Mar</div>
        <div class="calendar-day-header">Mer</div>
        <div class="calendar-day-header">Gio</div>
        <div class="calendar-day-header">Ven</div>
        <div class="calendar-day-header">Sab</div>
        <div class="calendar-day-header">Dom</div>
  `;
  
  const adjustedFirstDay = firstDay === 0 ? 6 : firstDay - 1;
  for (let i = 0; i < adjustedFirstDay; i++) {
    calendarHtml += '<div class="calendar-day empty"></div>';
  }
  
  for (let day = 1; day <= daysInMonth; day++) {
    const isToday = day === today.getDate();
    const hasExpiry = Math.random() < 0.15;
    calendarHtml += `
      <div class="calendar-day ${isToday ? 'today' : ''} ${hasExpiry ? 'has-expiry' : ''}">
        <span class="day-number">${day}</span>
        ${hasExpiry ? '<span class="expiry-dot"></span>' : ''}
      </div>
    `;
  }
  
  calendarHtml += '</div></div>';
  container.innerHTML = calendarHtml;
}

