// ========================================
// DATA QUALITY DASHBOARD FUNCTIONS
// ========================================

let dqGaugeChart = null;

async function loadDataQualityData() {
  console.log('[DATA-QUALITY] Loading data quality metrics...');
  
  try {
    const response = await adminFetch(`${API_BASE}/api/data-quality/metrics`);
    
    if (!response.ok) throw new Error('Failed to fetch data quality metrics');
    
    const data = await response.json();
    console.log('[DATA-QUALITY] Metrics loaded:', data);
    
    renderDataQualityDashboard(data);
  } catch (error) {
    console.error('[DATA-QUALITY] Error loading data:', error);
    showNotification('Errore nel caricamento metriche qualita', 'error');
  }
}

function renderDataQualityDashboard(data) {
  // Update timestamp
  const now = new Date();
  const timeStr = now.toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
  const updateTimeEl = document.getElementById('dq-update-time');
  if (updateTimeEl) updateTimeEl.textContent = timeStr;
  const footerTimeEl = document.getElementById('dq-footer-time');
  if (footerTimeEl) footerTimeEl.textContent = `Oggi ${timeStr}`;
  const clockEl = document.getElementById('dq-clock');
  if (clockEl) clockEl.textContent = timeStr;
  
  // Score
  const score = data.qualityScore || 0;
  document.getElementById('dq-score').textContent = score;
  const scoreLabel = score >= 80 ? 'Ottimo' : score >= 60 ? 'Buono' : score >= 40 ? 'Sufficiente' : 'Critico';
  document.getElementById('dq-score-label').textContent = scoreLabel;
  
  const changeEl = document.getElementById('dq-score-change');
  const change = data.scoreChange || 0;
  changeEl.innerHTML = `<span class="dq-change-value" style="color: ${change >= 0 ? '#22c55e' : '#ef4444'}">${change >= 0 ? '+' : ''}${change}</span> rispetto a ieri`;
  
  // Stats
  document.getElementById('dq-total-records').textContent = formatNumber(data.totalRecords || 0);
  document.getElementById('dq-critical-records').textContent = formatNumber(data.criticalRecords || 0);
  
  // Completeness
  const completePct = data.completenessPercent || 0;
  document.getElementById('dq-complete-pct').textContent = `${completePct}%`;
  document.getElementById('dq-detail-pct').textContent = `${completePct}%`;
  
  // Animate rings
  const dashoffset = 220 - (220 * completePct / 100);
  const ring = document.getElementById('dq-complete-ring');
  if (ring) ring.style.strokeDashoffset = dashoffset;
  
  const detailDashoffset = 157 - (157 * completePct / 100);
  const detailRing = document.getElementById('dq-detail-ring');
  if (detailRing) detailRing.style.strokeDashoffset = detailDashoffset;
  
  document.getElementById('dq-incomplete-count').textContent = data.incompleteTrips || 0;
  document.getElementById('dq-detail-incomplete').textContent = data.incompleteTrips || 0;
  document.getElementById('dq-total-badge').textContent = data.totalRecords || 0;
  
  // Missing fields
  const missingFields = data.missingFields || {};
  document.getElementById('dq-missing-datetime').textContent = missingFields.datetime || 0;
  document.getElementById('dq-missing-destination').textContent = missingFields.destination || 0;
  document.getElementById('dq-missing-km').textContent = missingFields.km || 0;
  document.getElementById('dq-breakdown-datetime').textContent = missingFields.datetime || 0;
  document.getElementById('dq-breakdown-destination').textContent = missingFields.destination || 0;
  document.getElementById('dq-breakdown-km').textContent = missingFields.km || 0;
  
  // Anomalies (comprehensive engine)
  const anomalies = data.anomalies || {};
  const totalAnomalies = (anomalies.kmInvalid || 0) + (anomalies.kmRegression || 0) + 
                         (anomalies.timeInvalid || 0) + (anomalies.noDeparture || 0) + 
                         (anomalies.overlap || 0) + (anomalies.durationMismatch || 0) +
                         (anomalies.kmImplausible || 0);
  document.getElementById('dq-anomaly-count').textContent = totalAnomalies;
  document.getElementById('dq-anom-km').textContent = (anomalies.kmInvalid || 0) + (anomalies.kmRegression || 0);
  document.getElementById('dq-anom-short').textContent = (anomalies.durationMismatch || 0) + (anomalies.kmImplausible || 0);
  document.getElementById('dq-anom-nostart').textContent = (anomalies.noDeparture || 0) + (anomalies.timeInvalid || 0);
  document.getElementById('dq-anom-vehicle').textContent = anomalies.overlap || 0;
  
  // Real-time/Timeliness stats
  const realtimePct = data.realtimePercent || 0;
  document.getElementById('dq-realtime-pct').textContent = `${realtimePct}%`;
  const latePct = data.latePercent || 0;
  document.getElementById('dq-rt-late').textContent = `- ${latePct}%`;
  document.getElementById('dq-rt-change').textContent = `Tempestivita: ${data.timelinessScore || 0}%`;
  
  // Critical records table
  renderCriticalRecordsTable(data.criticalDetails || []);
  
  // Render gauge
  renderDQGauge(score);
}

function renderDQGauge(score) {
  const ctx = document.getElementById('dq-gauge-chart');
  if (!ctx) return;
  
  if (dqGaugeChart) {
    dqGaugeChart.destroy();
  }
  
  const gaugeColor = score >= 80 ? '#22c55e' : score >= 60 ? '#eab308' : score >= 40 ? '#f59e0b' : '#ef4444';
  
  dqGaugeChart = new Chart(ctx, {
    type: 'doughnut',
    data: {
      datasets: [{
        data: [score, 100 - score],
        backgroundColor: [gaugeColor, 'rgba(30, 58, 95, 0.5)'],
        borderWidth: 0,
        circumference: 180,
        rotation: 270
      }]
    },
    options: {
      responsive: false,
      maintainAspectRatio: false,
      cutout: '75%',
      plugins: {
        legend: { display: false },
        tooltip: { enabled: false }
      }
    }
  });
}

function renderCriticalRecordsTable(records) {
  const tbody = document.getElementById('dq-critical-tbody');
  if (!tbody) return;
  
  if (!records || records.length === 0) {
    tbody.innerHTML = '<tr><td colspan="4" class="dq-empty">Nessun record critico</td></tr>';
    return;
  }
  
  tbody.innerHTML = records.slice(0, 10).map(record => {
    const statusClass = record.status === 'incomplete' ? 'incomplete' : 
                        record.status === 'anomaly' ? 'inconsistent' :
                        record.status === 'inconsistent' ? 'inconsistent' :
                        record.status === 'late' ? 'late' : 'valid';
    const statusText = record.status === 'incomplete' ? 'Incompleto' :
                       record.status === 'anomaly' ? 'Anomalia' :
                       record.status === 'inconsistent' ? 'Incoerente' :
                       record.status === 'late' ? 'Tardivo' : 'Validato';
    
    const issueText = record.issue ? ` title="${record.issue}"` : '';
    
    return `
      <tr${issueText}>
        <td>${record.vehicleCode || 'N/A'} - ${record.progressiveNumber || 'N/A'}</td>
        <td>${record.serviceType || 'Ordinario'}</td>
        <td><span class="dq-status-badge ${statusClass}">${statusText}</span></td>
        <td><button class="dq-resolve-btn" onclick="resolveRecord('${record.id}')">Risolvi</button></td>
      </tr>
    `;
  }).join('');
}

// Global storage for quality data
let dqDetailedData = null;
let dqAnomalies = [];
let dqEnrichedAnomalies = [];
let dqIncompleteTrips = [];
let dqCriticalRecords = [];

async function loadAllQualityRecords() {
  try {
    const [metricsRes, anomaliesRes] = await Promise.all([
      adminFetch(`${API_BASE}/api/data-quality/detailed`),
      adminFetch(`${API_BASE}/api/data-quality/anomalies`)
    ]);
    
    if (metricsRes.ok) {
      dqDetailedData = await metricsRes.json();
      dqIncompleteTrips = dqDetailedData.completeness?.incompleteTrips || [];
      dqCriticalRecords = dqDetailedData.criticalRecords || [];
    }
    if (anomaliesRes.ok) {
      const data = await anomaliesRes.json();
      dqAnomalies = data.anomalies || [];
      
      // Enrich anomalies with vehicle/progressive info from critical records
      dqEnrichedAnomalies = dqAnomalies.map(a => {
        const criticalMatch = dqCriticalRecords.find(r => r.id === a.entityId);
        const incompleteMatch = dqIncompleteTrips.find(r => r.id === a.entityId);
        return {
          ...a,
          vehicleCode: criticalMatch?.vehicleCode || incompleteMatch?.vehicleCode || '-',
          progressiveNumber: criticalMatch?.progressiveNumber || incompleteMatch?.progressiveNumber || '-',
          serviceDate: criticalMatch?.serviceDate || incompleteMatch?.serviceDate || '-'
        };
      });
    }
    console.log('[DATA-QUALITY] Loaded detailed data:', { 
      incomplete: dqIncompleteTrips.length, 
      anomalies: dqAnomalies.length,
      enrichedAnomalies: dqEnrichedAnomalies.length,
      critical: dqCriticalRecords.length 
    });
  } catch (error) {
    console.error('Error loading quality records:', error);
  }
}

function viewMonitoredRecords() {
  showDataQualityModal('monitored');
}

function viewIncompleteTrips() {
  showDataQualityModal('incomplete');
}

function exploreAnomalies() {
  showDataQualityModal('anomalies');
}

function viewAllCritical() {
  showDataQualityModal('critical');
}

function viewMissingField(fieldType) {
  showDataQualityModal('missing', fieldType);
}

async function showDataQualityModal(mode, filter = null) {
  // Load data if not already loaded
  if (!dqDetailedData && dqAnomalies.length === 0) {
    await loadAllQualityRecords();
  }
  
  let title = '';
  let content = '';
  
  switch (mode) {
    case 'monitored':
      title = 'Record Monitorati';
      content = renderMonitoredRecordsTable();
      break;
    case 'incomplete':
      title = 'Viaggi Incompleti';
      content = renderIncompleteRecordsTable();
      break;
    case 'anomalies':
      title = 'Esplora Anomalie';
      content = renderAnomaliesTable();
      break;
    case 'critical':
      title = 'Record Critici';
      content = renderCriticalRecordsModal();
      break;
    case 'missing':
      title = `Campi Mancanti: ${filter}`;
      content = renderMissingFieldsTable(filter);
      break;
  }
  
  const modalHtml = `
    <div class="modal-overlay dq-modal-overlay" id="dq-detail-modal" onclick="closeDQModal(event)">
      <div class="modal-content dq-modal-content" onclick="event.stopPropagation()">
        <div class="modal-header dq-modal-header">
          <h3>${title}</h3>
          <button class="modal-close" onclick="closeDQModal()">&times;</button>
        </div>
        <div class="modal-body dq-modal-body">
          ${content}
        </div>
        <div class="modal-footer dq-modal-footer">
          <button class="btn btn-secondary" onclick="closeDQModal()">Chiudi</button>
          <button class="btn btn-primary" onclick="exportDQData('${mode}')">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7,10 12,15 17,10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            Esporta CSV
          </button>
        </div>
      </div>
    </div>
  `;
  
  document.body.insertAdjacentHTML('beforeend', modalHtml);
  // Add active class to make modal visible (CSS hides modals without .active)
  const insertedModal = document.getElementById('dq-detail-modal');
  if (insertedModal) {
    insertedModal.classList.add('active');
  }
}

function renderMonitoredRecordsTable() {
  // Combine incomplete and critical records for monitored view
  const totalRecords = dqDetailedData?.overview?.totalTrips || 0;
  const incompleteRecords = dqIncompleteTrips.slice(0, 50);
  const critRecords = dqCriticalRecords.slice(0, 50);
  
  // Merge and deduplicate
  const recordMap = new Map();
  for (const r of incompleteRecords) {
    recordMap.set(r.id, { ...r, status: 'incomplete', issues: r.missingFields });
  }
  for (const r of critRecords) {
    if (recordMap.has(r.id)) {
      const existing = recordMap.get(r.id);
      existing.issues = [...(existing.issues || []), ...r.issues];
      existing.status = r.severity === 'critical' ? 'critical' : existing.status;
    } else {
      recordMap.set(r.id, { ...r, status: r.severity });
    }
  }
  
  const records = Array.from(recordMap.values());
  
  if (records.length === 0) {
    return '<div class="dq-empty-state">Tutti i record sono validi! Nessun problema rilevato.</div>';
  }
  
  return `
    <div class="dq-table-info">Record con problemi: <strong>${records.length}</strong> su ${totalRecords} totali</div>
    <div class="dq-table-scroll">
      <table class="dq-detail-table">
        <thead>
          <tr>
            <th>N. Progressivo</th>
            <th>Veicolo</th>
            <th>Data</th>
            <th>Problemi</th>
            <th>Stato</th>
            <th>Azioni</th>
          </tr>
        </thead>
        <tbody>
          ${records.map(r => `
            <tr class="${r.status === 'critical' ? 'critical-row' : 'incomplete-row'}">
              <td>${r.progressiveNumber || '-'}</td>
              <td>${r.vehicleCode || '-'}</td>
              <td>${r.serviceDate || '-'}</td>
              <td>${(r.issues || r.missingFields || []).slice(0, 3).join(', ')}</td>
              <td><span class="dq-status-badge ${r.status}">${r.status === 'critical' ? 'Critico' : 'Incompleto'}</span></td>
              <td>
                <button class="dq-action-btn-sm" onclick="resolveRecord('${r.id}')">
                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>
                  Modifica
                </button>
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

