function renderAnomaliesTable() {
  if (dqEnrichedAnomalies.length === 0 && dqAnomalies.length === 0) {
    return '<div class="dq-empty-state">Nessuna anomalia rilevata!</div>';
  }
  
  // Use enriched anomalies (pre-processed during load)
  const anomalies = dqEnrichedAnomalies.length > 0 ? dqEnrichedAnomalies : dqAnomalies;
  
  const anomalyLabels = {
    'km_invalid': 'Km Invalidi',
    'km_regression': 'Regressione Km',
    'time_invalid': 'Orari Invalidi',
    'no_departure': 'Partenza Mancante',
    'overlap': 'Sovrapposizione',
    'duration_mismatch': 'Durata Incoerente',
    'km_implausible': 'Km Implausibili'
  };
  
  const severityColors = {
    'critical': '#ef4444',
    'warning': '#f59e0b',
    'info': '#3b82f6'
  };
  
  const criticalCount = anomalies.filter(a => a.severity === 'critical').length;
  const warningCount = anomalies.filter(a => a.severity === 'warning').length;
  
  return `
    <div class="dq-anomaly-filters">
      <button class="dq-filter-btn active" onclick="filterAnomalies('all', event)">Tutte (${anomalies.length})</button>
      <button class="dq-filter-btn" onclick="filterAnomalies('critical', event)">Critiche (${criticalCount})</button>
      <button class="dq-filter-btn" onclick="filterAnomalies('warning', event)">Avvisi (${warningCount})</button>
    </div>
    <div class="dq-table-scroll" id="dq-anomalies-container">
      <table class="dq-detail-table">
        <thead>
          <tr>
            <th>Veicolo</th>
            <th>N. Prog.</th>
            <th>Tipo Anomalia</th>
            <th>Gravita</th>
            <th>Descrizione</th>
            <th>Azioni</th>
          </tr>
        </thead>
        <tbody>
          ${anomalies.slice(0, 100).map(a => `
            <tr class="anomaly-row ${a.severity}" data-severity="${a.severity}">
              <td>${a.vehicleCode || '-'}</td>
              <td>${a.progressiveNumber || '-'}</td>
              <td><span class="dq-anomaly-type">${anomalyLabels[a.anomalyType] || a.anomalyType}</span></td>
              <td>
                <span class="dq-severity-badge" style="background: ${severityColors[a.severity]}">
                  ${a.severity === 'critical' ? 'Critica' : a.severity === 'warning' ? 'Avviso' : 'Info'}
                </span>
              </td>
              <td class="dq-desc-cell">${a.description}</td>
              <td>
                <button class="dq-action-btn-sm primary" onclick="resolveRecord('${a.entityId}')">
                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>
                  Risolvi
                </button>
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

