function renderMissingFieldsTable(fieldType) {
  const fieldMap = {
    'datetime': ['departureTime', 'returnTime'],
    'destination': ['originType', 'destinationType'],
    'km': ['kmInitial', 'kmFinal']
  };
  
  const fieldsToCheck = fieldMap[fieldType] || [];
  const records = dqIncompleteTrips.filter(r => 
    (r.missingFields || []).some(f => fieldsToCheck.includes(f))
  );
  
  if (records.length === 0) {
    return '<div class="dq-empty-state">Nessun record con questo campo mancante.</div>';
  }
  
  return `
    <div class="dq-table-info">Record con campi mancanti: <strong>${records.length}</strong></div>
    <div class="dq-table-scroll">
      <table class="dq-detail-table">
        <thead>
          <tr>
            <th>N. Progressivo</th>
            <th>Veicolo</th>
            <th>Data</th>
            <th>Campi Mancanti</th>
            <th>Azioni</th>
          </tr>
        </thead>
        <tbody>
          ${records.slice(0, 100).map(r => `
            <tr class="incomplete-row">
              <td>${r.progressiveNumber || '-'}</td>
              <td>${r.vehicleCode || '-'}</td>
              <td>${r.serviceDate || '-'}</td>
              <td>${(r.missingFields || []).join(', ')}</td>
              <td>
                <button class="dq-action-btn-sm primary" onclick="resolveRecord('${r.id}')">
                  <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/></svg>
                  Compila
                </button>
              </td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
}

function filterAnomalies(severity, evt) {
  const buttons = document.querySelectorAll('.dq-filter-btn');
  buttons.forEach(b => b.classList.remove('active'));
  
  // Handle both explicit event parameter and implicit global event
  const clickEvent = evt || (typeof event !== 'undefined' ? event : null);
  if (clickEvent && clickEvent.target) {
    clickEvent.target.classList.add('active');
  }
  
  const rows = document.querySelectorAll('.anomaly-row');
  rows.forEach(row => {
    const rowSeverity = row.getAttribute('data-severity');
    if (severity === 'all' || rowSeverity === severity) {
      row.style.display = '';
    } else {
      row.style.display = 'none';
    }
  });
}

function closeDQModal(event) {
  if (event && event.target !== event.currentTarget) return;
  const modal = document.getElementById('dq-detail-modal');
  if (modal) modal.remove();
}

function exportDQData(mode) {
  let data = [];
  let filename = '';
  
  switch (mode) {
    case 'monitored':
      // Combine all records with issues
      data = [...dqIncompleteTrips, ...dqCriticalRecords];
      filename = 'record_monitorati.csv';
      break;
    case 'incomplete':
      data = dqIncompleteTrips;
      filename = 'viaggi_incompleti.csv';
      break;
    case 'anomalies':
      // Use enriched anomalies with vehicle/progressive data
      data = dqEnrichedAnomalies.length > 0 ? dqEnrichedAnomalies : dqAnomalies;
      filename = 'anomalie.csv';
      break;
    case 'critical':
      data = dqCriticalRecords;
      filename = 'record_critici.csv';
      break;
    case 'missing':
      data = dqIncompleteTrips;
      filename = 'campi_mancanti.csv';
      break;
  }
  
  if (data.length === 0) {
    showNotification('Nessun dato da esportare', 'warning');
    return;
  }
  
  // Create CSV with standardized headers
  let csv = '';
  if (mode === 'anomalies') {
    csv = 'Veicolo;N. Progressivo;Data;Tipo Anomalia;Gravita;Descrizione\n';
    csv += data.map(r => 
      `${r.vehicleCode || ''};${r.progressiveNumber || ''};${r.serviceDate || ''};${r.anomalyType || ''};${r.severity || ''};${(r.description || '').replace(/;/g, ',')}`
    ).join('\n');
  } else {
    csv = 'ID;N. Progressivo;Veicolo;Data;Problemi\n';
    csv += data.map(r => {
      const issues = r.issues || r.missingFields || [];
      return `${r.id || ''};${r.progressiveNumber || ''};${r.vehicleCode || ''};${r.serviceDate || ''};${issues.join(', ').replace(/;/g, ',')}`;
    }).join('\n');
  }
  
  const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
  
  showNotification(`Esportati ${data.length} record`, 'success');
}

async function resolveRecord(tripId) {
  // Close any existing DQ modal first (Esplora Anomalie, Record Critici, etc.)
  const existingDqModal = document.getElementById('dq-detail-modal');
  if (existingDqModal) {
    existingDqModal.remove();
  }
  
  try {
    // Fetch trip details
    const response = await adminFetch(`${API_BASE}/api/trips/${tripId}`);
    if (!response.ok) throw new Error('Viaggio non trovato');
    
    const trip = await response.json();
    
    // Find related issues from cached data
    const incompleteIssue = dqIncompleteTrips.find(r => r.id === tripId);
    const criticalIssue = dqCriticalRecords.find(r => r.id === tripId);
    const anomalyIssues = dqAnomalies.filter(a => a.entityId === tripId);
    
    // Get vehicle code from cached data if not in trip response
    const vehicleCode = trip.vehicleCode || 
                        incompleteIssue?.vehicleCode || 
                        criticalIssue?.vehicleCode || 
                        '-';
    
    const issuesSummary = [];
    let prevTripLink = null;
    
    if (incompleteIssue && incompleteIssue.missingFields) {
      issuesSummary.push(`Campi mancanti: ${incompleteIssue.missingFields.join(', ')}`);
    }
    if (criticalIssue && criticalIssue.issues) {
      criticalIssue.issues.forEach(i => issuesSummary.push(i));
    }
    anomalyIssues.forEach(a => {
      issuesSummary.push(a.description);
      // Check for km_regression anomaly with previous trip info
      if (a.anomalyType === 'km_regression' && a.details && a.details.prevTripId) {
        prevTripLink = a.details.prevTripId;
      }
    });
    
    const modalHtml = `
      <div class="modal-overlay dq-resolve-overlay" id="dq-resolve-modal" onclick="closeResolveModal(event)">
        <div class="modal-content dq-resolve-content" onclick="event.stopPropagation()">
          <div class="modal-header dq-resolve-header">
            <h3>Risolvi Problemi - Viaggio ${trip.progressiveNumber || tripId.substring(0, 8)}</h3>
            <button class="modal-close" onclick="closeResolveModal()">&times;</button>
          </div>
          <div class="modal-body dq-resolve-body">
            ${issuesSummary.length > 0 ? `
              <div class="dq-issues-summary">
                <h4>Problemi Rilevati:</h4>
                <ul>
                  ${issuesSummary.map(i => `<li>${i}</li>`).join('')}
                </ul>
                ${prevTripLink ? `
                  <div style="margin-top: 12px; padding-top: 12px; border-top: 1px solid rgba(239, 68, 68, 0.3);">
                    <button class="btn btn-secondary" onclick="closeResolveModal(); setTimeout(() => resolveRecord('${prevTripLink}'), 100);" style="font-size: 13px;">
                      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="margin-right: 6px;"><path d="m15 18-6-6 6-6"/></svg>
                      Apri Viaggio Precedente
                    </button>
                    <span style="font-size: 12px; color: rgba(255,255,255,0.6); margin-left: 8px;">
                      (quello con i km finali errati)
                    </span>
                  </div>
                ` : ''}
              </div>
            ` : ''}
            
            <form id="resolve-trip-form" class="dq-resolve-form">
              <input type="hidden" id="resolve-trip-id" value="${tripId}">
              
              <div class="dq-form-row">
                <div class="dq-form-group">
                  <label>Data Servizio</label>
                  <input type="date" id="resolve-serviceDate" value="${trip.serviceDate || ''}" required>
                </div>
                <div class="dq-form-group">
                  <label>Veicolo</label>
                  <input type="text" id="resolve-vehicle" value="${vehicleCode}" readonly>
                </div>
              </div>
              
              <div class="dq-form-row">
                <div class="dq-form-group">
                  <label>Ora Partenza</label>
                  <input type="time" id="resolve-departureTime" value="${trip.departureTime || ''}" required>
                </div>
                <div class="dq-form-group">
                  <label>Ora Rientro</label>
                  <input type="time" id="resolve-returnTime" value="${trip.returnTime || ''}">
                </div>
              </div>
              
              <div class="dq-form-row">
                <div class="dq-form-group">
                  <label>Km Iniziali</label>
                  <input type="number" id="resolve-kmInitial" value="${trip.kmInitial || ''}" required>
                </div>
                <div class="dq-form-group">
                  <label>Km Finali</label>
                  <input type="number" id="resolve-kmFinal" value="${trip.kmFinal || ''}" required>
                </div>
              </div>
              
              <div class="dq-form-row">
                <div class="dq-form-group">
                  <label>Tipo Origine</label>
                  <select id="resolve-originType">
                    <option value="">Seleziona...</option>
                    <option value="structure" ${trip.originType === 'structure' ? 'selected' : ''}>Struttura</option>
                    <option value="address" ${trip.originType === 'address' ? 'selected' : ''}>Indirizzo</option>
                  </select>
                </div>
                <div class="dq-form-group">
                  <label>Tipo Destinazione</label>
                  <select id="resolve-destinationType">
                    <option value="">Seleziona...</option>
                    <option value="structure" ${trip.destinationType === 'structure' ? 'selected' : ''}>Struttura</option>
                    <option value="address" ${trip.destinationType === 'address' ? 'selected' : ''}>Indirizzo</option>
                  </select>
                </div>
              </div>
              
              <div class="dq-form-group full-width">
                <label>Note Risoluzione</label>
                <textarea id="resolve-notes" rows="3" placeholder="Aggiungi note sulla correzione effettuata..."></textarea>
              </div>
            </form>
          </div>
          <div class="modal-footer dq-resolve-footer">
            <button class="btn btn-secondary" onclick="closeResolveModal()">Annulla</button>
            <button class="btn btn-primary" onclick="saveTripResolution()">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg>
              Salva Modifiche
            </button>
          </div>
        </div>
      </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    // Add active class to make modal visible (CSS hides modals without .active)
    const insertedModal = document.getElementById('dq-resolve-modal');
    if (insertedModal) {
      insertedModal.classList.add('active');
    }
  } catch (error) {
    console.error('Error loading trip for resolution:', error);
    showNotification('Errore nel caricamento del viaggio', 'error');
  }
}

function closeResolveModal(event) {
  if (event && event.target !== event.currentTarget) return;
  const modal = document.getElementById('dq-resolve-modal');
  if (modal) modal.remove();
}

async function saveTripResolution() {
  const tripId = document.getElementById('resolve-trip-id').value;
  
  const updateData = {
    serviceDate: document.getElementById('resolve-serviceDate').value,
    departureTime: document.getElementById('resolve-departureTime').value,
    returnTime: document.getElementById('resolve-returnTime').value,
    kmInitial: parseInt(document.getElementById('resolve-kmInitial').value) || null,
    kmFinal: parseInt(document.getElementById('resolve-kmFinal').value) || null,
    originType: document.getElementById('resolve-originType').value || null,
    destinationType: document.getElementById('resolve-destinationType').value || null
  };
  
  // Validate km
  if (updateData.kmInitial !== null && updateData.kmFinal !== null && updateData.kmFinal < updateData.kmInitial) {
    showNotification('Km finali non possono essere inferiori ai km iniziali', 'error');
    return;
  }
  
  try {
    const response = await adminFetch(`${API_BASE}/api/trips/${tripId}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(updateData)
    });
    
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.error || 'Errore nel salvataggio');
    }
    
    showNotification('Viaggio aggiornato con successo', 'success');
    closeResolveModal();
    closeDQModal();
    
    // Reset all cached data
    dqDetailedData = null;
    dqIncompleteTrips = [];
    dqCriticalRecords = [];
    dqAnomalies = [];
    dqEnrichedAnomalies = [];
    
    // Refresh data quality dashboard, cached records, and main dashboard (await to ensure fresh data)
    await Promise.all([
      loadDataQualityData(),
      loadAllQualityRecords(),
      loadInitialData()
    ]);
    
    // Update the main dashboard display
    updateDashboard();
    
  } catch (error) {
    console.error('Error saving trip resolution:', error);
    showNotification(error.message || 'Errore nel salvataggio', 'error');
  }
}

