let deleteSelectedShiftIds = new Set();
let deleteSelectionMode = false;

function openDeleteShiftsModal() {
  const modal = document.getElementById('delete-shifts-modal');
  if (!modal) return;
  deleteSelectedShiftIds.clear();
  deleteSelectionMode = false;
  document.getElementById('delete-mode').value = 'month';
  updateDeleteMode();
  const currentLocationFilter = document.getElementById('monthly-location-filter')?.value || '';
  const locSel = document.getElementById('delete-location-filter');
  if (locSel) {
    locSel.innerHTML = '<option value="">Tutte le sedi</option>';
    (locations || []).forEach(l => { locSel.innerHTML += `<option value="${l.id}" ${l.id === currentLocationFilter ? 'selected' : ''}>${l.name}</option>`; });
  }
  const vehSel = document.getElementById('delete-vehicle-filter');
  if (vehSel) {
    vehSel.innerHTML = '<option value="">Tutti i veicoli</option>';
    (vehicles || []).forEach(v => { vehSel.innerHTML += `<option value="${v.id}">${v.code}${v.natoName ? ' - ' + v.natoName : ''}</option>`; });
  }
  updateDeletePreview();
  modal.style.display = 'flex';
}

function closeDeleteShiftsModal() {
  const modal = document.getElementById('delete-shifts-modal');
  if (modal) modal.style.display = 'none';
  deleteSelectionMode = false;
  deleteSelectedShiftIds.clear();
  document.querySelectorAll('.sched-shift-cell.delete-selected').forEach(el => el.classList.remove('delete-selected'));
}

function updateDeleteMode() {
  const mode = document.getElementById('delete-mode')?.value;
  document.getElementById('delete-custom-dates').style.display = mode === 'custom' ? '' : 'none';
  document.getElementById('delete-selected-info').style.display = mode === 'selected' ? '' : 'none';
  if (mode === 'selected') {
    deleteSelectionMode = true;
    showNotification('Clicca sui turni nella griglia per selezionarli', 'info');
  } else {
    deleteSelectionMode = false;
    deleteSelectedShiftIds.clear();
    document.querySelectorAll('.sched-shift-cell.delete-selected').forEach(el => el.classList.remove('delete-selected'));
  }
  updateDeletePreview();
}

function toggleShiftForDeletion(shiftId, cellEl) {
  if (!deleteSelectionMode) return;
  if (deleteSelectedShiftIds.has(shiftId)) {
    deleteSelectedShiftIds.delete(shiftId);
    cellEl.classList.remove('delete-selected');
  } else {
    deleteSelectedShiftIds.add(shiftId);
    cellEl.classList.add('delete-selected');
  }
  const countEl = document.getElementById('delete-selected-count');
  if (countEl) countEl.textContent = `${deleteSelectedShiftIds.size} turni selezionati`;
  updateDeletePreview();
}

function updateDeletePreview() {
  const mode = document.getElementById('delete-mode')?.value;
  const previewEl = document.getElementById('delete-preview-text');
  if (!previewEl) return;
  const locFilter = document.getElementById('delete-location-filter')?.value;
  const vehFilter = document.getElementById('delete-vehicle-filter')?.value;
  let extra = '';
  if (locFilter) { const loc = (locations || []).find(l => l.id === locFilter); extra += ` sede "${loc?.name || ''}"`; }
  if (vehFilter) { const veh = (vehicles || []).find(v => v.id === vehFilter); extra += ` veicolo "${veh?.code || ''}"`; }
  if (mode === 'month') {
    const monthName = MONTHS_IT[monthlyScheduleData.month] || '';
    previewEl.textContent = `Verranno eliminati tutti i turni di ${monthName} ${monthlyScheduleData.year}${extra}`;
  } else if (mode === 'week') {
    const count = shiftInstances.filter(s => {
      if (locFilter && s.locationId !== locFilter) return false;
      if (vehFilter && s.vehicleId !== vehFilter) return false;
      return true;
    }).length;
    previewEl.textContent = `Verranno eliminati ${count} turni della settimana corrente${extra}`;
  } else if (mode === 'custom') {
    previewEl.textContent = `Verranno eliminati i turni nel periodo selezionato${extra}`;
  } else {
    previewEl.textContent = `${deleteSelectedShiftIds.size} turni selezionati per l'eliminazione`;
  }
}

async function executeDeleteShifts() {
  const mode = document.getElementById('delete-mode')?.value;
  const locFilter = document.getElementById('delete-location-filter')?.value;
  const vehFilter = document.getElementById('delete-vehicle-filter')?.value;
  
  let body = {};
  if (mode === 'selected') {
    if (deleteSelectedShiftIds.size === 0) { showNotification('Nessun turno selezionato', 'error'); return; }
    body = { ids: [...deleteSelectedShiftIds] };
  } else if (mode === 'month') {
    const year = monthlyScheduleData.year;
    const month = monthlyScheduleData.month;
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const dateFrom = `${year}-${String(month + 1).padStart(2, '0')}-01`;
    const dateTo = `${year}-${String(month + 1).padStart(2, '0')}-${String(daysInMonth).padStart(2, '0')}`;
    body = { dateFrom, dateTo };
    if (locFilter) body.locationId = locFilter;
    if (vehFilter) body.vehicleId = vehFilter;
  } else if (mode === 'week') {
    const weekDates = getWeekDates(schedulingCurrentWeek);
    body = { dateFrom: formatDateKey(weekDates[0]), dateTo: formatDateKey(weekDates[6]) };
    if (locFilter) body.locationId = locFilter;
    if (vehFilter) body.vehicleId = vehFilter;
  } else if (mode === 'custom') {
    const dateFrom = document.getElementById('delete-date-from')?.value;
    const dateTo = document.getElementById('delete-date-to')?.value;
    if (!dateFrom || !dateTo) { showNotification('Seleziona le date', 'error'); return; }
    body = { dateFrom, dateTo };
    if (locFilter) body.locationId = locFilter;
    if (vehFilter) body.vehicleId = vehFilter;
  }

  const confirmMsg = mode === 'selected' 
    ? `Eliminare ${deleteSelectedShiftIds.size} turni selezionati?` 
    : 'Eliminare tutti i turni con i filtri impostati?';
  if (!confirm(confirmMsg + '\n\nQuesta azione non puo\' essere annullata.')) return;

  try {
    const btn = document.getElementById('confirm-delete-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Eliminazione...'; }
    const res = await adminFetch(`${API_BASE}/api/shift-instances/bulk-delete`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    if (!res.ok) throw new Error('Errore server');
    const data = await res.json();
    showNotification(`${data.deletedCount} turni eliminati con successo`, 'success');
    closeDeleteShiftsModal();
    if (document.getElementById('monthly-scheduling-section') && !document.getElementById('monthly-scheduling-section').classList.contains('hidden')) {
      loadMonthlySchedule();
    } else {
      loadSchedulingData();
    }
    loadShiftAuditLog();
  } catch (error) {
    console.error('Error deleting shifts:', error);
    showNotification('Errore nell\'eliminazione dei turni', 'error');
  } finally {
    const btn = document.getElementById('confirm-delete-btn');
    if (btn) { btn.disabled = false; btn.textContent = 'Elimina Turni'; }
  }
}

