// ========================================
// SHIFT STATISTICS PAGE
// ========================================
let shiftStatsData = null;

function initShiftStatisticsPage() {
  const yearSel = document.getElementById('shift-stats-year');
  const monthSel = document.getElementById('shift-stats-month');
  const locSel = document.getElementById('shift-stats-location');
  const exportLocSel = document.getElementById('export-location-filter');
  const now = new Date();
  if (yearSel && yearSel.options.length === 0) {
    for (let y = 2035; y >= 2000; y--) {
      const opt = new Option(String(y), String(y));
      if (y === now.getFullYear()) opt.selected = true;
      yearSel.add(opt);
    }
  }
  if (monthSel && monthSel.options.length === 0) {
    const monthNames = ['Gennaio','Febbraio','Marzo','Aprile','Maggio','Giugno','Luglio','Agosto','Settembre','Ottobre','Novembre','Dicembre'];
    for (let m = 0; m < 12; m++) {
      const val = String(m + 1).padStart(2, '0');
      const opt = new Option(monthNames[m], val);
      if (m === now.getMonth()) opt.selected = true;
      monthSel.add(opt);
    }
  }
  if (locSel && locSel.options.length <= 1 && locations.length > 0) {
    locations.forEach(loc => locSel.add(new Option(loc.name, loc.id)));
  }
  if (exportLocSel && exportLocSel.options.length <= 1 && locations.length > 0) {
    locations.forEach(loc => exportLocSel.add(new Option(loc.name, loc.id)));
  }
  const exportMonth = document.getElementById('export-month');
  if (exportMonth && !exportMonth.value) {
    const now = new Date();
    exportMonth.value = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
  }
  loadShiftStatsPage();
}

function getShiftStatsMonthValue() {
  const y = document.getElementById('shift-stats-year')?.value;
  const m = document.getElementById('shift-stats-month')?.value;
  if (y && m) return `${y}-${m}`;
  return '';
}

async function loadShiftStatsPage() {
  const month = getShiftStatsMonthValue();
  const locationId = document.getElementById('shift-stats-location')?.value || '';
  if (!month) return;
  const overviewEl = document.getElementById('shift-stats-overview');
  const staffTableEl = document.getElementById('shift-stats-staff-table');
  const locChartEl = document.getElementById('shift-stats-locations-chart');
  try {
    const params = new URLSearchParams({ month });
    if (locationId) params.append('locationId', locationId);
    const res = await adminFetch(`${API_BASE}/api/shift-stats?${params}`);
    if (!res.ok) throw new Error('Errore caricamento');
    shiftStatsData = await res.json();
    renderShiftStatsOverview(overviewEl, shiftStatsData);
    renderShiftStatsStaffTable(staffTableEl, shiftStatsData);
    renderShiftStatsLocations(locChartEl, shiftStatsData);
  } catch (error) {
    console.error('Error loading shift stats page:', error);
    if (overviewEl) overviewEl.innerHTML = '';
    if (staffTableEl) staffTableEl.innerHTML = '<div style="text-align: center; color: #ef4444; padding: 20px;">Errore nel caricamento statistiche</div>';
  }
}

function renderShiftStatsOverview(el, data) {
  if (!el) return;
  const items = [
    { label: 'Turni Totali', value: data.totalShifts, color: '#0066CC', bg: '#eff6ff', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>' },
    { label: 'Coperti', value: data.coveredShifts, color: '#16a34a', bg: '#f0fdf4', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>' },
    { label: 'Scoperti', value: data.uncoveredShifts, color: '#dc2626', bg: '#fef2f2', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>' },
    { label: 'Copertura', value: data.coveragePercent + '%', color: '#7c3aed', bg: '#faf5ff', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>' },
    { label: 'Operatori', value: data.staffMembers?.length || 0, color: '#0891b2', bg: '#ecfeff', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>' },
    { label: 'Sedi Attive', value: data.locationStats?.length || 0, color: '#d97706', bg: '#fffbeb', icon: '<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>' },
  ];
  el.innerHTML = items.map(item => `
    <div style="padding: 16px; background: ${item.bg}; border-radius: 12px; text-align: center; border: 1px solid ${item.color}22;">
      <div style="color: ${item.color}; margin-bottom: 6px;">${item.icon}</div>
      <div style="font-size: 26px; font-weight: 800; color: ${item.color};">${item.value}</div>
      <div style="font-size: 11px; color: #64748b; text-transform: uppercase; font-weight: 600; margin-top: 4px;">${item.label}</div>
    </div>
  `).join('');
}

