async function executeGenerateMonthlyShifts() {
  const pattern = document.getElementById('gen-pattern')?.value || 'all_days';
  const scope = document.getElementById('gen-scope')?.value || 'all';
  const autoAssign = document.getElementById('gen-auto-assign')?.checked ?? true;
  const respectHours = document.getElementById('gen-respect-hours')?.checked ?? true;
  const locationFilter = document.getElementById('monthly-location-filter')?.value || '';

  let vehicleIdParam = null;
  let locationIdParam = null;

  if (scope === 'location' && locationFilter) {
    locationIdParam = locationFilter;
  }

  const btn = document.getElementById('gen-confirm-btn');
  if (btn) {
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-sm"></span> Generazione in corso...';
  }

  try {
    const response = await adminFetch('/api/monthly-schedule/generate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        month: monthlyScheduleData.month + 1,
        year: monthlyScheduleData.year,
        locationId: locationIdParam,
        vehicleId: vehicleIdParam,
        pattern,
        autoAssign,
        respectMaxHours: respectHours
      })
    });

    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.error || 'Errore nella generazione');
    }

    const result = await response.json();

    document.getElementById('generate-shifts-modal')?.remove();

    let msg = `Creati ${result.createdShifts} turni`;
    if (autoAssign && result.assignedStaff > 0) {
      msg += `, assegnati ${result.assignedStaff} membri del personale`;
      if (result.unfilledSlots > 0) {
        msg += ` (${result.unfilledSlots} posizioni da coprire)`;
      }
    }
    showNotification(msg, 'success');

    await loadMonthlySchedule();
  } catch (error) {
    console.error('Error generating monthly shifts:', error);
    showNotification('Errore: ' + error.message, 'error');
    if (btn) {
      btn.disabled = false;
      btn.innerHTML = 'Genera Turni';
    }
  }
}

async function copyFromPreviousMonth() {
  const currentMonth = monthlyScheduleData.month;
  const currentYear = monthlyScheduleData.year;
  
  // Calculate previous month
  let prevMonth = currentMonth - 1;
  let prevYear = currentYear;
  if (prevMonth < 0) {
    prevMonth = 11;
    prevYear -= 1;
  }
  
  const prevMonthName = MONTHS_IT[prevMonth];
  const currentMonthName = MONTHS_IT[currentMonth];
  
  // Check if current month already has assignments
  if (monthlyScheduleData.assignments.length > 0) {
    if (!confirm(`Il mese di ${currentMonthName} ${currentYear} ha gia ${monthlyScheduleData.assignments.length} assegnazioni.\n\nVuoi aggiungere le assegnazioni da ${prevMonthName} ${prevYear}?\n(Le assegnazioni esistenti verranno mantenute)`)) {
      return;
    }
  } else {
    if (!confirm(`Vuoi copiare tutti i turni da ${prevMonthName} ${prevYear} a ${currentMonthName} ${currentYear}?`)) {
      return;
    }
  }
  
  showNotification('Copia turni in corso...', 'info');
  
  try {
    const response = await adminFetch('/api/monthly-schedule/copy-from-previous', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        targetMonth: currentMonth + 1,
        targetYear: currentYear,
        sourceMonth: prevMonth + 1,
        sourceYear: prevYear
      })
    });
    
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Errore nella copia');
    }
    
    const result = await response.json();
    
    // Reload schedule to show new assignments
    await loadMonthlySchedule();
    
    showNotification(`Copiati ${result.copiedCount} turni da ${prevMonthName} ${prevYear}`, 'success');
  } catch (error) {
    console.error('Error copying from previous month:', error);
    showNotification('Errore: ' + error.message, 'error');
  }
}

function exportMonthlyShifts() {
  showNotification('Esportazione in corso...', 'info');
  
  const daysInMonth = getDaysInMonth(monthlyScheduleData.month, monthlyScheduleData.year);
  const monthName = MONTHS_IT[monthlyScheduleData.month];
  
  const locationFilter = document.getElementById('monthly-location-filter')?.value || '';
  let filteredVehicles = vehicles.filter(v => v.isActive !== false);
  if (locationFilter) {
    filteredVehicles = filteredVehicles.filter(v => v.locationId === locationFilter);
  }
  
  // Build CSV
  let csv = 'TURNAZIONE PERSONALE - ' + monthName + ' ' + monthlyScheduleData.year + '\n\n';
  csv += 'Giorno;Nome Giorno;';
  
  filteredVehicles.forEach(v => {
    csv += `${v.code} Mattina AUT;${v.code} Mattina SOC;${v.code} Pom AUT;${v.code} Pom SOC;`;
  });
  csv += '\n';
  
  for (let d = 1; d <= daysInMonth; d++) {
    const date = new Date(monthlyScheduleData.year, monthlyScheduleData.month, d);
    const dateStr = `${monthlyScheduleData.year}-${String(monthlyScheduleData.month + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
    
    csv += `${d};${DAYS_IT[date.getDay()]};`;
    
    filteredVehicles.forEach(v => {
      const morningAut = monthlyScheduleData.assignments.find(a => 
        a.vehicleId === v.id && a.date === dateStr && a.shiftType === 'morning' && a.role === 'autista'
      );
      const morningSoc = monthlyScheduleData.assignments.find(a => 
        a.vehicleId === v.id && a.date === dateStr && a.shiftType === 'morning' && a.role === 'soccorritore'
      );
      const afternoonAut = monthlyScheduleData.assignments.find(a => 
        a.vehicleId === v.id && a.date === dateStr && a.shiftType === 'afternoon' && a.role === 'autista'
      );
      const afternoonSoc = monthlyScheduleData.assignments.find(a => 
        a.vehicleId === v.id && a.date === dateStr && a.shiftType === 'afternoon' && a.role === 'soccorritore'
      );
      
      csv += `${morningAut?.staffName || ''};${morningSoc?.staffName || ''};${afternoonAut?.staffName || ''};${afternoonSoc?.staffName || ''};`;
    });
    csv += '\n';
  }
  
  const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `turni_${monthName.toLowerCase()}_${monthlyScheduleData.year}.csv`;
  a.click();
  URL.revokeObjectURL(url);
  
  showNotification('File esportato con successo', 'success');
}

