// ========================================
// CONFLICT DETECTION & AVAILABILITY OVERLAY
// ========================================

let availabilityOverlayEnabled = false;
let staffConflicts = [];

function detectConflicts() {
  staffConflicts = [];
  const assignmentsByStaff = {};
  
  // Group assignments by staff member
  monthlyScheduleData.assignments.forEach(a => {
    if (!a.staffMemberId) return;
    if (!assignmentsByStaff[a.staffMemberId]) {
      assignmentsByStaff[a.staffMemberId] = [];
    }
    assignmentsByStaff[a.staffMemberId].push(a);
  });
  
  // Check for conflicts
  Object.keys(assignmentsByStaff).forEach(staffId => {
    const assignments = assignmentsByStaff[staffId];
    const staff = staffMembers.find(s => s.id === staffId);
    const staffName = staff ? `${staff.firstName} ${staff.lastName}` : 'Personale';
    
    // Check for same day double shifts (morning + afternoon on same day)
    const byDate = {};
    assignments.forEach(a => {
      if (!byDate[a.date]) byDate[a.date] = [];
      byDate[a.date].push(a);
    });
    
    Object.keys(byDate).forEach(date => {
      const dayAssignments = byDate[date];
      
      // Check for double shift on same day
      if (dayAssignments.length >= 2) {
        const hasMorning = dayAssignments.some(a => a.shiftType === 'morning');
        const hasAfternoon = dayAssignments.some(a => a.shiftType === 'afternoon');
        
        if (hasMorning && hasAfternoon) {
          staffConflicts.push({
            type: 'double_shift',
            severity: 'warning',
            staffId,
            staffName,
            date,
            message: `${staffName} ha doppio turno il ${formatDateIT(date)}`
          });
        }
      }
      
      // Check for multiple vehicle assignments at same time
      const vehicleAssignments = {};
      dayAssignments.forEach(a => {
        const key = `${a.shiftType}`;
        if (!vehicleAssignments[key]) vehicleAssignments[key] = [];
        vehicleAssignments[key].push(a);
      });
      
      Object.keys(vehicleAssignments).forEach(key => {
        if (vehicleAssignments[key].length > 1) {
          staffConflicts.push({
            type: 'overlap',
            severity: 'error',
            staffId,
            staffName,
            date,
            message: `${staffName} assegnato a ${vehicleAssignments[key].length} veicoli contemporaneamente il ${formatDateIT(date)}`
          });
        }
      });
    });
    
    // Check for excessive consecutive days (more than 6)
    const sortedDates = Object.keys(byDate).sort();
    let consecutiveCount = 1;
    let startDate = sortedDates[0];
    
    for (let i = 1; i < sortedDates.length; i++) {
      const prevDate = new Date(sortedDates[i - 1]);
      const currDate = new Date(sortedDates[i]);
      const diffDays = Math.round((currDate - prevDate) / (1000 * 60 * 60 * 24));
      
      if (diffDays === 1) {
        consecutiveCount++;
        if (consecutiveCount > 6) {
          staffConflicts.push({
            type: 'consecutive',
            severity: 'warning',
            staffId,
            staffName,
            date: sortedDates[i],
            message: `${staffName} ha ${consecutiveCount} giorni consecutivi di lavoro`
          });
        }
      } else {
        consecutiveCount = 1;
      }
    }
  });
  
  return staffConflicts;
}

function formatDateIT(dateStr) {
  const date = new Date(dateStr);
  return `${date.getDate()}/${date.getMonth() + 1}/${date.getFullYear()}`;
}

function toggleAvailabilityOverlay() {
  availabilityOverlayEnabled = !availabilityOverlayEnabled;
  
  const btn = document.querySelector('.monthly-schedule-controls button[onclick*="toggleAvailabilityOverlay"]');
  if (btn) {
    btn.classList.toggle('active', availabilityOverlayEnabled);
  }
  
  if (availabilityOverlayEnabled) {
    renderAvailabilityOverlay();
    showNotification('Overlay disponibilita attivato', 'info');
  } else {
    removeAvailabilityOverlay();
    showNotification('Overlay disponibilita disattivato', 'info');
  }
}

function renderAvailabilityOverlay() {
  // Color cells based on staff availability (simulated)
  const cells = document.querySelectorAll('.shift-cell');
  cells.forEach(cell => {
    const date = cell.dataset.date;
    const dayOfWeek = new Date(date).getDay();
    
    // Weekend highlighting
    if (dayOfWeek === 0 || dayOfWeek === 6) {
      cell.classList.add('weekend-overlay');
    }
    
    // Simulate availability status
    const random = Math.random();
    if (random < 0.1) {
      cell.classList.add('low-availability');
    } else if (random < 0.3) {
      cell.classList.add('medium-availability');
    }
  });
}

function removeAvailabilityOverlay() {
  const cells = document.querySelectorAll('.shift-cell');
  cells.forEach(cell => {
    cell.classList.remove('weekend-overlay', 'low-availability', 'medium-availability');
  });
}

