function toggleDayActive(vehicleId, dayNum, active) {
  const grid = document.querySelector(`.day-schedule-grid[data-vehicle-id="${vehicleId}"]`);
  if (!grid) return;
  const dayRow = grid.querySelector(`.day-schedule-row[data-day="${dayNum}"]`);
  if (!dayRow) return;
  if (active) {
    dayRow.classList.remove('day-inactive');
    const container = dayRow.querySelector('.day-shifts-container');
    if (container) {
      container.innerHTML = `
        <div class="day-shift-entry" data-shift-idx="0">
          <input type="time" class="form-input day-shift-start" value="07:00" style="width: 75px; font-size: 12px; padding: 3px 4px;">
          <span style="color: #94a3b8; font-size: 11px;">-</span>
          <input type="time" class="form-input day-shift-end" value="14:00" style="width: 75px; font-size: 12px; padding: 3px 4px;">
          <button type="button" class="btn-icon-xs" onclick="removeDayShift('${vehicleId}', ${dayNum}, 0)" title="Rimuovi">
            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>
        <button type="button" class="btn-add-shift-sm" onclick="addDayShift('${vehicleId}', ${dayNum})">+ Orario</button>
      `;
    }
  } else {
    dayRow.classList.add('day-inactive');
    const container = dayRow.querySelector('.day-shifts-container');
    if (container) {
      container.innerHTML = '<span style="color: #94a3b8; font-size: 11px; font-style: italic;">Non attivo</span>';
    }
  }
}

function addGlobalShift(vehicleId) {
  const container = document.querySelector(`.global-shifts-container[data-vehicle-id="${vehicleId}"]`);
  if (!container) return;
  const addBtn = container.querySelector('.btn-add-shift-sm');
  const entry = document.createElement('div');
  entry.className = 'global-shift-entry';
  entry.style.cssText = 'display: flex; align-items: center; gap: 6px; margin-bottom: 4px;';
  const idx = container.querySelectorAll('.global-shift-entry').length;
  entry.innerHTML = `
    <span style="font-size: 11px; color: #64748b; min-width: 50px;">Fascia ${idx + 1}:</span>
    <input type="time" class="form-input global-shift-start" value="14:00" style="width: 80px; font-size: 12px; padding: 3px 4px;">
    <span style="color: #94a3b8; font-size: 11px;">-</span>
    <input type="time" class="form-input global-shift-end" value="22:00" style="width: 80px; font-size: 12px; padding: 3px 4px;">
    <button type="button" class="btn-icon-xs" onclick="removeGlobalShift('${vehicleId}', ${idx})" title="Rimuovi fascia">
      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#ef4444" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>
  `;
  if (addBtn) container.insertBefore(entry, addBtn);
  else container.appendChild(entry);
}

function removeGlobalShift(vehicleId, shiftIdx) {
  const container = document.querySelector(`.global-shifts-container[data-vehicle-id="${vehicleId}"]`);
  if (!container) return;
  const entries = container.querySelectorAll('.global-shift-entry');
  if (entries.length <= 1) { showNotification('Deve esserci almeno una fascia oraria', 'error'); return; }
  entries[shiftIdx]?.remove();
}

