function collectScheduleDaysFromDOM(row) {
  const grid = row.querySelector('.day-schedule-grid');
  if (!grid) return null;
  const scheduleDays = {};
  grid.querySelectorAll('.day-schedule-row').forEach(dayRow => {
    const dayNum = parseInt(dayRow.dataset.day);
    const active = dayRow.querySelector('.day-active-check')?.checked ?? false;
    const shifts = [];
    dayRow.querySelectorAll('.day-shift-entry').forEach(entry => {
      const start = entry.querySelector('.day-shift-start')?.value || '';
      const end = entry.querySelector('.day-shift-end')?.value || '';
      if (start && end) shifts.push({ start, end });
    });
    scheduleDays[dayNum] = { active, shifts };
  });
  return scheduleDays;
}

async function saveVehicleScheduleConfig() {
  const tbody = document.getElementById('vehicle-config-tbody');
  if (!tbody) return;
  
  const rows = tbody.querySelectorAll('tr[data-vehicle-id]');
  const updates = [];
  
  rows.forEach(row => {
    const vehicleId = row.dataset.vehicleId;
    const natoName = row.querySelector('[data-field="natoName"]')?.value?.trim() || null;
    const scheduleRoles = row.querySelector('[data-field="scheduleRoles"]')?.value || 'autista,soccorritore';
    let scheduleColor = row.querySelector('[data-field="scheduleColor"]')?.value || null;
    const scheduleEnabled = row.querySelector('[data-field="scheduleEnabled"]')?.checked ?? true;
    const isEmergency = row.querySelector('[data-field="isEmergency"]')?.checked ?? false;
    
    const scheduleDays = collectScheduleDaysFromDOM(row);
    
    const globalShiftsContainer = row.querySelector(`.global-shifts-container[data-vehicle-id="${vehicleId}"]`);
    const allShifts = [];
    if (globalShiftsContainer) {
      globalShiftsContainer.querySelectorAll('.global-shift-entry').forEach(entry => {
        const start = entry.querySelector('.global-shift-start')?.value;
        const end = entry.querySelector('.global-shift-end')?.value;
        if (start && end) {
          allShifts.push({ start, end });
        }
      });
    }
    
    if (scheduleColor === '#ffffff') scheduleColor = null;
    
    const profilesData = collectProfilesFromDOM(vehicleId);
    
    updates.push({
      id: vehicleId,
      natoName: profilesData ? null : natoName,
      scheduleRoles: profilesData ? null : scheduleRoles,
      scheduleColor,
      scheduleEnabled,
      isEmergency,
      scheduleDays: profilesData ? null : scheduleDays,
      scheduleShifts: profilesData ? null : (allShifts.length > 0 ? JSON.stringify(allShifts) : null),
      scheduleProfiles: profilesData || null
    });
  });
  
  closeVehicleScheduleConfig();
  
  try {
    const results = await Promise.all(updates.map(update => 
      adminFetch(`/api/vehicles/${update.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(update)
      }).then(response => ({ update, ok: response.ok }))
    ));
    
    results.forEach(({ update, ok }) => {
      if (ok) {
        const vehicleIdx = vehicles.findIndex(v => v.id === update.id);
        if (vehicleIdx >= 0) {
          vehicles[vehicleIdx] = { ...vehicles[vehicleIdx], ...update };
        }
      }
    });
    
    showNotification('Configurazione veicoli salvata', 'success');
    renderVehicleTabs();
    renderScheduleGrid();
  } catch (error) {
    console.error('Error saving vehicle config:', error);
    showNotification('Errore nel salvare la configurazione', 'error');
  }
}

