// Sync monthly schedule - assignments are saved immediately when added, 
// this button just reloads from server to confirm and sync the view
async function saveMonthlySchedule() {
  const saveBtn = document.getElementById('save-monthly-schedule-btn');
  
  if (saveBtn) {
    saveBtn.disabled = true;
    saveBtn.innerHTML = `<svg class="animate-spin" xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg> Salvataggio...`;
  }
  
  try {
    const pendingAssignments = monthlyScheduleData.pendingAssignments || [];
    let savedCount = 0;
    let errorCount = 0;
    
    for (const assignment of pendingAssignments) {
      try {
        const res = await adminFetch('/api/monthly-schedule/assign', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            vehicleId: assignment.vehicleId,
            date: assignment.date,
            shiftType: assignment.shiftType,
            staffMemberId: assignment.staffMemberId,
            role: assignment.role
          })
        });
        if (res.ok) {
          savedCount++;
        } else {
          errorCount++;
        }
      } catch {
        errorCount++;
      }
    }
    
    monthlyScheduleData.pendingAssignments = [];
    
    await loadMonthlySchedule();
    
    const assignmentCount = (monthlyScheduleData.assignments || []).length;
    if (savedCount > 0) {
      showNotification(`Salvate ${savedCount} assegnazioni. Totale: ${assignmentCount} assegnazioni nel mese`, 'success');
    } else {
      showNotification(`Turnistica aggiornata: ${assignmentCount} assegnazioni nel mese`, 'success');
    }
    if (errorCount > 0) {
      showNotification(`${errorCount} assegnazioni con errore`, 'error');
    }
    
  } catch (error) {
    console.error('Error saving monthly schedule:', error);
    showNotification('Errore nel salvataggio', 'error');
  }
  
  const newBtn = document.getElementById('save-monthly-schedule-btn');
  if (newBtn) {
    newBtn.disabled = false;
    newBtn.innerHTML = `<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M19 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11l5 5v11a2 2 0 0 1-2 2z"/><polyline points="17 21 17 13 7 13 7 21"/><polyline points="7 3 7 8 15 8"/></svg> Salva`;
  }
}

window.saveMonthlySchedule = saveMonthlySchedule;

