function navigateAvailabilityMonth(delta) {
  availabilityMonth += delta;
  if (availabilityMonth > 11) {
    availabilityMonth = 0;
    availabilityYear++;
  } else if (availabilityMonth < 0) {
    availabilityMonth = 11;
    availabilityYear--;
  }
  updateAvailabilityMonthLabel();
  loadStaffAvailability();
}

function openAvailabilityMonthPicker() {
  // Create month picker modal similar to scheduling
  const modal = document.createElement('div');
  modal.className = 'modal-overlay';
  modal.id = 'availability-month-modal';
  modal.innerHTML = `
    <div class="modal-content" style="max-width: 400px;">
      <div class="modal-header">
        <h3>Seleziona Mese</h3>
        <button class="btn-icon" onclick="closeAvailabilityMonthModal()">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
        </button>
      </div>
      <div class="modal-body">
        <div style="display: flex; align-items: center; justify-content: center; gap: 16px; margin-bottom: 24px;">
          <button class="btn btn-icon" onclick="changeAvailPickerYear(-1)">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m15 18-6-6 6-6"/></svg>
          </button>
          <span id="avail-picker-year" style="font-size: 20px; font-weight: 600;">${availabilityYear}</span>
          <button class="btn btn-icon" onclick="changeAvailPickerYear(1)">
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m9 18 6-6-6-6"/></svg>
          </button>
        </div>
        <div class="month-picker-grid" id="avail-month-picker-grid">
          ${MONTH_NAMES_IT.map((m, i) => `
            <button class="month-picker-btn ${i === availabilityMonth ? 'active' : ''}" onclick="selectAvailMonth(${i})">${m}</button>
          `).join('')}
        </div>
      </div>
    </div>
  `;
  document.body.appendChild(modal);
  modal.addEventListener('click', (e) => {
    if (e.target === modal) closeAvailabilityMonthModal();
  });
}

function closeAvailabilityMonthModal() {
  const modal = document.getElementById('availability-month-modal');
  if (modal) modal.remove();
}

function changeAvailPickerYear(delta) {
  availabilityYear += delta;
  document.getElementById('avail-picker-year').textContent = availabilityYear;
}

function selectAvailMonth(month) {
  availabilityMonth = month;
  closeAvailabilityMonthModal();
  updateAvailabilityMonthLabel();
  loadStaffAvailability();
}

function populateAvailabilityLocationFilter() {
  const select = document.getElementById('avail-location-filter');
  if (!select) return;
  select.innerHTML = '<option value="">Tutte le sedi</option>';
  locations.forEach(loc => {
    select.innerHTML += `<option value="${loc.id}">${loc.name}</option>`;
  });
}

async function loadStaffAvailability() {
  try {
    const locationId = document.getElementById('avail-location-filter')?.value || '';
    const role = document.getElementById('avail-role-filter')?.value || '';
    
    const params = new URLSearchParams({
      month: availabilityMonth.toString(),
      year: availabilityYear.toString()
    });
    if (locationId) params.append('locationId', locationId);
    if (role) params.append('role', role);
    
    const response = await adminFetch(`${API_BASE}/api/staff-availability?${params}`);
    
    if (!response.ok) throw new Error('Errore nel caricamento disponibilità');
    
    availabilityData = await response.json();
    filteredAvailabilityData = [...availabilityData];
    
    updateAvailabilityStats();
    renderAvailabilityView();
  } catch (error) {
    console.error('Error loading staff availability:', error);
    showNotification('Errore nel caricamento disponibilità', 'error');
  }
}

function updateAvailabilityStats() {
  document.getElementById('avail-total-submissions').textContent = availabilityData.length;
  document.getElementById('avail-available-count').textContent = 
    availabilityData.filter(a => a.availabilityType === 'available').length;
  const absenceTypes = ['unavailable', 'ferie', 'malattia', 'permesso', 'infortunio', 'maternita', 'formazione'];
  document.getElementById('avail-unavailable-count').textContent = 
    availabilityData.filter(a => absenceTypes.includes(a.availabilityType)).length;
  document.getElementById('avail-preferred-count').textContent = 
    availabilityData.filter(a => a.availabilityType === 'preferred').length;
  document.getElementById('avail-pending-count').textContent = 
    availabilityData.filter(a => !a.isApproved).length;
}

function filterAvailabilityResults() {
  const typeFilter = document.getElementById('avail-type-filter')?.value || '';
  const searchInput = document.getElementById('avail-search-input')?.value?.toLowerCase() || '';
  
  filteredAvailabilityData = availabilityData.filter(item => {
    if (typeFilter && item.availabilityType !== typeFilter) return false;
    if (searchInput && item.staffMember) {
      const fullName = `${item.staffMember.firstName} ${item.staffMember.lastName}`.toLowerCase();
      if (!fullName.includes(searchInput)) return false;
    }
    return true;
  });
  
  renderAvailabilityView();
}

function setAvailabilityView(view) {
  availabilityView = view;
  document.getElementById('avail-list-view-btn').classList.toggle('active', view === 'list');
  document.getElementById('avail-calendar-view-btn').classList.toggle('active', view === 'calendar');
  document.getElementById('availability-list-view').classList.toggle('hidden', view !== 'list');
  document.getElementById('availability-calendar-view').classList.toggle('hidden', view !== 'calendar');
  renderAvailabilityView();
}

function renderAvailabilityView() {
  if (availabilityView === 'list') {
    renderAvailabilityList();
  } else {
    renderAvailabilityCalendar();
  }
}

function renderAvailabilityList() {
  const tbody = document.getElementById('availability-table-body');
  if (!tbody) return;
  
  if (filteredAvailabilityData.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="8" class="availability-empty-state">
          <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
          <p>Nessuna disponibilita per questo mese</p>
        </td>
      </tr>
    `;
    return;
  }
  
  tbody.innerHTML = filteredAvailabilityData.map(item => {
    const staffName = item.staffMember 
      ? `${item.staffMember.firstName} ${item.staffMember.lastName}` 
      : 'Sconosciuto';
    const role = item.staffMember?.primaryRole || '-';
    const roleLabel = role.charAt(0).toUpperCase() + role.slice(1);
    const timeRange = item.timeStart && item.timeEnd 
      ? `${item.timeStart.substring(0,5)} - ${item.timeEnd.substring(0,5)}` 
      : 'Tutto il giorno';
    
    return `
      <tr>
        <td><strong>${staffName}</strong></td>
        <td>${roleLabel}</td>
        <td>${formatDateIT(item.dateStart)}</td>
        <td>${formatDateIT(item.dateEnd)}</td>
        <td>${timeRange}</td>
        <td><span class="avail-type-badge ${item.availabilityType}">${AVAIL_TYPE_LABELS[item.availabilityType] || item.availabilityType}</span></td>
        <td><span class="avail-status-badge ${item.isApproved ? 'approved' : 'pending'}">${item.isApproved ? 'Approvato' : 'Da approvare'}</span></td>
        <td>
          <div class="avail-actions">
            ${!item.isApproved ? `
              <button class="btn-icon approve" title="Approva" onclick="approveAvailability('${item.id}')">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
              </button>
            ` : ''}
            <button class="btn-icon assign" title="Assegna a turno" onclick="assignFromAvailability('${item.id}', '${item.staffMemberId}')">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg>
              </button>
            <button class="btn-icon delete" title="Elimina" onclick="deleteAvailability('${item.id}')">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
            </button>
          </div>
        </td>
      </tr>
    `;
  }).join('');
}

function renderAvailabilityCalendar() {
  const grid = document.getElementById('availability-calendar-grid');
  if (!grid) return;
  
  const firstDay = new Date(availabilityYear, availabilityMonth, 1);
  const lastDay = new Date(availabilityYear, availabilityMonth + 1, 0);
  const startDayOfWeek = (firstDay.getDay() + 6) % 7; // Monday = 0
  
  const dayNames = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'];
  let html = dayNames.map(d => `<div class="avail-calendar-header">${d}</div>`).join('');
  
  // Previous month days
  const prevMonthEnd = new Date(availabilityYear, availabilityMonth, 0).getDate();
  for (let i = startDayOfWeek - 1; i >= 0; i--) {
    html += `<div class="avail-calendar-day other-month"><div class="avail-calendar-day-num">${prevMonthEnd - i}</div></div>`;
  }
  
  // Current month days
  for (let day = 1; day <= lastDay.getDate(); day++) {
    const dateStr = `${availabilityYear}-${String(availabilityMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    const dayItems = filteredAvailabilityData.filter(item => {
      return dateStr >= item.dateStart && dateStr <= item.dateEnd;
    });
    
    html += `
      <div class="avail-calendar-day">
        <div class="avail-calendar-day-num">${day}</div>
        <div class="avail-calendar-items">
          ${dayItems.slice(0, 3).map(item => {
            const name = item.staffMember ? `${item.staffMember.firstName.charAt(0)}. ${item.staffMember.lastName}` : '?';
            return `<div class="avail-calendar-item ${item.availabilityType}" title="${name}">${name}</div>`;
          }).join('')}
          ${dayItems.length > 3 ? `<div class="avail-calendar-item" style="background: #f1f5f9; color: #64748b;">+${dayItems.length - 3}</div>` : ''}
        </div>
      </div>
    `;
  }
  
  // Next month days
  const totalCells = startDayOfWeek + lastDay.getDate();
  const remainingCells = (7 - (totalCells % 7)) % 7;
  for (let i = 1; i <= remainingCells; i++) {
    html += `<div class="avail-calendar-day other-month"><div class="avail-calendar-day-num">${i}</div></div>`;
  }
  
  grid.innerHTML = html;
}

async function approveAvailability(id) {
  try {
    const response = await adminFetch(`${API_BASE}/api/staff-availability/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ 
        isApproved: true,
        approvedAt: new Date().toISOString()
      })
    });
    
    if (!response.ok) throw new Error('Errore nell\'approvazione');
    
    showNotification('Disponibilita approvata', 'success');
    loadStaffAvailability();
  } catch (error) {
    console.error('Error approving availability:', error);
    showNotification('Errore nell\'approvazione', 'error');
  }
}

