function toggleAvailTimeFields() {
  const type = document.getElementById('new-avail-type')?.value;
  const fields = document.getElementById('avail-time-fields');
  if (!fields) return;
  const fullDayTypes = ['ferie', 'malattia', 'infortunio', 'maternita'];
  if (fullDayTypes.includes(type)) {
    fields.style.display = 'none';
    document.getElementById('new-avail-time-start').value = '';
    document.getElementById('new-avail-time-end').value = '';
  } else {
    fields.style.display = 'grid';
  }
}

async function saveNewAvailability() {
  const staffMemberId = document.getElementById('new-avail-staff')?.value;
  const availabilityType = document.getElementById('new-avail-type')?.value;
  const dateStart = document.getElementById('new-avail-date-start')?.value;
  const dateEnd = document.getElementById('new-avail-date-end')?.value;
  const timeStart = document.getElementById('new-avail-time-start')?.value || null;
  const timeEnd = document.getElementById('new-avail-time-end')?.value || null;
  const notes = document.getElementById('new-avail-notes')?.value || '';

  if (!staffMemberId) { showNotification('Seleziona una persona', 'error'); return; }
  if (!dateStart || !dateEnd) { showNotification('Seleziona le date', 'error'); return; }
  if (dateEnd < dateStart) { showNotification('La data fine deve essere dopo la data inizio', 'error'); return; }

  try {
    const res = await adminFetch(`${API_BASE}/api/staff-availability`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        staffMemberId,
        availabilityType,
        dateStart,
        dateEnd,
        timeStart: timeStart ? timeStart + ':00' : null,
        timeEnd: timeEnd ? timeEnd + ':00' : null,
        notes,
        reason: notes,
        isApproved: true
      })
    });

    if (!res.ok) throw new Error('Errore nel salvataggio');

    showNotification('Disponibilita salvata con successo', 'success');
    document.getElementById('new-availability-modal')?.remove();
    loadStaffAvailability();
  } catch (error) {
    console.error('Error saving availability:', error);
    showNotification('Errore nel salvataggio', 'error');
  }
}

window.openNewAvailabilityModal = openNewAvailabilityModal;
window.saveNewAvailability = saveNewAvailability;
window.toggleAvailTimeFields = toggleAvailTimeFields;

async function deleteAvailability(id) {
  if (!confirm('Sei sicuro di voler eliminare questa disponibilita?')) return;
  
  try {
    const response = await adminFetch(`${API_BASE}/api/staff-availability/${id}`, {
      method: 'DELETE'
    });
    
    if (!response.ok) throw new Error('Errore nell\'eliminazione');
    
    showNotification('Disponibilita eliminata', 'success');
    loadStaffAvailability();
  } catch (error) {
    console.error('Error deleting availability:', error);
    showNotification('Errore nell\'eliminazione', 'error');
  }
}

function assignFromAvailability(availabilityId, staffMemberId) {
  // Navigate to monthly scheduling with staff member pre-selected
  const item = availabilityData.find(a => a.id === availabilityId);
  if (item) {
    showNotification(`Vai alla Turnistica Mensile per assegnare ${item.staffMember?.firstName} ${item.staffMember?.lastName} a un turno`, 'info');
    // Could auto-switch to scheduling tab
    showSection('monthly-scheduling');
  }
}

function exportAvailabilityToExcel() {
  if (filteredAvailabilityData.length === 0) {
    showNotification('Nessun dato da esportare', 'warning');
    return;
  }
  
  const headers = ['Nome', 'Cognome', 'Ruolo', 'Data Inizio', 'Data Fine', 'Ora Inizio', 'Ora Fine', 'Tipo', 'Approvato', 'Note'];
  const rows = filteredAvailabilityData.map(item => [
    item.staffMember?.firstName || '',
    item.staffMember?.lastName || '',
    item.staffMember?.primaryRole || '',
    item.dateStart,
    item.dateEnd,
    item.timeStart || '',
    item.timeEnd || '',
    AVAIL_TYPE_LABELS[item.availabilityType] || item.availabilityType,
    item.isApproved ? 'Si' : 'No',
    item.notes || ''
  ]);
  
  const csv = [headers, ...rows].map(row => row.map(cell => `"${cell}"`).join(',')).join('\n');
  const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `disponibilita_${MONTH_NAMES_IT[availabilityMonth]}_${availabilityYear}.csv`;
  a.click();
  URL.revokeObjectURL(url);
  showNotification('Esportazione completata', 'success');
}

function formatDateIT(dateStr) {
  if (!dateStr) return '-';
  const [year, month, day] = dateStr.split('-');
  return `${day}/${month}/${year}`;
}

// ============================================================================
// VOLUNTEER REIMBURSEMENTS SYSTEM
// ============================================================================

let reimbursementsData = [];
let volunteersData = [];
let locationsDataForReimbursements = [];
let locationDistancesData = [];

async function loadVolunteerReimbursementsSection() {
  // Set current month/year in filters
  const now = new Date();
  document.getElementById('reimbursement-month-filter').value = now.getMonth() + 1;
  document.getElementById('reimbursement-year-filter').value = now.getFullYear();
  document.getElementById('reimbursement-month').value = now.getMonth() + 1;
  document.getElementById('reimbursement-year').value = now.getFullYear();
  
  await Promise.all([
    loadReimbursements(),
    loadVolunteers(),
    loadLocationsForReimbursements()
  ]);
}

async function loadReimbursements() {
  try {
    const month = document.getElementById('reimbursement-month-filter').value;
    const year = document.getElementById('reimbursement-year-filter').value;
    const status = document.getElementById('reimbursement-status-filter').value;
    
    let url = `/api/reimbursements?month=${month}&year=${year}`;
    if (status) url += `&status=${status}`;
    
    const response = await adminFetch(url);
    if (!response.ok) throw new Error('Failed to load reimbursements');
    
    reimbursementsData = await response.json();
    renderReimbursementsList();
    updateReimbursementStats();
  } catch (error) {
    console.error('Error loading reimbursements:', error);
    document.getElementById('reimbursements-list').innerHTML = 
      '<tr><td colspan="8" class="text-center text-muted">Errore nel caricamento</td></tr>';
  }
}

async function loadVolunteers() {
  try {
    const response = await adminFetch('/api/reimbursements/volunteers');
    if (!response.ok) throw new Error('Failed to load volunteers');
    volunteersData = await response.json();
    
    // Populate volunteer select
    const select = document.getElementById('reimbursement-volunteer');
    select.innerHTML = '<option value="">Seleziona volontario...</option>';
    volunteersData.forEach(v => {
      select.innerHTML += `<option value="${v.id}">${v.firstName} ${v.lastName}</option>`;
    });
  } catch (error) {
    console.error('Error loading volunteers:', error);
  }
}

async function loadLocationsForReimbursements() {
  try {
    const response = await adminFetch('/api/locations');
    if (!response.ok) throw new Error('Failed to load locations');
    locationsDataForReimbursements = await response.json();
    
    // Load distances
    const distResponse = await adminFetch('/api/reimbursements/location-distances');
    if (distResponse.ok) {
      locationDistancesData = await distResponse.json();
    }
  } catch (error) {
    console.error('Error loading locations:', error);
  }
}

function renderReimbursementsList() {
  const tbody = document.getElementById('reimbursements-list');
  
  if (reimbursementsData.length === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="8" class="text-center" style="padding: 60px 20px;">
          <div style="color: var(--text-muted);">
            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" style="margin-bottom: 12px; opacity: 0.4;"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><line x1="16" y1="13" x2="8" y2="13"/><line x1="16" y1="17" x2="8" y2="17"/><polyline points="10 9 9 9 8 9"/></svg>
            <p style="font-weight: 600; font-size: 15px; margin-bottom: 4px;">Nessun rimborso trovato</p>
            <p style="font-size: 13px;">Crea il primo rimborso del mese cliccando su "Nuovo Rimborso"</p>
          </div>
        </td>
      </tr>`;
    return;
  }
  
  const statusLabels = {
    'draft': '<span class="status-badge status-inactive">Bozza</span>',
    'pending_signature': '<span class="status-badge status-warning">In attesa</span>',
    'signed': '<span class="status-badge status-info">Firmato</span>',
    'approved': '<span class="status-badge status-active">Approvato</span>',
    'paid': '<span class="status-badge status-active">Pagato</span>',
    'cancelled': '<span class="status-badge status-inactive">Annullato</span>'
  };
  
  tbody.innerHTML = reimbursementsData.map(r => `
    <tr>
      <td>
        <div style="display: flex; align-items: center; gap: 10px;">
          <div style="width: 36px; height: 36px; border-radius: 8px; background: #eff6ff; display: flex; align-items: center; justify-content: center; color: #3b82f6; font-weight: 600; font-size: 13px; flex-shrink: 0;">
            ${(r.volunteer?.firstName?.[0] || '')+(r.volunteer?.lastName?.[0] || '')}
          </div>
          <div>
            <div style="font-weight: 600; color: var(--text-primary);">${r.volunteer?.firstName || ''} ${r.volunteer?.lastName || ''}</div>
            <div style="font-size: 12px; color: var(--text-muted);">Volontario</div>
          </div>
        </div>
      </td>
      <td><span style="font-weight: 500;">${String(r.month).padStart(2, '0')}/${r.year}</span></td>
      <td><span class="status-badge status-info">${r.totalShifts}</span></td>
      <td>${r.totalHours.toFixed(1)}h</td>
      <td>${r.totalKm.toFixed(0)} km</td>
      <td><span style="font-weight: 700; color: #10b981;">${r.totalAmount.toFixed(2)} EUR</span></td>
      <td>${statusLabels[r.status] || r.status}</td>
      <td>
        <div style="display: flex; gap: 6px;">
          <button class="btn-icon" onclick="viewReimbursement('${r.id}')" title="Visualizza">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
          </button>
          ${r.status === 'draft' ? `
            <button class="btn-icon" onclick="sendForSignature('${r.id}')" title="Invia per firma" style="color: #3b82f6;">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
            </button>
          ` : ''}
          ${r.status === 'signed' ? `
            <button class="btn-icon primary" onclick="approveReimbursement('${r.id}')" title="Approva">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>
            </button>
          ` : ''}
          ${['draft', 'pending_signature', 'signed', 'approved', 'paid'].includes(r.status) ? `
            <button class="btn-icon" onclick="downloadReimbursementPDF('${r.id}')" title="Scarica PDF" style="color: #f59e0b;">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
            </button>
          ` : ''}
          ${r.status === 'draft' ? `
            <button class="btn-icon danger" onclick="deleteReimbursement('${r.id}')" title="Elimina">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
            </button>
          ` : ''}
        </div>
      </td>
    </tr>
  `).join('');
}

function updateReimbursementStats() {
  const total = reimbursementsData.reduce((sum, r) => sum + r.totalAmount, 0);
  const pending = reimbursementsData.filter(r => r.status === 'pending_signature').length;
  const signed = reimbursementsData.filter(r => ['signed', 'approved', 'paid'].includes(r.status)).length;
  const uniqueVolunteers = new Set(reimbursementsData.map(r => r.staffMemberId)).size;
  
  document.getElementById('reimbursement-month-total').textContent = total.toFixed(2).replace('.', ',') + ' EUR';
  document.getElementById('reimbursement-volunteers').textContent = uniqueVolunteers;
  document.getElementById('reimbursement-pending').textContent = pending;
  document.getElementById('reimbursement-signed').textContent = signed;
}

