let shiftRowCounter = 0;
const MEAL_ALLOWANCE = 10.00;
const TARGET_HOURLY_RATE = 8.00;
const KM_RATE = 0.96;
const MIN_SHIFT_PAYMENT = 79.60;
const MAX_SHIFT_PAYMENT = 80.85;

async function generateTestShifts() {
  const staffMemberId = document.getElementById('reimbursement-volunteer').value;
  const month = document.getElementById('reimbursement-month').value;
  const year = document.getElementById('reimbursement-year').value;
  
  if (!staffMemberId) {
    showNotification('Seleziona prima un volontario', 'error');
    return;
  }
  
  try {
    const response = await adminFetch('/api/reimbursements/generate-test-shifts', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ staffMemberId, month: parseInt(month), year: parseInt(year), numShifts: 10 })
    });
    
    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.error || 'Errore nella generazione');
    }
    
    const result = await response.json();
    showNotification(result.message, 'success');
    loadVolunteerShifts();
  } catch (error) {
    console.error('Error generating test shifts:', error);
    showNotification(error.message, 'error');
  }
}

async function loadVolunteerShifts() {
  const staffMemberId = document.getElementById('reimbursement-volunteer').value;
  const month = document.getElementById('reimbursement-month').value;
  const year = document.getElementById('reimbursement-year').value;
  
  if (!staffMemberId) {
    document.getElementById('shifts-container').innerHTML = '<div style="text-align: center; color: var(--text-muted); padding: 20px;">Seleziona un volontario per vedere i turni</div>';
    document.getElementById('reimb-summary-box').style.display = 'none';
    return;
  }
  
  const loadingIndicator = document.getElementById('reimb-loading-indicator');
  loadingIndicator.style.display = 'block';
  document.getElementById('shifts-container').innerHTML = '';
  
  try {
    const response = await adminFetch(`/api/reimbursements/volunteer-shifts/${staffMemberId}?month=${month}&year=${year}`);
    const shifts = await response.json();
    
    loadingIndicator.style.display = 'none';
    
    if (shifts.length === 0) {
      document.getElementById('shifts-container').innerHTML = '<div style="text-align: center; color: var(--text-muted); padding: 20px;">Nessun turno trovato per questo periodo. Puoi aggiungere turni manualmente.</div>';
      addShiftRow();
    } else {
      shiftRowCounter = 0;
      shifts.forEach(shift => {
        addShiftRowWithData(shift);
      });
    }
    
    updateReimbursementPreview();
  } catch (error) {
    console.error('Error loading volunteer shifts:', error);
    loadingIndicator.style.display = 'none';
    document.getElementById('shifts-container').innerHTML = '<div style="text-align: center; color: var(--text-muted); padding: 20px;">Errore nel caricamento. Puoi aggiungere turni manualmente.</div>';
    addShiftRow();
  }
}

function addShiftRowWithData(shiftData) {
  shiftRowCounter++;
  const container = document.getElementById('shifts-container');
  
  // Show header when first shift is added
  document.getElementById('shifts-header').style.display = 'grid';
  container.style.borderRadius = '0 0 8px 8px';
  
  const locationOptions = locationsDataForReimbursements.map(l => 
    `<option value="${l.id}" ${l.id === shiftData.locationId ? 'selected' : ''}>${l.name}</option>`
  ).join('');
  
  // Calculate km and amount for this shift
  const hours = parseFloat(shiftData.hours) || 10;
  const basePayment = hours * TARGET_HOURLY_RATE;
  const kmAmount = basePayment - MEAL_ALLOWANCE;
  const calculatedKm = kmAmount / KM_RATE;
  
  const row = document.createElement('div');
  row.className = 'shift-row';
  row.id = `shift-row-${shiftRowCounter}`;
  row.dataset.rowId = shiftRowCounter;
  row.style.cssText = 'display: grid; grid-template-columns: 110px 1fr 70px 70px 90px 90px auto; gap: 10px; padding: 10px 12px; background: var(--surface-color); border-bottom: 1px solid var(--border-color); align-items: center;';
  row.innerHTML = `
    <input type="date" class="form-input shift-date" value="${shiftData.date || ''}" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px;">
    <select class="form-select shift-location" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px;">
      <option value="">Sede...</option>
      ${locationOptions}
    </select>
    <input type="number" class="form-input shift-hours" value="${hours}" min="1" max="24" step="0.5" placeholder="Ore" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px; text-align: center;">
    <select class="form-select shift-time" required style="font-size: 12px; padding: 6px 8px;">
      <option value="07:00" ${shiftData.startTime?.startsWith('07') ? 'selected' : ''}>07:00</option>
      <option value="12:00" ${shiftData.startTime?.startsWith('12') ? 'selected' : ''}>12:00</option>
      <option value="14:00" ${shiftData.startTime?.startsWith('14') ? 'selected' : ''}>14:00</option>
      <option value="19:00" ${shiftData.startTime?.startsWith('19') ? 'selected' : ''}>19:00</option>
    </select>
    <span class="shift-km" style="font-size: 12px; font-weight: 500; color: var(--text-muted); text-align: center;">${calculatedKm.toFixed(1)} km</span>
    <span class="shift-amount" style="font-size: 12px; font-weight: 600; color: #10b981; text-align: center;">${basePayment.toFixed(2).replace('.', ',')} EUR</span>
    <button type="button" class="btn-icon-sm btn-danger" onclick="removeShiftRow(${shiftRowCounter}); updateReimbursementPreview();" title="Rimuovi" style="padding: 4px;">
      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>
  `;
  container.appendChild(row);
}

function addShiftRow() {
  shiftRowCounter++;
  const container = document.getElementById('shifts-container');
  
  // Show header when first shift is added
  document.getElementById('shifts-header').style.display = 'grid';
  container.style.borderRadius = '0 0 8px 8px';
  
  const emptyMessage = container.querySelector('div[style*="text-align: center"]');
  if (emptyMessage) emptyMessage.remove();
  
  const locationOptions = locationsDataForReimbursements.map(l => 
    `<option value="${l.id}">${l.name}</option>`
  ).join('');
  
  // Default values for new shift
  const hours = 10;
  const basePayment = hours * TARGET_HOURLY_RATE;
  const kmAmount = basePayment - MEAL_ALLOWANCE;
  const calculatedKm = kmAmount / KM_RATE;
  
  const row = document.createElement('div');
  row.className = 'shift-row';
  row.id = `shift-row-${shiftRowCounter}`;
  row.dataset.rowId = shiftRowCounter;
  row.style.cssText = 'display: grid; grid-template-columns: 110px 1fr 70px 70px 90px 90px auto; gap: 10px; padding: 10px 12px; background: var(--surface-color); border-bottom: 1px solid var(--border-color); align-items: center;';
  row.innerHTML = `
    <input type="date" class="form-input shift-date" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px;">
    <select class="form-select shift-location" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px;">
      <option value="">Sede...</option>
      ${locationOptions}
    </select>
    <input type="number" class="form-input shift-hours" value="10" min="1" max="24" step="0.5" placeholder="Ore" onchange="updateReimbursementPreview()" required style="font-size: 12px; padding: 6px 8px; text-align: center;">
    <select class="form-select shift-time" required style="font-size: 12px; padding: 6px 8px;">
      <option value="07:00">07:00</option>
      <option value="12:00">12:00</option>
      <option value="14:00">14:00</option>
      <option value="19:00">19:00</option>
    </select>
    <span class="shift-km" style="font-size: 12px; font-weight: 500; color: var(--text-muted); text-align: center;">${calculatedKm.toFixed(1)} km</span>
    <span class="shift-amount" style="font-size: 12px; font-weight: 600; color: #10b981; text-align: center;">${basePayment.toFixed(2).replace('.', ',')} EUR</span>
    <button type="button" class="btn-icon-sm btn-danger" onclick="removeShiftRow(${shiftRowCounter}); updateReimbursementPreview();" title="Rimuovi" style="padding: 4px;">
      <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
    </button>
  `;
  container.appendChild(row);
  updateReimbursementPreview();
}

function removeShiftRow(id) {
  const row = document.getElementById(`shift-row-${id}`);
  if (row) row.remove();
}

function updateReimbursementPreview() {
  const shiftRows = document.querySelectorAll('#shifts-container .shift-row');
  const summaryBox = document.getElementById('reimb-summary-box');
  const shiftsHeader = document.getElementById('shifts-header');
  const shiftsContainer = document.getElementById('shifts-container');
  
  if (shiftRows.length === 0) {
    summaryBox.style.display = 'none';
    shiftsHeader.style.display = 'none';
    shiftsContainer.style.borderRadius = '8px';
    return;
  }
  
  // Show header when there are shifts
  shiftsHeader.style.display = 'grid';
  shiftsContainer.style.borderRadius = '0 0 8px 8px';
  
  let totalShifts = 0;
  let totalHours = 0;
  let totalKm = 0;
  
  for (const row of shiftRows) {
    const hours = parseFloat(row.querySelector('.shift-hours')?.value) || 0;
    const locationId = row.querySelector('.shift-location')?.value;
    
    if (hours > 0 && locationId) {
      totalShifts++;
      totalHours += hours;
      
      // Calculate km and amount for this shift and update display
      const basePayment = hours * TARGET_HOURLY_RATE;
      const kmAmount = basePayment - MEAL_ALLOWANCE;
      const calculatedKm = kmAmount / KM_RATE;
      totalKm += calculatedKm;
      
      // Update the km and amount display in the row
      const kmSpan = row.querySelector('.shift-km');
      const amountSpan = row.querySelector('.shift-amount');
      if (kmSpan) kmSpan.textContent = calculatedKm.toFixed(1) + ' km';
      if (amountSpan) amountSpan.textContent = basePayment.toFixed(2).replace('.', ',') + ' EUR';
    }
  }
  
  if (totalShifts === 0) {
    summaryBox.style.display = 'none';
    return;
  }
  
  const totalMeals = totalShifts * MEAL_ALLOWANCE;
  const totalPayment = totalHours * TARGET_HOURLY_RATE;
  const kmReimbursement = totalPayment - totalMeals;
  
  summaryBox.style.display = 'block';
  document.getElementById('reimb-preview-shifts').textContent = totalShifts;
  document.getElementById('reimb-preview-hours').textContent = totalHours.toFixed(1);
  document.getElementById('reimb-preview-km-distance').textContent = Math.round(totalKm);
  document.getElementById('reimb-preview-meals').textContent = `${totalShifts} x 10 EUR`;
  document.getElementById('reimb-preview-total').textContent = totalPayment.toFixed(2).replace('.', ',') + ' EUR';
  document.getElementById('reimb-preview-km-count').textContent = Math.round(totalKm);
  document.getElementById('reimb-preview-km-total').textContent = kmReimbursement.toFixed(2).replace('.', ',');
  document.getElementById('reimb-preview-meal-count').textContent = totalShifts;
  document.getElementById('reimb-preview-meal-total').textContent = totalMeals.toFixed(2).replace('.', ',');
}

async function calculateAndCreateReimbursement() {
  const staffMemberId = document.getElementById('reimbursement-volunteer').value;
  const month = parseInt(document.getElementById('reimbursement-month').value);
  const year = parseInt(document.getElementById('reimbursement-year').value);
  const notes = document.getElementById('reimbursement-notes').value;
  
  if (!staffMemberId) {
    showNotification('Seleziona un volontario', 'error');
    return;
  }
  
  // Collect shifts
  const shiftRows = document.querySelectorAll('#shifts-container .shift-row');
  const shifts = [];
  
  for (const row of shiftRows) {
    const date = row.querySelector('.shift-date').value;
    const locationId = row.querySelector('.shift-location').value;
    const hours = parseFloat(row.querySelector('.shift-hours').value);
    const startTime = row.querySelector('.shift-time').value;
    
    if (!date || !locationId || !hours) {
      showNotification('Compila tutti i dati dei turni', 'error');
      return;
    }
    
    shifts.push({ date, locationId, hours, startTime });
  }
  
  if (shifts.length === 0) {
    showNotification('Aggiungi almeno un turno', 'error');
    return;
  }
  
  try {
    // Note: totalAmount is NOT sent - it is calculated automatically server-side
    // based on €8/hour rate (with small variance for realism)
    const response = await adminFetch('/api/reimbursements/calculate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ staffMemberId, shifts, month, year, notes })
    });
    
    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.error || 'Errore nel calcolo');
    }
    
    const result = await response.json();
    showNotification('Rimborso creato con successo!', 'success');
    closeNewReimbursementModal();
    loadReimbursements();
  } catch (error) {
    console.error('Error creating reimbursement:', error);
    showNotification(error.message, 'error');
  }
}

// Location distances modal
function openLocationDistancesModal() {
  const modal = document.getElementById('location-distances-modal');
  modal.classList.remove('hidden');
  modal.classList.add('active');
  renderLocationDistances();
}

function closeLocationDistancesModal() {
  const modal = document.getElementById('location-distances-modal');
  modal.classList.remove('active');
  modal.classList.add('hidden');
}

function renderLocationDistances() {
  const container = document.getElementById('location-distances-list');
  
  if (locationsDataForReimbursements.length === 0) {
    container.innerHTML = '<div class="text-center text-muted">Nessuna sede configurata</div>';
    return;
  }
  
  container.innerHTML = locationsDataForReimbursements.map(loc => {
    const distance = locationDistancesData.find(d => d.locationId === loc.id);
    const km = distance ? distance.defaultDistanceKm : '';
    return `
      <div class="distance-row" style="display: flex; gap: 16px; align-items: center; margin-bottom: 12px; padding: 12px; background: var(--surface-color); border-radius: 8px;">
        <span style="flex: 1; font-weight: 500;">${loc.name}</span>
        <input type="number" class="form-input location-distance-input" 
               data-location-id="${loc.id}" 
               data-location-name="${loc.name}"
               value="${km}" 
               step="0.1" min="0" 
               placeholder="km"
               style="width: 100px;">
        <span style="color: var(--text-muted);">km (solo andata)</span>
      </div>
    `;
  }).join('');
}

async function saveLocationDistances() {
  const inputs = document.querySelectorAll('.location-distance-input');
  
  try {
    for (const input of inputs) {
      const locationId = input.dataset.locationId;
      const locationName = input.dataset.locationName;
      const defaultDistanceKm = parseFloat(input.value);
      
      if (defaultDistanceKm && defaultDistanceKm > 0) {
        await adminFetch('/api/reimbursements/location-distances', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ locationId, locationName, defaultDistanceKm })
        });
      }
    }
    
    showNotification('Distanze salvate con successo', 'success');
    closeLocationDistancesModal();
    loadLocationsForReimbursements();
  } catch (error) {
    console.error('Error saving distances:', error);
    showNotification('Errore nel salvataggio', 'error');
  }
}

// View/Actions
async function viewReimbursement(id) {
  try {
    const response = await adminFetch(`/api/reimbursements/${id}`);
    if (!response.ok) throw new Error('Failed to load reimbursement');
    
    const data = await response.json();
    const modal = document.getElementById('view-reimbursement-modal');
    const content = document.getElementById('view-reimbursement-content');
    const actions = document.getElementById('view-reimbursement-actions');
    
    const volunteer = volunteersData.find(v => v.id === data.staffMemberId);
    
    content.innerHTML = `
      <div class="reimbursement-summary" style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 24px;">
        <div class="summary-item" style="padding: 16px; background: var(--surface-color); border-radius: 8px;">
          <div style="color: var(--text-muted); font-size: 12px;">Volontario</div>
          <div style="font-weight: 600; font-size: 16px;">${volunteer?.firstName || ''} ${volunteer?.lastName || ''}</div>
        </div>
        <div class="summary-item" style="padding: 16px; background: var(--surface-color); border-radius: 8px;">
          <div style="color: var(--text-muted); font-size: 12px;">Periodo</div>
          <div style="font-weight: 600; font-size: 16px;">${String(data.month).padStart(2, '0')}/${data.year}</div>
        </div>
        <div class="summary-item" style="padding: 16px; background: var(--surface-color); border-radius: 8px;">
          <div style="color: var(--text-muted); font-size: 12px;">Totale Km</div>
          <div style="font-weight: 600; font-size: 16px;">${data.totalKm.toFixed(1)} km</div>
        </div>
        <div class="summary-item" style="padding: 16px; background: linear-gradient(135deg, #3b82f6, #8b5cf6); border-radius: 8px; color: white;">
          <div style="opacity: 0.9; font-size: 12px;">Totale Rimborso</div>
          <div style="font-weight: 700; font-size: 20px;">${data.totalAmount.toFixed(2)} EUR</div>
        </div>
      </div>
      
      <h4 style="margin-bottom: 12px;">Dettaglio Turni</h4>
      <table class="data-table">
        <thead>
          <tr>
            <th>Data</th>
            <th>Sede</th>
            <th>Ore</th>
            <th>Km</th>
            <th>EUR/km</th>
            <th>Rimborso Km</th>
            <th>Pasto</th>
            <th>Totale</th>
          </tr>
        </thead>
        <tbody>
          ${(data.shifts || []).map(s => `
            <tr>
              <td>${new Date(s.shiftDate).toLocaleDateString('it-IT')}</td>
              <td>${s.locationName}</td>
              <td>${s.hoursWorked.toFixed(1)}</td>
              <td>${s.kmDistance.toFixed(1)}</td>
              <td>${s.kmRate.toFixed(4)}</td>
              <td>${s.kmAmount.toFixed(2)} EUR</td>
              <td>${s.mealAmount.toFixed(2)} EUR</td>
              <td><strong>${s.totalAmount.toFixed(2)} EUR</strong></td>
            </tr>
          `).join('')}
        </tbody>
      </table>
      
      ${data.signatureData ? `
        <div style="margin-top: 24px;">
          <h4>Firma Volontario</h4>
          <img src="${data.signatureData}" alt="Firma" style="max-width: 200px; border: 1px solid var(--border-color); border-radius: 4px;">
          <div style="color: var(--text-muted); font-size: 12px; margin-top: 8px;">
            Firmato il: ${data.signedAt ? new Date(data.signedAt).toLocaleString('it-IT') : 'N/D'}
          </div>
        </div>
      ` : ''}
    `;
    
    actions.innerHTML = `
      <button class="btn btn-secondary" onclick="closeViewReimbursementModal()">Chiudi</button>
      <button class="btn btn-primary" onclick="downloadReimbursementPDF('${id}')">Scarica PDF</button>
    `;
    
    modal.classList.remove('hidden');
    modal.classList.add('active');
  } catch (error) {
    console.error('Error viewing reimbursement:', error);
    showNotification('Errore nel caricamento', 'error');
  }
}

function closeViewReimbursementModal() {
  const modal = document.getElementById('view-reimbursement-modal');
  modal.classList.remove('active');
  modal.classList.add('hidden');
}

async function sendForSignature(id) {
  if (!confirm('Inviare il rimborso al volontario per la firma?')) return;
  
  try {
    const response = await adminFetch(`/api/reimbursements/${id}/send`, { method: 'POST' });
    if (!response.ok) throw new Error('Failed to send');
    
    showNotification('Rimborso inviato per la firma', 'success');
    loadReimbursements();
  } catch (error) {
    console.error('Error sending reimbursement:', error);
    showNotification('Errore nell\'invio', 'error');
  }
}

async function approveReimbursement(id) {
  if (!confirm('Approvare il rimborso?')) return;
  
  try {
    const response = await adminFetch(`/api/reimbursements/${id}/approve`, { method: 'POST' });
    if (!response.ok) throw new Error('Failed to approve');
    
    showNotification('Rimborso approvato', 'success');
    loadReimbursements();
  } catch (error) {
    console.error('Error approving reimbursement:', error);
    showNotification('Errore nell\'approvazione', 'error');
  }
}

function downloadReimbursementPDF(id) {
  window.open(`/api/reimbursements/${id}/pdf`, '_blank');
}

async function deleteReimbursement(id) {
  if (!confirm('Eliminare il rimborso? Questa azione non puo essere annullata.')) return;
  
  try {
    const response = await adminFetch(`/api/reimbursements/${id}`, { method: 'DELETE' });
    if (!response.ok) throw new Error('Failed to delete');
    
    showNotification('Rimborso eliminato', 'success');
    loadReimbursements();
  } catch (error) {
    console.error('Error deleting reimbursement:', error);
    showNotification('Errore nell\'eliminazione', 'error');
  }
}

