let partnerCategoryChart = null;

async function loadPartnerDashboard() {
  try {
    const response = await adminFetch('/api/partners/stats/dashboard');
    if (!response.ok) throw new Error('Failed to load partner stats');
    const stats = await response.json();
    
    // Update stat cards
    const approvedEl = document.getElementById('partner-total-approved');
    if (approvedEl) approvedEl.textContent = (stats.statusStats && stats.statusStats.approved) || 0;
    const pendingEl = document.getElementById('partner-pending-count');
    if (pendingEl) pendingEl.textContent = stats.pendingRequests || 0;
    const verificationsEl = document.getElementById('partner-verifications-month');
    if (verificationsEl) verificationsEl.textContent = (stats.verifications && stats.verifications.thisMonth) || 0;
    const ratingEl = document.getElementById('partner-avg-rating');
    if (ratingEl) ratingEl.textContent = (stats.ratings && stats.ratings.average) || '-';
    
    // Update tier stats
    const tierStats = document.getElementById('partner-tier-stats');
    if (tierStats) {
      const tiers = ['platinum', 'gold', 'silver', 'bronze'];
      tiers.forEach(tier => {
        const countEl = tierStats.querySelector('.tier-' + tier + ' .tier-count');
        if (countEl) countEl.textContent = (stats.tierStats && stats.tierStats[tier]) || 0;
      });
    }
    
    // Update badge in sidebar
    const badge = document.getElementById('partner-requests-badge');
    if (badge) {
      badge.textContent = stats.pendingRequests || 0;
      badge.style.display = stats.pendingRequests > 0 ? 'inline-flex' : 'none';
    }
    
    // Load category chart
    if (stats.categoryStats && stats.categoryStats.length > 0) {
      renderPartnerCategoryChart(stats.categoryStats);
    }
    
    // Load recent requests
    loadRecentPartnerRequests();
    
  } catch (error) {
    console.error('Error loading partner dashboard:', error);
  }
}

function renderPartnerCategoryChart(categoryStats) {
  const container = document.getElementById('partner-category-bars');
  if (!container) return;
  
  const categoryLabels = {
    ristorazione: 'Ristorazione',
    commercio: 'Commercio',
    servizi: 'Servizi',
    salute: 'Salute',
    tempo_libero: 'Tempo Libero',
    viaggi: 'Viaggi',
    auto: 'Auto',
    casa: 'Casa',
    tecnologia: 'Tecnologia',
    formazione: 'Formazione',
    altro: 'Altro'
  };
  
  const colors = {
    ristorazione: '#f59e0b',
    commercio: '#10b981',
    servizi: '#3b82f6',
    salute: '#ef4444',
    tempo_libero: '#8b5cf6',
    viaggi: '#06b6d4',
    auto: '#64748b',
    casa: '#ec4899',
    tecnologia: '#14b8a6',
    formazione: '#f97316',
    altro: '#6b7280'
  };
  
  const total = categoryStats.reduce((sum, c) => sum + c.count, 0);
  const sorted = [...categoryStats].sort((a, b) => b.count - a.count);
  
  container.innerHTML = sorted.map(c => {
    const percentage = total > 0 ? Math.round((c.count / total) * 100) : 0;
    const color = colors[c.category] || '#6b7280';
    const label = categoryLabels[c.category] || c.category;
    
    return `
      <div style="display: flex; align-items: center; gap: 0.75rem;">
        <div style="width: 90px; font-size: 0.75rem; color: #64748b; font-weight: 500;">${label}</div>
        <div style="flex: 1; height: 8px; background: #f1f5f9; border-radius: 4px; overflow: hidden;">
          <div style="width: ${percentage}%; height: 100%; background: ${color}; border-radius: 4px; transition: width 0.5s ease;"></div>
        </div>
        <div style="width: 40px; text-align: right; font-size: 0.875rem; font-weight: 600; color: #1e293b;">${c.count}</div>
      </div>
    `;
  }).join('');
}

async function loadRecentPartnerRequests() {
  try {
    const response = await adminFetch('/api/partner-requests?status=pending');
    if (!response.ok) return;
    const requests = await response.json();
    
    const container = document.getElementById('partner-recent-requests');
    if (!container) return;
    
    if (requests.length === 0) {
      container.innerHTML = '<p class="empty-state">Nessuna richiesta in attesa</p>';
      return;
    }
    
    container.innerHTML = requests.slice(0, 5).map(req => `
      <div class="partner-request-item">
        <div class="request-info">
          <strong>${req.companyName}</strong>
          <span>${req.contactName} - ${req.email}</span>
        </div>
        <div class="request-actions">
          <span class="request-date">${new Date(req.createdAt).toLocaleDateString('it-IT')}</span>
          <button class="btn btn-sm btn-primary" onclick="convertPartnerRequest('${req.id}')">Approva</button>
        </div>
      </div>
    `).join('');
    
  } catch (error) {
    console.error('Error loading recent requests:', error);
  }
}

async function loadPartnersList() {
  try {
    const statusFilter = document.getElementById('partner-filter-status')?.value || '';
    const categoryFilter = document.getElementById('partner-filter-category')?.value || '';
    
    let url = '/api/partners?';
    if (statusFilter) url += `status=${statusFilter}&`;
    if (categoryFilter) url += `category=${categoryFilter}&`;
    
    const response = await adminFetch(url);
    if (!response.ok) throw new Error('Failed to load partners');
    const partners = await response.json();
    
    renderPartnersTable(partners);
    
  } catch (error) {
    console.error('Error loading partners:', error);
    const tbody = document.getElementById('partners-tbody');
    if (tbody) {
      tbody.innerHTML = '<tr><td colspan="8" class="text-center text-muted">Errore nel caricamento</td></tr>';
    }
  }
}

function renderPartnersTable(partners) {
  const tbody = document.getElementById('partners-tbody');
  if (!tbody) return;
  
  if (partners.length === 0) {
    tbody.innerHTML = '<tr><td colspan="8" class="text-center text-muted">Nessun partner trovato</td></tr>';
    return;
  }
  
  const statusLabels = { pending: 'In Attesa', approved: 'Attivo', rejected: 'Rifiutato', suspended: 'Sospeso', inactive: 'Inattivo' };
  const statusClasses = { pending: 'warning', approved: 'success', rejected: 'danger', suspended: 'warning', inactive: 'secondary' };
  const categoryLabels = {
    ristorazione: 'Ristorazione', commercio: 'Commercio', servizi: 'Servizi', salute: 'Salute',
    tempo_libero: 'Tempo Libero', viaggi: 'Viaggi', auto: 'Auto', casa: 'Casa',
    tecnologia: 'Tecnologia', formazione: 'Formazione', altro: 'Altro'
  };
  const tierColors = { platinum: '#9333ea', gold: '#f59e0b', silver: '#94a3b8', bronze: '#cd7f32' };
  
  tbody.innerHTML = partners.map(p => `
    <tr>
      <td><strong>${p.companyName}</strong></td>
      <td>${categoryLabels[p.category] || p.category}</td>
      <td>${p.contactName || '-'}</td>
      <td>
        <div>${p.email || '-'}</div>
        <div class="text-muted">${p.phone || ''}</div>
      </td>
      <td>${p.discountValue || '-'}</td>
      <td><span class="tier-badge" style="background: ${tierColors[p.tier] || '#6b7280'}; color: white; padding: 2px 8px; border-radius: 4px; font-size: 10px; text-transform: uppercase;">${p.tier}</span></td>
      <td><span class="status-badge status-${statusClasses[p.status] || 'secondary'}">${statusLabels[p.status] || p.status}</span></td>
      <td>
        <div class="action-buttons">
          ${p.status === 'pending' ? `<button class="btn btn-sm btn-success" onclick="approvePartner('${p.id}')">Approva</button>` : ''}
          ${p.status === 'approved' ? `<button class="btn btn-sm btn-warning" onclick="suspendPartner('${p.id}')">Sospendi</button>` : ''}
          <button class="btn btn-sm btn-secondary" onclick="editPartner('${p.id}')">Modifica</button>
          <button class="btn btn-sm btn-danger" onclick="deletePartner('${p.id}')">Elimina</button>
        </div>
      </td>
    </tr>
  `).join('');
}

async function loadPartnerRequests() {
  try {
    const statusFilter = document.getElementById('request-filter-status')?.value || '';
    
    let url = '/api/partner-requests';
    if (statusFilter) url += `?status=${statusFilter}`;
    
    const response = await adminFetch(url);
    if (!response.ok) throw new Error('Failed to load requests');
    const requests = await response.json();
    
    renderPartnerRequestsTable(requests);
    
  } catch (error) {
    console.error('Error loading partner requests:', error);
  }
}

function renderPartnerRequestsTable(requests) {
  const tbody = document.getElementById('partner-requests-tbody');
  if (!tbody) return;
  
  if (requests.length === 0) {
    tbody.innerHTML = '<tr><td colspan="8" class="text-center text-muted">Nessuna richiesta trovata</td></tr>';
    return;
  }
  
  const statusLabels = { pending: 'In Attesa', contacted: 'Contattato', approved: 'Approvato', rejected: 'Rifiutato' };
  const statusClasses = { pending: 'warning', contacted: 'info', approved: 'success', rejected: 'danger' };
  
  tbody.innerHTML = requests.map(r => `
    <tr>
      <td>${new Date(r.createdAt).toLocaleDateString('it-IT')}</td>
      <td><strong>${r.companyName}</strong></td>
      <td>${r.contactName}</td>
      <td><a href="mailto:${r.email}">${r.email}</a></td>
      <td>${r.phone || '-'}</td>
      <td class="text-muted" style="max-width: 200px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap;" title="${r.message || ''}">${r.message || '-'}</td>
      <td><span class="status-badge status-${statusClasses[r.status] || 'secondary'}">${statusLabels[r.status] || r.status}</span></td>
      <td>
        <div class="action-buttons">
          ${r.status === 'pending' ? `
            <button class="btn btn-sm btn-success" onclick="convertPartnerRequest('${r.id}')">Converti</button>
            <button class="btn btn-sm btn-info" onclick="markRequestContacted('${r.id}')">Contattato</button>
            <button class="btn btn-sm btn-danger" onclick="rejectPartnerRequest('${r.id}')">Rifiuta</button>
          ` : ''}
        </div>
      </td>
    </tr>
  `).join('');
}

async function approvePartner(id) {
  if (!confirm('Confermi approvazione del partner?')) return;
  try {
    const response = await adminFetch(`/api/partners/${id}/approve`, {
      method: 'POST'
    });
    if (response.ok) {
      showNotification('Partner approvato', 'success');
      loadPartnersList();
    }
  } catch (error) {
    showNotification('Errore approvazione', 'error');
  }
}

async function suspendPartner(id) {
  if (!confirm('Confermi sospensione del partner?')) return;
  try {
    const response = await adminFetch(`/api/partners/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'suspended' })
    });
    if (response.ok) {
      showNotification('Partner sospeso', 'success');
      loadPartnersList();
    }
  } catch (error) {
    showNotification('Errore sospensione', 'error');
  }
}

async function deletePartner(id) {
  if (!confirm('Sei sicuro di voler eliminare questo partner?')) return;
  try {
    const response = await adminFetch(`/api/partners/${id}`, {
      method: 'DELETE'
    });
    if (response.ok) {
      showNotification('Partner eliminato', 'success');
      loadPartnersList();
    }
  } catch (error) {
    showNotification('Errore eliminazione', 'error');
  }
}

async function convertPartnerRequest(id) {
  if (!confirm('Confermi conversione della richiesta in partner attivo?')) return;
  try {
    const response = await adminFetch(`/api/partner-requests/${id}/convert`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ category: 'altro' })
    });
    if (response.ok) {
      showNotification('Partner creato con successo!', 'success');
      loadPartnerRequests();
      loadPartnerDashboard();
    }
  } catch (error) {
    showNotification('Errore conversione', 'error');
  }
}

async function markRequestContacted(id) {
  try {
    const response = await adminFetch(`/api/partner-requests/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'contacted' })
    });
    if (response.ok) {
      showNotification('Richiesta aggiornata', 'success');
      loadPartnerRequests();
    }
  } catch (error) {
    showNotification('Errore aggiornamento', 'error');
  }
}

async function rejectPartnerRequest(id) {
  const reason = prompt('Motivo del rifiuto (opzionale):');
  try {
    const response = await adminFetch(`/api/partner-requests/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'rejected', processingNotes: reason || '' })
    });
    if (response.ok) {
      showNotification('Richiesta rifiutata', 'success');
      loadPartnerRequests();
    }
  } catch (error) {
    showNotification('Errore rifiuto', 'error');
  }
}

// Calculate tier based on discount percentage
function calculateTier(discountValue) {
  const value = parseInt(discountValue) || 0;
  if (value >= 20) return { tier: 'platinum', label: 'PLATINUM', color: '#9333ea', description: 'Partner strategico (20%+)' };
  if (value >= 15) return { tier: 'gold', label: 'GOLD', color: '#f59e0b', description: 'Partner premium (15-19%)' };
  if (value >= 12) return { tier: 'silver', label: 'SILVER', color: '#94a3b8', description: 'Partner intermedio (12-14%)' };
  return { tier: 'bronze', label: 'BRONZE', color: '#cd7f32', description: 'Partner base (10-11%)' };
}

// Update tier preview when discount value changes
function updateTierPreview() {
  const discountValue = document.getElementById('partner-discount-value')?.value || 0;
  const tierInfo = calculateTier(discountValue);
  
  const badge = document.getElementById('tier-badge');
  const description = document.getElementById('tier-description');
  
  if (badge) {
    badge.textContent = tierInfo.label;
    badge.style.background = tierInfo.color;
  }
  if (description) {
    description.textContent = tierInfo.description;
  }
}

// Open modal for adding new partner
function openAddPartnerModal() {
  const modal = document.getElementById('partner-modal');
  const form = document.getElementById('partner-form');
  const title = document.getElementById('partner-modal-title');
  
  if (form) form.reset();
  if (title) title.textContent = 'Nuovo Partner';
  document.getElementById('partner-id').value = '';
  document.getElementById('partner-status').value = 'approved';
  document.getElementById('partner-discount-value').value = '10';
  updateTierPreview();
  
  if (modal) modal.classList.remove('hidden');
}

// Open modal for editing existing partner
async function editPartner(id) {
  try {
    const response = await adminFetch(`/api/partners/${id}`);
    if (!response.ok) throw new Error('Failed to load partner');
    const partner = await response.json();
    
    const modal = document.getElementById('partner-modal');
    const title = document.getElementById('partner-modal-title');
    
    if (title) title.textContent = 'Modifica Partner';
    
    // Populate form fields
    document.getElementById('partner-id').value = partner.id;
    document.getElementById('partner-company').value = partner.companyName || '';
    document.getElementById('partner-category').value = partner.category || 'altro';
    document.getElementById('partner-contact').value = partner.contactName || '';
    document.getElementById('partner-email').value = partner.email || '';
    document.getElementById('partner-phone').value = partner.phone || '';
    document.getElementById('partner-website').value = partner.website || '';
    document.getElementById('partner-address').value = partner.address || '';
    document.getElementById('partner-city').value = partner.city || '';
    document.getElementById('partner-province').value = partner.province || '';
    document.getElementById('partner-postalcode').value = partner.postalCode || '';
    document.getElementById('partner-latitude').value = partner.latitude || '';
    document.getElementById('partner-longitude').value = partner.longitude || '';
    document.getElementById('partner-description').value = partner.description || '';
    document.getElementById('partner-discount-type').value = partner.discountType || 'percentage';
    document.getElementById('partner-discount-value').value = partner.discountValue || '10';
    document.getElementById('partner-status').value = partner.status || 'pending';
    
    updateTierPreview();
    
    if (modal) modal.classList.remove('hidden');
    
  } catch (error) {
    console.error('Error loading partner:', error);
    showNotification('Errore nel caricamento del partner', 'error');
  }
}

// Close partner modal
function closePartnerModal() {
  const modal = document.getElementById('partner-modal');
  if (modal) modal.classList.add('hidden');
}

// Save partner (create or update)
async function savePartner(event) {
  event.preventDefault();
  
  const id = document.getElementById('partner-id').value;
  const discountValue = parseInt(document.getElementById('partner-discount-value').value) || 10;
  const tierInfo = calculateTier(discountValue);
  
  const data = {
    companyName: document.getElementById('partner-company').value,
    category: document.getElementById('partner-category').value,
    contactName: document.getElementById('partner-contact').value,
    email: document.getElementById('partner-email').value,
    phone: document.getElementById('partner-phone').value || null,
    website: document.getElementById('partner-website').value || null,
    address: document.getElementById('partner-address').value || null,
    city: document.getElementById('partner-city').value || null,
    province: document.getElementById('partner-province').value || null,
    postalCode: document.getElementById('partner-postalcode').value || null,
    latitude: document.getElementById('partner-latitude').value || null,
    longitude: document.getElementById('partner-longitude').value || null,
    description: document.getElementById('partner-description').value || null,
    discountType: document.getElementById('partner-discount-type').value,
    discountValue: discountValue.toString(),
    status: document.getElementById('partner-status').value,
    tier: tierInfo.tier
  };
  
  try {
    const url = id ? `/api/partners/${id}` : '/api/partners';
    const method = id ? 'PATCH' : 'POST';
    
    const response = await adminFetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    
    if (!response.ok) {
      const error = await response.json();
      throw new Error(error.message || 'Errore salvataggio');
    }
    
    showNotification(id ? 'Partner aggiornato' : 'Partner creato', 'success');
    closePartnerModal();
    loadPartnersList();
    
  } catch (error) {
    console.error('Error saving partner:', error);
    showNotification('Errore: ' + error.message, 'error');
  }
}

// Event listeners for partner filters
document.getElementById('partner-filter-status')?.addEventListener('change', loadPartnersList);
document.getElementById('partner-filter-category')?.addEventListener('change', loadPartnersList);
document.getElementById('request-filter-status')?.addEventListener('change', loadPartnerRequests);

