// Logo Management
let pendingLogoBase64 = null;

async function loadOrgLogo() {
  if (!currentUserInfo?.organization?.id) return;
  const orgId = currentUserInfo.organization.id;
  try {
    const response = await fetch(`/api/organizations/${orgId}/logo`);
    if (response.ok) {
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const previewImg = document.getElementById('logo-preview-img');
      const currentPreview = document.getElementById('logo-current-preview');
      const noPreview = document.getElementById('logo-no-preview');
      const removeBtn = document.getElementById('logo-remove-btn');
      if (previewImg) previewImg.src = url;
      if (currentPreview) currentPreview.style.display = '';
      if (noPreview) noPreview.style.display = 'none';
      if (removeBtn) removeBtn.style.display = '';
    }
  } catch (e) {
    console.log('No logo found for organization');
  }
}

async function handleLogoUpload(event) {
  const file = event.target.files[0];
  if (!file) return;

  if (file.size > 2 * 1024 * 1024) {
    showNotification('Il file è troppo grande. Massimo 2 MB.', 'error');
    return;
  }

  if (!['image/png', 'image/jpeg', 'image/webp'].includes(file.type)) {
    showNotification('Formato non supportato. Usa PNG, JPG o WebP.', 'error');
    return;
  }

  const orgId = currentUserInfo?.organization?.id;
  if (!orgId) {
    showNotification('Organizzazione non trovata', 'error');
    return;
  }

  const statusEl = document.getElementById('logo-upload-status');
  const msgEl = document.getElementById('logo-upload-message');
  if (statusEl) statusEl.style.display = '';
  if (msgEl) { msgEl.textContent = 'Caricamento in corso...'; msgEl.style.color = '#0369a1'; }

  try {
    const reader = new FileReader();
    reader.onload = async function(e) {
      const base64Data = e.target.result;
      const response = await adminFetch(`/api/organizations/${orgId}/logo`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ logoData: base64Data, mimeType: file.type }),
      });

      if (response.ok) {
        showNotification('Logo caricato con successo!', 'success');
        if (msgEl) { msgEl.textContent = 'Logo caricato con successo!'; msgEl.style.color = '#15803d'; }
        loadOrgLogo();
      } else {
        const err = await response.json();
        showNotification('Errore: ' + (err.error || 'Caricamento fallito'), 'error');
        if (msgEl) { msgEl.textContent = 'Errore nel caricamento'; msgEl.style.color = '#dc2626'; }
      }
    };
    reader.readAsDataURL(file);
  } catch (error) {
    showNotification('Errore nel caricamento del logo', 'error');
    if (msgEl) { msgEl.textContent = 'Errore nel caricamento'; msgEl.style.color = '#dc2626'; }
  }

  event.target.value = '';
}

async function removeOrgLogo() {
  const orgId = currentUserInfo?.organization?.id;
  if (!orgId) return;

  if (!confirm('Sei sicuro di voler rimuovere il logo?')) return;

  try {
    const response = await adminFetch(`/api/organizations/${orgId}/logo`, { method: 'DELETE' });
    if (response.ok) {
      showNotification('Logo rimosso', 'success');
      const previewImg = document.getElementById('logo-preview-img');
      const currentPreview = document.getElementById('logo-current-preview');
      const noPreview = document.getElementById('logo-no-preview');
      const removeBtn = document.getElementById('logo-remove-btn');
      if (previewImg) previewImg.src = '';
      if (currentPreview) currentPreview.style.display = 'none';
      if (noPreview) noPreview.style.display = '';
      if (removeBtn) removeBtn.style.display = 'none';
    }
  } catch (error) {
    showNotification('Errore nella rimozione del logo', 'error');
  }
}
window.handleLogoUpload = handleLogoUpload;
window.removeOrgLogo = removeOrgLogo;

