// ============================================
// CONFIDENTIALITY AGREEMENTS SECTION
// ============================================

let confidentialityAgreements = [];
let confidentialityLocations = [];

function getPublicConfidentialityUrl() {
  return window.location.origin + '/impegno-riservatezza';
}

function copyPublicConfidentialityLink() {
  const url = getPublicConfidentialityUrl();
  navigator.clipboard.writeText(url).then(() => {
    showNotification('Link copiato negli appunti!', 'success');
  }).catch(() => {
    showNotification('Errore durante la copia', 'error');
  });
}

async function loadConfidentialityAgreements() {
  const linkEl = document.getElementById('public-conf-link');
  if (linkEl) {
    linkEl.textContent = getPublicConfidentialityUrl();
  }
  try {
    const params = new URLSearchParams();
    const locationFilter = document.getElementById("conf-location-filter");
    const typeFilter = document.getElementById("conf-type-filter");
    const statusFilter = document.getElementById("conf-status-filter");
    
    if (locationFilter?.value && locationFilter.value !== "all") {
      params.append("locationId", locationFilter.value);
    }
    if (typeFilter?.value && typeFilter.value !== "all") {
      params.append("staffType", typeFilter.value);
    }
    if (statusFilter?.value && statusFilter.value !== "all") {
      params.append("valid", statusFilter.value);
    }
    
    const response = await adminFetch(`${API_BASE}/api/admin/confidentiality/agreements?${params}`);
    
    if (!response.ok) throw new Error("Failed to load agreements");
    
    const data = await response.json();
    confidentialityAgreements = data.agreements || [];
    confidentialityLocations = data.locations || [];
    
    // Update stats
    const stats = data.stats || {};
    document.getElementById("conf-total-count").textContent = stats.total || 0;
    document.getElementById("conf-valid-count").textContent = stats.valid || 0;
    document.getElementById("conf-revoked-count").textContent = stats.revoked || 0;
    document.getElementById("conf-autista-count").textContent = stats.byRole?.autista || 0;
    document.getElementById("conf-soccorritore-count").textContent = stats.byRole?.soccorritore || 0;
    document.getElementById("conf-infermiere-count").textContent = stats.byRole?.infermiere || 0;
    
    // Populate location filter
    populateConfidentialityLocationFilter();
    
    // Render table
    renderConfidentialityTable();
  } catch (error) {
    console.error("Error loading confidentiality agreements:", error);
    showNotification("Errore nel caricamento degli impegni", "error");
  }
}

function populateConfidentialityLocationFilter() {
  const select = document.getElementById("conf-location-filter");
  if (!select) return;
  
  const currentValue = select.value;
  select.innerHTML = "<option value=\"all\">Tutte le sedi</option>";
  
  confidentialityLocations.forEach(loc => {
    const option = document.createElement("option");
    option.value = loc.id;
    option.textContent = loc.name;
    if (currentValue === loc.id) option.selected = true;
    select.appendChild(option);
  });
}

function filterConfidentialityAgreements() {
  loadConfidentialityAgreements();
}

function renderConfidentialityTable() {
  const tbody = document.getElementById("confidentiality-tbody");
  if (!tbody) return;
  
  const searchInput = document.getElementById("conf-search-input");
  const searchTerm = searchInput?.value?.toLowerCase() || "";
  
  let filtered = confidentialityAgreements;
  
  if (searchTerm) {
    filtered = filtered.filter(a => 
      (a.firstName?.toLowerCase() || "").includes(searchTerm) ||
      (a.lastName?.toLowerCase() || "").includes(searchTerm) ||
      (a.fiscalCode?.toLowerCase() || "").includes(searchTerm)
    );
  }
  
  if (filtered.length === 0) {
    tbody.innerHTML = "<tr><td colspan=\"8\" class=\"empty-state\">Nessun impegno trovato</td></tr>";
    return;
  }
  
  tbody.innerHTML = filtered.map(agreement => {
    const signDate = new Date(agreement.signatureTimestamp || agreement.createdAt).toLocaleDateString("it-IT");
    const statusClass = agreement.isValid ? "badge-success" : "badge-danger";
    const statusText = agreement.isValid ? "Valido" : "Revocato";
    
    return `
      <tr>
        <td>${escapeHtml(agreement.firstName || "-")}</td>
        <td>${escapeHtml(agreement.lastName || "-")}</td>
        <td><span class="badge badge-info">${agreement.staffType || "-"}</span></td>
        <td>${escapeHtml(agreement.role || "-")}</td>
        <td>${escapeHtml(agreement.locationName || "N/A")}</td>
        <td>${signDate}</td>
        <td><span class="badge ${statusClass}">${statusText}</span></td>
        <td>
          <div class="action-buttons">
            <button class="btn-icon" title="Scarica PDF" onclick="downloadConfidentialityPdf('${agreement.id}')">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
            </button>
            ${agreement.isValid ? `
              <button class="btn-icon btn-icon-danger" title="Revoca" onclick="revokeConfidentialityAgreement('${agreement.id}')">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            ` : `
              <button class="btn-icon btn-icon-danger" title="Elimina definitivamente" onclick="deleteConfidentialityAgreement('${agreement.id}', '${escapeHtml(agreement.firstName)} ${escapeHtml(agreement.lastName)}')">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round"><path d="M3 6h18"/><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6"/><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"/></svg>
              </button>
            `}
          </div>
        </td>
      </tr>
    `;
  }).join("");
}

async function downloadConfidentialityPdf(id) {
  try {
    window.open(`${API_BASE}/api/admin/confidentiality/agreements/${id}/pdf`, "_blank");
  } catch (error) {
    console.error("Error downloading PDF:", error);
    showNotification("Errore nel download del PDF", "error");
  }
}

async function revokeConfidentialityAgreement(id) {
  const reason = prompt("Motivo della revoca (opzionale):");
  if (reason === null) return; // User cancelled
  
  try {
    const response = await adminFetch(`${API_BASE}/api/admin/confidentiality/agreements/${id}/revoke`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ reason: reason || "Revocato dall'amministratore" })
    });
    
    if (!response.ok) throw new Error("Failed to revoke");
    
    showNotification("Impegno revocato con successo", "success");
    loadConfidentialityAgreements();
  } catch (error) {
    console.error("Error revoking agreement:", error);
    showNotification("Errore nella revoca dell'impegno", "error");
  }
}

async function deleteConfidentialityAgreement(id, name) {
  if (!confirm(`Sei sicuro di voler eliminare definitivamente l'impegno di ${name}?\n\nQuesta azione non può essere annullata.`)) {
    return;
  }
  
  try {
    const response = await adminFetch(`${API_BASE}/api/admin/confidentiality/agreements/${id}`, {
      method: "DELETE"
    });
    
    if (!response.ok) {
      const data = await response.json();
      throw new Error(data.error || "Failed to delete");
    }
    
    showNotification("Impegno eliminato definitivamente", "success");
    loadConfidentialityAgreements();
  } catch (error) {
    console.error("Error deleting agreement:", error);
    showNotification(error.message || "Errore nell'eliminazione dell'impegno", "error");
  }
}

function exportConfidentialityToExcel() {
  const headers = ["Nome", "Cognome", "Tipologia", "Ruolo", "Sede", "Data Firma", "Stato"];
  const rows = confidentialityAgreements.map(a => [
    a.firstName || "",
    a.lastName || "",
    a.staffType || "",
    a.role || "",
    a.locationName || "N/A",
    new Date(a.signatureTimestamp || a.createdAt).toLocaleDateString("it-IT"),
    a.isValid ? "Valido" : "Revocato"
  ]);
  
  let csvContent = "\ufeff" + headers.join(";") + "\n";
  rows.forEach(row => {
    csvContent += row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(";") + "\n";
  });
  
  const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  link.download = `impegni_riservatezza_${new Date().toISOString().split("T")[0]}.csv`;
  link.click();
  URL.revokeObjectURL(link.href);
  
  showNotification("Export completato", "success");
}


