async function loadConventionClients() {
  try {
    const res = await adminFetch('/api/admin/hub/clients');
    const clients = await res.json();
    const select = document.getElementById('convention-client-select');
    if (select) {
      clients.forEach(c => {
        const opt = document.createElement('option');
        opt.value = c.id;
        opt.textContent = `${c.firstName} ${c.lastName}${c.facilityName ? ' (' + c.facilityName + ')' : ''}`;
        select.appendChild(opt);
      });
    }
  } catch (e) { console.error(e); }
}

async function submitCreateConvention(e) {
  e.preventDefault();
  const form = e.target;
  const data = {
    name: form.name.value,
    description: form.description.value || null,
    clientId: form.clientId.value || null,
    hourlyRate: form.hourlyRate.value ? parseFloat(form.hourlyRate.value) : null,
    perTripRate: form.perTripRate.value ? parseFloat(form.perTripRate.value) : null,
    monthlyFlatRate: form.monthlyFlatRate.value ? parseFloat(form.monthlyFlatRate.value) : null,
    maxTripsPerMonth: form.maxTripsPerMonth.value ? parseInt(form.maxTripsPerMonth.value) : null,
    validFrom: form.validFrom.value || null,
    validTo: form.validTo.value || null,
    terms: form.terms.value || null
  };
  try {
    const res = await adminFetch('/api/admin/hub/conventions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    if (res.ok) {
      showNotification('Convenzione creata con successo', 'success');
      form.closest('.modal-overlay').remove();
      loadHubConventions();
      loadBookingHubStats();
    } else {
      const err = await res.json();
      showNotification(err.error || 'Errore nella creazione', 'error');
    }
  } catch (e) { console.error(e); showNotification('Errore nella creazione', 'error'); }
}

