async function handleOrgLogoUpload(orgId, input) {
  const file = input.files[0];
  if (!file) return;

  if (file.size > 2 * 1024 * 1024) {
    showNotification('Il file deve essere inferiore a 2MB', 'error');
    return;
  }

  const reader = new FileReader();
  reader.onload = async function(e) {
    const logoData = e.target.result;
    const mimeType = file.type;

    try {
      const res = await adminFetch(`/api/organizations/${orgId}/logo`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ logoData, mimeType }),
      });

      if (!res.ok) throw new Error('Errore nel caricamento');
      const data = await res.json();

      const preview = document.getElementById(`org-logo-preview-${orgId}`);
      if (preview) {
        preview.innerHTML = `<img src="${data.logoUrl}?t=${Date.now()}" style="width:100%;height:100%;object-fit:contain">`;
      }

      showNotification('Logo caricato con successo!', 'success');
    } catch (err) {
      console.error('Error uploading logo:', err);
      showNotification('Errore nel caricamento del logo', 'error');
    }
  };
  reader.readAsDataURL(file);
}
window.handleOrgLogoUpload = handleOrgLogoUpload;

async function deleteOrganization(orgId, orgName) {
  if (!confirm(`Sei sicuro di voler eliminare l'organizzazione "${orgName}"?\n\nATTENZIONE: Verranno eliminati tutti i dati associati (utenti, veicoli, sedi, servizi). Questa azione non e reversibile.`)) return;
  if (!confirm(`Conferma finale: eliminare definitivamente "${orgName}" e tutti i suoi dati?`)) return;
  try {
    const res = await adminFetch(`/api/org-admin/organizations/${orgId}`, { method: 'DELETE' });
    if (!res.ok) throw new Error('Errore durante l\'eliminazione');
    showNotification('Organizzazione eliminata con successo', 'success');
    loadOrganizationsPage();
  } catch (err) {
    showNotification(err.message, 'error');
  }
}

