function switchOrgTab(tab) {
  const orgsBtn = document.getElementById('tab-orgs-btn');
  const demoBtn = document.getElementById('tab-demo-btn');
  const orgsList = document.getElementById('organizations-list');
  const demoList = document.getElementById('demo-requests-list');
  const addBtn = document.getElementById('add-org-btn');
  
  if (tab === 'orgs') {
    orgsBtn.style.borderBottomColor = 'var(--primary)';
    orgsBtn.style.color = 'var(--primary)';
    orgsBtn.style.fontWeight = '600';
    demoBtn.style.borderBottomColor = 'transparent';
    demoBtn.style.color = 'var(--text-secondary)';
    demoBtn.style.fontWeight = '500';
    orgsList.style.display = '';
    demoList.style.display = 'none';
    if (addBtn) addBtn.style.display = '';
    loadOrganizationsPage();
  } else {
    demoBtn.style.borderBottomColor = 'var(--primary)';
    demoBtn.style.color = 'var(--primary)';
    demoBtn.style.fontWeight = '600';
    orgsBtn.style.borderBottomColor = 'transparent';
    orgsBtn.style.color = 'var(--text-secondary)';
    orgsBtn.style.fontWeight = '500';
    orgsList.style.display = 'none';
    demoList.style.display = '';
    if (addBtn) addBtn.style.display = 'none';
    loadDemoRequests();
  }
}

async function loadDemoRequests() {
  const container = document.getElementById('demo-requests-list');
  if (!container) return;
  container.innerHTML = '<p style="color:var(--text-secondary);padding:20px">Caricamento richieste...</p>';

  try {
    const res = await fetch('/api/org-admin/demo-requests', { credentials: 'include' });
    if (!res.ok) throw new Error('Errore nel caricamento');
    const requests = await res.json();

    if (requests.length === 0) {
      container.innerHTML = '<div style="text-align:center;padding:48px;color:var(--text-secondary)"><p>Nessuna richiesta demo ricevuta.</p></div>';
      return;
    }

    const statusBadge = (s) => {
      const map = { pending: ['In Attesa', '#F5A623', '#FFF3E0'], approved: ['Approvata', '#00A651', '#E6F9F0'], rejected: ['Rifiutata', '#E74C3C', '#FDECEA'] };
      const [label, color, bg] = map[s] || ['?', '#999', '#f5f5f5'];
      return '<span style="display:inline-flex;align-items:center;padding:3px 10px;border-radius:20px;font-size:12px;font-weight:500;background:' + bg + ';color:' + color + '">' + label + '</span>';
    };

    container.innerHTML = '<div style="display:grid;gap:12px">' + requests.map(r => {
      const date = new Date(r.createdAt).toLocaleDateString('it-IT', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
      return '<div class="card" style="padding:20px">' +
        '<div style="display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:12px">' +
          '<div>' +
            '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">' +
              '<strong style="font-size:16px">' + r.organizationName + '</strong>' +
              statusBadge(r.status) +
            '</div>' +
            '<div style="color:var(--text-secondary);font-size:13px">' +
              '<span style="font-weight:500">' + r.contactName + '</span>' +
              ' &middot; <a href="mailto:' + r.contactEmail + '" style="color:var(--primary)">' + r.contactEmail + '</a>' +
              (r.contactPhone ? ' &middot; ' + r.contactPhone : '') +
            '</div>' +
            '<div style="color:var(--text-secondary);font-size:13px;margin-top:4px">' +
              (r.city ? r.city + (r.province ? ' (' + r.province + ')' : '') : '') +
              (r.vehicleCount ? ' &middot; ' + r.vehicleCount + ' veicoli' : '') +
              ' &middot; ' + date +
            '</div>' +
            (r.notes ? '<div style="margin-top:8px;padding:10px 14px;background:var(--bg-secondary);border-radius:8px;font-size:13px;color:var(--text-secondary);line-height:1.5">' + r.notes + '</div>' : '') +
            (r.reviewNotes ? '<div style="margin-top:6px;font-size:12px;color:var(--text-secondary);font-style:italic">Note revisione: ' + r.reviewNotes + '</div>' : '') +
          '</div>' +
          '<div style="display:flex;gap:8px;flex-shrink:0">' +
            (r.status === 'pending' ? 
              '<button class="btn" style="background:#00A651;color:white;border:none;padding:8px 16px;font-size:13px" onclick="reviewDemoRequest(\'' + r.id + '\', \'approved\')">Approva</button>' +
              '<button class="btn" style="background:#E74C3C;color:white;border:none;padding:8px 16px;font-size:13px" onclick="reviewDemoRequest(\'' + r.id + '\', \'rejected\')">Rifiuta</button>'
            : '<button class="btn btn-outline" style="padding:8px 16px;font-size:13px" onclick="deleteDemoRequest(\'' + r.id + '\')">Elimina</button>') +
          '</div>' +
        '</div>' +
      '</div>';
    }).join('') + '</div>';
  } catch (err) {
    container.innerHTML = '<div style="padding:20px;color:var(--error)">' + err.message + '</div>';
  }
}

async function reviewDemoRequest(id, status) {
  const reviewNotes = prompt(status === 'approved' ? 'Note per l\'approvazione (opzionale):' : 'Motivo del rifiuto (opzionale):');
  try {
    const res = await fetch('/api/org-admin/demo-requests/' + id, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      credentials: 'include',
      body: JSON.stringify({ status, reviewNotes: reviewNotes || '' })
    });
    if (!res.ok) throw new Error('Errore');
    showNotification(status === 'approved' ? 'Richiesta approvata' : 'Richiesta rifiutata', 'success');
    loadDemoRequests();
    updateDemoRequestsBadge();
  } catch (err) {
    showNotification('Errore: ' + err.message, 'error');
  }
}

async function deleteDemoRequest(id) {
  if (!confirm('Eliminare questa richiesta demo?')) return;
  try {
    const res = await fetch('/api/org-admin/demo-requests/' + id, { method: 'DELETE', credentials: 'include' });
    if (!res.ok) throw new Error('Errore');
    showNotification('Richiesta eliminata', 'success');
    loadDemoRequests();
  } catch (err) {
    showNotification('Errore: ' + err.message, 'error');
  }
}

async function updateDemoRequestsBadge() {
  try {
    const res = await fetch('/api/org-admin/demo-requests/count', { credentials: 'include' });
    if (!res.ok) return;
    const data = await res.json();
    const badge = document.getElementById('demo-requests-badge');
    if (badge) {
      if (data.count > 0) {
        badge.textContent = data.count;
        badge.style.display = 'inline';
      } else {
        badge.style.display = 'none';
      }
    }
  } catch (e) {}
}

