function switchSAHubTab(tab) {
  document.querySelectorAll('.sa-hub-tab').forEach(b => {
    b.classList.remove('active');
    b.style.borderBottom = '2px solid transparent';
  });
  const activeBtn = document.querySelector(`.sa-hub-tab[data-tab="${tab}"]`);
  if (activeBtn) {
    activeBtn.classList.add('active');
    activeBtn.style.borderBottom = '2px solid var(--primary)';
  }
  document.getElementById('sa-hub-tab-orgs').style.display = tab === 'orgs' ? 'block' : 'none';
  document.getElementById('sa-hub-tab-bookings').style.display = tab === 'bookings' ? 'block' : 'none';
  document.getElementById('sa-hub-tab-conventions').style.display = tab === 'conventions' ? 'block' : 'none';
}

// === GARE D'APPALTO INTELLIGENCE ===
// === GARE D'APPALTO INTELLIGENCE ===
let allTendersCache = [];

async function syncAnacTenders() {
  const btn = document.getElementById('anac-sync-btn');
  const label = document.getElementById('anac-sync-label');
  const fill = btn.querySelector('.sync-progress-fill');

  btn.classList.remove('sync-done', 'sync-error');
  btn.classList.add('syncing');
  btn.disabled = true;
  label.textContent = 'Importazione in corso...';
  if (fill) fill.style.width = '0%';

  try {
    const res = await adminFetch(`${API_BASE}/api/tenders/sync-anac`, { method: 'POST' });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();

    if (fill) { fill.style.animation = 'none'; fill.style.width = '100%'; }
    btn.classList.remove('syncing');
    btn.classList.add('sync-done');
    label.textContent = data.imported > 0 ? `${data.imported} bandi importati` : 'Tutto aggiornato';

    const banner = document.getElementById('anac-sync-status');
    const msg = document.getElementById('anac-sync-message');
    const time = document.getElementById('anac-sync-time');
    if (banner) banner.style.display = 'flex';
    if (msg) msg.textContent = data.message || `Importati ${data.imported} bandi`;
    if (time) time.textContent = new Date().toLocaleString('it-IT');
    showNotification(data.message || 'Sincronizzazione completata', 'success');
    loadTenders();

    setTimeout(() => {
      btn.classList.remove('sync-done');
      btn.disabled = false;
      label.textContent = 'Importa da ANAC';
      if (fill) { fill.style.width = '0%'; fill.style.animation = ''; }
    }, 4000);
  } catch (e) {
    console.error('ANAC sync error:', e);
    if (fill) { fill.style.animation = 'none'; fill.style.width = '0%'; }
    btn.classList.remove('syncing');
    btn.classList.add('sync-error');
    label.textContent = 'Errore';
    showNotification('Errore nella sincronizzazione ANAC', 'error');

    setTimeout(() => {
      btn.classList.remove('sync-error');
      btn.disabled = false;
      label.textContent = 'Importa da ANAC';
      if (fill) fill.style.animation = '';
    }, 3000);
  }
}

function switchTenderTab(tab) {
  document.querySelectorAll('.tender-tab').forEach(t => t.classList.remove('active'));
  document.querySelector(`.tender-tab[data-tab="${tab}"]`).classList.add('active');
  document.querySelectorAll('.tender-tab-content').forEach(c => c.style.display = 'none');
  document.getElementById(`tender-tab-${tab}`).style.display = 'block';
  const filters = document.getElementById('tender-filters');
  if (tab === 'list') { filters.style.display = ''; }
  else { filters.style.display = 'none'; }
  if (tab === 'timeline') renderTendersTimeline(allTendersCache);
  if (tab === 'map') renderTendersMap(allTendersCache);
}

function filterTendersByStatus(status) {
  const sel = document.getElementById('tender-status-filter');
  if (sel) { sel.value = status; }
  loadTenders();
}

async function loadTenders() {
  try {
    const res = await adminFetch(`${API_BASE}/api/tenders`);
    const tenders = await res.json();
    allTendersCache = tenders;
    const total = tenders.length;
    const active = tenders.filter(t => ['evaluating', 'bidding'].includes(t.status)).length;
    const won = tenders.filter(t => t.status === 'won').length;
    const totalValue = tenders.reduce((sum, t) => sum + (parseFloat(t.estimatedValue) || 0), 0);
    document.getElementById('tender-total-count').textContent = total;
    document.getElementById('tender-active-count').textContent = active;
    document.getElementById('tender-won-count').textContent = won;
    document.getElementById('tender-total-value').textContent = totalValue > 0 ? fmtCur(totalValue) : '-';
    const statusFilter = document.getElementById('tender-status-filter')?.value;
    const priorityFilter = document.getElementById('tender-priority-filter')?.value;
    const serviceFilter = document.getElementById('tender-service-filter')?.value;
    const regionFilter = document.getElementById('tender-region-filter')?.value;
    let filtered = tenders;
    if (statusFilter) filtered = filtered.filter(t => t.status === statusFilter);
    if (priorityFilter) filtered = filtered.filter(t => t.priority === priorityFilter);
    if (serviceFilter) filtered = filtered.filter(t => t.serviceType === serviceFilter);
    if (regionFilter) filtered = filtered.filter(t => (t.region || '').toLowerCase().includes(regionFilter.toLowerCase()));
    renderTendersList(filtered);
  } catch (e) {
    console.error('Error loading tenders:', e);
    document.getElementById('tenders-list').innerHTML = '<div class="empty-state">Errore nel caricamento dei bandi</div>';
  }
}

function fmtCur(v) { return new Intl.NumberFormat('it-IT', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 }).format(v); }

const statusLabels = { new: 'Nuovo', evaluating: 'In Valutazione', bidding: 'In Gara', won: 'Aggiudicato', lost: 'Non Aggiudicato', expired: 'Scaduto', archived: 'Archiviato' };
const priorityLabels = { low: 'Bassa', medium: 'Media', high: 'Alta', critical: 'Critica' };
const serviceLabels = { emergenza_118: 'Emergenza 118', trasporto_dialisi: 'Trasporto Dialisi', trasporto_ordinario: 'Trasporto Ordinario', eventi: 'Eventi', altro: 'Altro' };

function renderTendersList(tenders) {
  const c = document.getElementById('tenders-list');
  if (!tenders.length) {
    c.innerHTML = '<div class="empty-state" style="text-align:center;padding:60px 20px;"><svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="1.5"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg><p style="color:#64748b;margin-top:12px;">Nessun bando trovato. Importa bandi da ANAC o aggiungi manualmente.</p></div>';
    return;
  }
  c.innerHTML = tenders.map(t => {
    const daysLeft = t.deadline ? Math.ceil((new Date(t.deadline) - Date.now()) / (1000*60*60*24)) : null;
    const deadlineClass = daysLeft !== null ? (daysLeft < 15 ? 'color:#ef4444;font-weight:600;' : daysLeft < 30 ? 'color:#f59e0b;' : 'color:#10b981;') : '';
    return `<div class="tender-card">
      <div class="tender-card-header">
        <div class="tender-card-title">${t.title || 'Bando senza titolo'}</div>
        <div class="tender-card-badges">
          <span class="tender-badge ${t.status}">${statusLabels[t.status] || t.status}</span>
          <span class="tender-badge ${t.priority}">${priorityLabels[t.priority] || t.priority}</span>
        </div>
      </div>
      <div class="tender-card-meta">
        ${t.stationeName ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>${t.stationeName}</div>` : ''}
        ${t.region ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>${t.province ? t.province + ', ' : ''}${t.region}</div>` : ''}
        ${t.estimatedValue ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>${fmtCur(parseFloat(t.estimatedValue))}</div>` : ''}
        ${t.deadline ? `<div class="tender-meta-item" style="${deadlineClass}"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>Scadenza: ${new Date(t.deadline).toLocaleDateString('it-IT')}${daysLeft !== null ? ` (${daysLeft} gg)` : ''}</div>` : ''}
        ${t.cpvCode ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="2" y="7" width="20" height="14" rx="2" ry="2"/><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"/></svg>CPV: ${t.cpvCode}</div>` : ''}
        ${t.serviceType ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z"/><line x1="4" y1="22" x2="4" y2="15"/></svg>${serviceLabels[t.serviceType] || t.serviceType}</div>` : ''}
        ${t.durationMonths ? `<div class="tender-meta-item"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/></svg>${t.durationMonths} mesi</div>` : ''}
      </div>
      <div class="tender-card-actions">
        <button class="btn btn-outline" onclick="editTender('${t.id}')">Modifica</button>
        <button class="btn btn-outline" onclick="changeTenderStatus('${t.id}', '${t.status}')">Cambia Stato</button>
        ${t.sourceUrl ? `<a href="${t.sourceUrl}" target="_blank" class="btn btn-outline">Fonte ANAC</a>` : ''}
        <button class="btn btn-outline" style="color:#ef4444;border-color:rgba(239,68,68,0.3);" onclick="deleteTender('${t.id}')">Elimina</button>
      </div>
    </div>`;
  }).join('');
}

function renderTendersTimeline(tenders) {
  const c = document.getElementById('tenders-timeline');
  const withDeadline = tenders.filter(t => t.deadline).sort((a, b) => new Date(a.deadline) - new Date(b.deadline));
  if (!withDeadline.length) {
    c.innerHTML = '<div class="empty-state" style="text-align:center;padding:40px;">Nessun bando con scadenza impostata</div>';
    return;
  }
  c.innerHTML = withDeadline.map(t => {
    const dl = new Date(t.deadline);
    const daysLeft = Math.ceil((dl - Date.now()) / (1000*60*60*24));
    const urgency = daysLeft < 15 ? 'urgent' : daysLeft < 30 ? 'soon' : '';
    return `<div class="timeline-item ${urgency}">
      <div class="timeline-date">${dl.toLocaleDateString('it-IT', { day: 'numeric', month: 'long', year: 'numeric' })} ${daysLeft > 0 ? `(tra ${daysLeft} giorni)` : '(SCADUTO)'}</div>
      <div class="timeline-title">${t.title}</div>
      <div class="timeline-meta">
        ${t.stationeName ? `<span>${t.stationeName}</span>` : ''}
        ${t.estimatedValue ? `<span>${fmtCur(parseFloat(t.estimatedValue))}</span>` : ''}
        <span class="tender-badge ${t.status}" style="font-size:10px;">${statusLabels[t.status] || t.status}</span>
      </div>
    </div>`;
  }).join('');
}

function renderTendersMap(tenders) {
  const mapEl = document.getElementById('tenders-veneto-map');
  const venetoCoords = {
    'Padova': [45.4064, 11.8768], 'Venezia': [45.4408, 12.3155], 'Verona': [45.4384, 10.9916],
    'Vicenza': [45.5455, 11.5354], 'Treviso': [45.6669, 12.2430], 'Rovigo': [45.0699, 11.7902],
    'Belluno': [46.1404, 12.2167]
  };
  mapEl.innerHTML = `<div style="padding:40px;text-align:center;">
    <h3 style="margin-bottom:16px;color:var(--text-primary);">Distribuzione Bandi - Regione Veneto</h3>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(200px,1fr));gap:12px;">
      ${Object.entries(venetoCoords).map(([prov, coords]) => {
        const provTenders = tenders.filter(t => (t.province || '').toLowerCase().includes(prov.toLowerCase()));
        const total = provTenders.length;
        const value = provTenders.reduce((s, t) => s + (parseFloat(t.estimatedValue) || 0), 0);
        return `<div style="padding:16px;background:var(--surface);border:1px solid var(--border);border-radius:12px;text-align:center;${total > 0 ? 'border-color:var(--primary);' : ''}">
          <div style="font-size:24px;font-weight:700;color:${total > 0 ? 'var(--primary)' : 'var(--text-secondary)'};">${total}</div>
          <div style="font-size:14px;font-weight:600;color:var(--text-primary);margin-top:4px;">${prov}</div>
          ${value > 0 ? `<div style="font-size:12px;color:var(--text-secondary);margin-top:4px;">${fmtCur(value)}</div>` : '<div style="font-size:12px;color:var(--text-secondary);margin-top:4px;">Nessun bando</div>'}
        </div>`;
      }).join('')}
    </div>
  </div>`;
}

