    avgResponseTime: { label: 'Tempo Risposta Medio (min)', lower: true },
    tripsPerVehicle: { label: 'Servizi/Veicolo/Giorno', lower: false },
    customerSatisfaction: { label: 'Soddisfazione Cliente (%)', lower: false },
    fleetUtilization: { label: 'Utilizzo Flotta (%)', lower: false },
    revenuePerTrip: { label: 'Ricavo per Servizio (EUR)', lower: false },
    complianceScore: { label: 'Score Compliance (%)', lower: false },
    staffTurnover: { label: 'Turnover Personale (%)', lower: true },
