function renderPredictiveAlerts(data, severityFilter) {
  const allAlerts = data.alerts || [];
  const categoryFilter = document.getElementById('alert-category-filter')?.value;
  let filtered = allAlerts;
  if (categoryFilter) filtered = filtered.filter(a => a.category === categoryFilter);
  if (severityFilter) filtered = filtered.filter(a => a.severity === severityFilter);
  const critical = allAlerts.filter(a => a.severity === 'critical').length;
  const warnings = allAlerts.filter(a => a.severity === 'warning').length;
  const info = allAlerts.filter(a => a.severity === 'info').length;
  document.getElementById('alert-critical-count').textContent = critical;
  document.getElementById('alert-warning-count').textContent = warnings;
  document.getElementById('alert-resolved-count').textContent = info;
  const c = document.getElementById('predictive-alerts-list');
  if (!filtered.length) {
    c.innerHTML = '<div class="empty-state" style="text-align:center;padding:40px;">Nessun alert trovato per i filtri selezionati</div>';
    return;
  }
  const severityColors = { critical: '#ef4444', warning: '#f59e0b', info: '#3b82f6' };
  const severityLabelsMap = { critical: 'Critico', warning: 'Avvertimento', info: 'Informativo' };
  const categoryIcons = {
    fleet: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="1" y="3" width="15" height="13"/><polygon points="16 8 20 8 23 11 23 16 16 16 16 8"/><circle cx="5.5" cy="18.5" r="2.5"/><circle cx="18.5" cy="18.5" r="2.5"/></svg>',
    staff: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>',
    finance: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>',
    compliance: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>',
    operations: '<svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>'
  };
  c.innerHTML = filtered.map(a => `<div style="padding:16px;background:var(--surface);border:1px solid var(--border);border-radius:12px;margin-bottom:12px;border-left:4px solid ${severityColors[a.severity] || '#94a3b8'};">
    <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:12px;">
      <div style="display:flex;align-items:flex-start;gap:12px;flex:1;">
        <div style="padding:8px;background:${severityColors[a.severity]}10;border-radius:8px;color:${severityColors[a.severity]};">${categoryIcons[a.category] || categoryIcons.operations}</div>
        <div style="flex:1;">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;">
            <span style="font-weight:600;font-size:14px;color:var(--text-primary);">${a.title}</span>
            <span style="padding:2px 8px;border-radius:12px;font-size:10px;font-weight:600;background:${severityColors[a.severity]}15;color:${severityColors[a.severity]};">${severityLabelsMap[a.severity] || a.severity}</span>
            ${a.confidence ? `<span style="font-size:10px;color:var(--text-secondary);">Confidenza: ${a.confidence}%</span>` : ''}
          </div>
          <p style="color:var(--text-secondary);font-size:13px;margin:4px 0 0;line-height:1.5;">${a.description}</p>
          ${a.metric ? `<div style="margin-top:8px;padding:6px 12px;background:var(--hover);border-radius:6px;font-size:12px;font-weight:500;display:inline-block;">${a.metric}</div>` : ''}
        </div>
      </div>
    </div>
    ${a.action ? `<div class="alert-card-actions">
      <button class="alert-action-btn" onclick="showNotification('Azione: ${a.action}', 'info')">${a.action}</button>
      <button class="alert-action-btn resolve" onclick="this.parentElement.parentElement.style.opacity='0.5';showNotification('Alert risolto', 'success');">Segna come risolto</button>
    </div>` : ''}
  </div>`).join('');
}


