function renderScoreCard(data) {
  const c = document.getElementById('score-card-content');
  const overall = data.overall || 0;
  const grade = data.grade || getGrade(overall);
  const gradeColor = overall >= 90 ? '#10b981' : overall >= 75 ? '#3b82f6' : overall >= 60 ? '#f59e0b' : '#ef4444';
  const categories = data.categories || [];
  const labels = categories.map(c => c.name);
  const values = categories.map(c => c.score);

  c.innerHTML = `
    <div class="score-overview">
      <div class="score-total-card">
        <div class="score-total-value" style="color:${gradeColor};">${overall}</div>
        <div class="score-total-label">Score Complessivo su 100</div>
        <div class="score-total-grade" style="background:${gradeColor}15;color:${gradeColor};">Grado: ${grade}</div>
        <div style="margin-top:16px;font-size:12px;color:var(--text-secondary);text-align:center;">
          ${overall >= 85 ? 'Eccellente posizionamento competitivo' : overall >= 70 ? 'Buon posizionamento, margini di miglioramento' : 'Necessari interventi di miglioramento'}
        </div>
      </div>
      <div class="radar-chart-container"><canvas id="scoreRadarChart" width="400" height="400"></canvas></div>
    </div>
    <div class="score-detail-grid">
      ${categories.map(cat => {
        const color = cat.score >= 85 ? '#10b981' : cat.score >= 70 ? '#3b82f6' : cat.score >= 55 ? '#f59e0b' : '#ef4444';
        return `<div class="score-detail-card">
          <div class="score-detail-header">
            <span class="score-detail-title">${cat.name}</span>
            <span class="score-detail-value" style="color:${color};">${cat.score}/100</span>
          </div>
          <div class="score-detail-bar">
            <div class="score-detail-bar-fill" style="width:${cat.score}%;background:${color};"></div>
          </div>
          ${cat.items ? `<div style="margin-top:12px;">${cat.items.map(item => `<div style="font-size:12px;color:var(--text-secondary);padding:3px 0;">${item}</div>`).join('')}</div>` : ''}
        </div>`;
      }).join('')}
    </div>`;
  setTimeout(() => drawRadarChart('scoreRadarChart', labels, values), 100);
}

function getGrade(score) {
  if (score >= 95) return 'A+';
  if (score >= 90) return 'A';
  if (score >= 85) return 'A-';
  if (score >= 80) return 'B+';
  if (score >= 75) return 'B';
  if (score >= 70) return 'B-';
  if (score >= 65) return 'C+';
  if (score >= 60) return 'C';
  return 'D';
}

