window.generateMonitoringToken = generateMonitoringToken;
window.deleteMonitoringToken = deleteMonitoringToken;
window.loadArt8Report = loadArt8Report;
window.downloadArt8Pdf = downloadArt8Pdf;
window.initArt8ReportPage = initArt8ReportPage;
window.loadMonitoringTokens = loadMonitoringTokens;

