function getFeatherIcon(name) {
  return FEATHER_ICONS[name] || FEATHER_ICONS['package'];
}

const MP_CATEGORY_COLORS = {
  modulo: { bg: 'rgba(0,102,204,0.08)', text: '#0066CC', label: 'Modulo' },
  servizio: { bg: 'rgba(139,92,246,0.08)', text: '#8b5cf6', label: 'Servizio' },
  licenza: { bg: 'rgba(245,158,11,0.08)', text: '#d97706', label: 'Licenza' },
  addon: { bg: 'rgba(239,68,68,0.08)', text: '#ef4444', label: 'Add-on' },
  pacchetto: { bg: 'rgba(0,166,81,0.08)', text: '#00A651', label: 'Pacchetto' }
};

async function loadMarketplace(view) {
  const contentArea = document.getElementById('mp-content-area');
  const purchasesArea = document.getElementById('mp-purchases-section');
  const headerArea = document.getElementById('mp-header');
  
  if (view === 'my-purchases') {
    if (contentArea) contentArea.classList.add('hidden');
    if (headerArea) headerArea.classList.add('hidden');
    if (purchasesArea) purchasesArea.classList.remove('hidden');
    await loadMyPurchases();
    return;
  }
  
  if (contentArea) contentArea.classList.remove('hidden');
  if (headerArea) headerArea.classList.remove('hidden');
  if (purchasesArea) purchasesArea.classList.add('hidden');
  
  try {
    const res = await adminFetch('/api/marketplace');
    _marketplaceItems = await res.json();
    renderMarketplace();
  } catch (err) {
    console.error('Error loading marketplace:', err);
    const grid = document.getElementById('mp-items-grid');
    if (grid) grid.innerHTML = '<div class="mp-empty-state"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="1.5"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg><h3>Errore di caricamento</h3><p>Impossibile caricare il catalogo. Riprova tra qualche istante.</p></div>';
  }
}

function filterMarketplaceCategory(cat) {
  _marketplaceFilter = cat;
  document.querySelectorAll('.mp-tab').forEach(t => t.classList.toggle('active', t.dataset.cat === cat));
  renderMarketplace();
}

function formatMpPrice(cents) {
  if (!cents && cents !== 0) return '0';
  const euros = cents / 100;
  if (euros >= 1000) return euros.toLocaleString('it-IT', { maximumFractionDigits: 0 });
  if (Number.isInteger(euros)) return euros.toString();
  return euros.toLocaleString('it-IT', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function renderMarketplace() {
  const allItems = _marketplaceFilter === 'all' ? _marketplaceItems : _marketplaceItems.filter(i => i.category === _marketplaceFilter);
  const featured = _marketplaceFilter === 'all' ? allItems.filter(i => i.isFeatured) : [];
  
  const featuredEl = document.getElementById('mp-featured-section');
  if (featured.length > 0) {
    const f = featured[0];
    const cat = MP_CATEGORY_COLORS[f.category] || MP_CATEGORY_COLORS.modulo;
    const priceText = f.billingType === 'one_time' 
      ? `${formatMpPrice(f.priceOneTime)}<span class="mp-hero-price-unit">&euro; una tantum</span>`
      : `${formatMpPrice(f.priceMonthly)}<span class="mp-hero-price-unit">&euro;/mese</span>`;
    
    featuredEl.innerHTML = `
      <div class="mp-hero">
        <div class="mp-hero-bg"><div class="mp-hero-circle mp-hero-c1"></div><div class="mp-hero-circle mp-hero-c2"></div><div class="mp-hero-circle mp-hero-c3"></div></div>
        <div class="mp-hero-body">
          <div class="mp-hero-content">
            <div class="mp-hero-meta">
              ${f.badgeText ? `<span class="mp-hero-badge">${f.badgeText}</span>` : ''}
              <span class="mp-hero-cat">${cat.label}</span>
            </div>
            <h2 class="mp-hero-title">${f.name}</h2>
            <p class="mp-hero-desc">${f.longDescription || f.description}</p>
            <div class="mp-hero-pricing">
              <div class="mp-hero-price">Da ${priceText}</div>
              ${f.trialDays > 0 ? `<div class="mp-hero-trial"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg> Prova gratuita ${f.trialDays} giorni</div>` : ''}
            </div>
          </div>
          <div class="mp-hero-actions">
            ${f.isOwned 
              ? '<div class="mp-hero-owned"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Gia Attivo</div>'
              : `<button class="mp-hero-cta" onclick="openMarketplaceDetail('${f.id}')">${f.trialDays > 0 ? 'Inizia Prova Gratuita' : 'Scopri di piu'}<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="margin-left:6px"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></button>`
            }
          </div>
        </div>
      </div>
    `;
    featuredEl.classList.remove('hidden');
  } else {
    featuredEl.classList.add('hidden');
  }
  
  const grid = document.getElementById('mp-items-grid');
  if (allItems.length === 0) {
    grid.innerHTML = '<div class="mp-empty-state"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="1.5"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 0 1-8 0"/></svg><h3>Nessun elemento</h3><p>Nessun elemento trovato in questa categoria.</p></div>';
    return;
  }

  let html = '';
  if (_marketplaceFilter === 'all') {
    const catOrder = ['modulo', 'servizio', 'licenza', 'addon', 'pacchetto'];
    const grouped = {};
    allItems.forEach(item => {
      if (!grouped[item.category]) grouped[item.category] = [];
      grouped[item.category].push(item);
    });
    catOrder.forEach(catKey => {
      const catItems = grouped[catKey];
      if (!catItems || catItems.length === 0) return;
      const cat = MP_CATEGORY_COLORS[catKey] || MP_CATEGORY_COLORS.modulo;
      html += `<div class="mp-cat-group">
        <div class="mp-cat-group-hdr">
          <div class="mp-cat-group-dot" style="background:${cat.text}"></div>
          <h3 class="mp-cat-group-title">${cat.label}</h3>
          <span class="mp-cat-group-count">${catItems.length}</span>
        </div>
        <div class="mp-cards-row">${catItems.map(item => renderMpCard(item)).join('')}</div>
      </div>`;
    });
  } else {
    html = `<div class="mp-cards-row">${allItems.map(item => renderMpCard(item)).join('')}</div>`;
  }
  
  grid.innerHTML = html;
}

function renderMpCard(item) {
  const cat = MP_CATEGORY_COLORS[item.category] || MP_CATEGORY_COLORS.modulo;
  const features = Array.isArray(item.features) ? item.features.slice(0, 3) : [];
  
  let priceHtml = '';
  if (item.billingType === 'one_time') {
    priceHtml = `<span class="mp-card-amount">${formatMpPrice(item.priceOneTime)}&euro;</span><span class="mp-card-period"> una tantum</span>`;
  } else {
    priceHtml = `<span class="mp-card-amount">${formatMpPrice(item.priceMonthly)}&euro;</span><span class="mp-card-period">/mese</span>`;
  }
  
  let actionHtml = '';
  if (item.isOwned) {
    actionHtml = '<button class="mp-card-btn mp-card-btn-owned" onclick="event.stopPropagation()"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Attivo</button>';
  } else if (item.trialDays > 0) {
    actionHtml = `<button class="mp-card-btn mp-card-btn-trial" onclick="event.stopPropagation(); openMarketplaceDetail('${item.id}')">Prova Gratis</button>`;
  } else {
    actionHtml = `<button class="mp-card-btn mp-card-btn-buy" onclick="event.stopPropagation(); openMarketplaceDetail('${item.id}')">Dettagli</button>`;
  }
  
  return `
    <div class="mp-card ${item.isOwned ? 'mp-card-active' : ''}" onclick="openMarketplaceDetail('${item.id}')">
      ${item.badgeText && !item.isOwned ? `<div class="mp-card-badge" style="background:${item.badgeColor || cat.text}">${item.badgeText}</div>` : ''}
      ${item.isOwned ? `<div class="mp-card-owned-check"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="3"><polyline points="20 6 9 17 4 12"/></svg></div>` : ''}
      <div class="mp-card-top">
        <div class="mp-card-icon" style="background:${cat.bg};color:${cat.text}">${getFeatherIcon(item.icon)}</div>
        <div class="mp-card-title-group">
          <div class="mp-card-name">${item.name}</div>
          <div class="mp-card-cat" style="color:${cat.text}">${cat.label.toUpperCase()}</div>
        </div>
      </div>
      <p class="mp-card-desc">${item.description || ''}</p>
      <div class="mp-card-features">
        ${features.map(f => `<span class="mp-card-feat"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="${cat.text}" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>${f}</span>`).join('')}
      </div>
      <div class="mp-card-bottom">
        <div class="mp-card-price">${priceHtml}</div>
        ${actionHtml}
      </div>
      ${item.trialDays > 0 && !item.isOwned ? `<div class="mp-card-trial-note"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg> ${item.trialDays} giorni gratis</div>` : ''}
    </div>
  `;
}

function openMarketplaceDetail(itemId) {
  const item = _marketplaceItems.find(i => i.id === itemId);
  if (!item) return;
  const cat = MP_CATEGORY_COLORS[item.category] || MP_CATEGORY_COLORS.modulo;
  const features = Array.isArray(item.features) ? item.features : [];
  
  let overlay = document.getElementById('mp-detail-overlay');
  if (!overlay) { overlay = document.createElement('div'); overlay.id = 'mp-detail-overlay'; document.body.appendChild(overlay); }
  
  let pricingHtml = '';
  if (item.billingType === 'one_time') {
    pricingHtml = `<div class="mp-modal-pricing"><div class="mp-modal-price-card mp-modal-price-selected"><div class="mp-modal-price-label">Pagamento Unico</div><div class="mp-modal-price-amount">${formatMpPrice(item.priceOneTime)}<span>&euro;</span></div><div class="mp-modal-price-sub">una tantum</div></div></div>`;
  } else {
    const savings = item.priceMonthly > 0 ? Math.round(((item.priceMonthly * 12 - item.priceYearly) / (item.priceMonthly * 12)) * 100) : 0;
    pricingHtml = `<div class="mp-modal-pricing">
      <div class="mp-modal-price-card mp-modal-price-selected" data-plan="monthly" onclick="selectMpPlan('monthly')"><div class="mp-modal-price-label">Mensile</div><div class="mp-modal-price-amount">${formatMpPrice(item.priceMonthly)}<span>&euro;</span></div><div class="mp-modal-price-sub">al mese</div></div>
      <div class="mp-modal-price-card" data-plan="yearly" onclick="selectMpPlan('yearly')">${savings > 0 ? `<div class="mp-modal-price-save">-${savings}%</div>` : ''}<div class="mp-modal-price-label">Annuale</div><div class="mp-modal-price-amount">${formatMpPrice(item.priceYearly)}<span>&euro;</span></div><div class="mp-modal-price-sub">${formatMpPrice(Math.round(item.priceYearly / 12))}&euro;/mese</div></div>
    </div>`;
  }
  
  overlay.className = 'mp-detail-overlay';
  overlay.innerHTML = `
    <div class="mp-detail-modal" onclick="event.stopPropagation()">
      <button class="mp-detail-close" onclick="closeMpDetail()"><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button>
      <div class="mp-detail-header" style="border-left:4px solid ${cat.text};">
        <div class="mp-detail-icon" style="background:${cat.bg};color:${cat.text}">${getFeatherIcon(item.icon)}</div>
        <div><h2 class="mp-detail-title">${item.name}</h2><span class="mp-detail-cat" style="color:${cat.text};background:${cat.bg}">${cat.label}${item.badgeText ? ' &middot; ' + item.badgeText : ''}</span></div>
      </div>
      <p class="mp-detail-desc">${item.longDescription || item.description || ''}</p>
      ${item.trialDays > 0 ? `<div class="mp-detail-trial-banner"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg> Prova gratuita di <strong>${item.trialDays} giorni</strong> inclusa. Nessun addebito fino alla scadenza.</div>` : ''}
      ${features.length > 0 ? `<div class="mp-detail-features"><h4>Funzionalita incluse</h4><ul>${features.map(f => `<li><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#00A651" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg>${f}</li>`).join('')}</ul></div>` : ''}
      ${pricingHtml}
      <div class="mp-detail-actions">
        <button class="mp-detail-cancel" onclick="closeMpDetail()">Chiudi</button>
        ${item.isOwned 
          ? '<button class="mp-detail-owned-btn"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Gia Attivo</button>'
          : `<button class="mp-detail-buy-btn" onclick="purchaseMarketplaceItem('${item.moduleKey}', '${item.billingType}')">${item.trialDays > 0 ? 'Inizia Prova Gratuita' : 'Acquista Ora'}</button>`
        }
      </div>
    </div>
  `;
  overlay.style.display = 'flex';
  overlay.onclick = closeMpDetail;
  document.body.style.overflow = 'hidden';
}

window._mpSelectedPlan = 'monthly';
function selectMpPlan(plan) {
  window._mpSelectedPlan = plan;
  document.querySelectorAll('.mp-modal-price-card').forEach(el => el.classList.toggle('mp-modal-price-selected', el.dataset.plan === plan));
}

function closeMpDetail() {
  const overlay = document.getElementById('mp-detail-overlay');
  if (overlay) overlay.style.display = 'none';
  document.body.style.overflow = '';
}

async function purchaseMarketplaceItem(moduleKey, billingType) {
  const item = _marketplaceItems.find(i => i.moduleKey === moduleKey);
  if (!item) return;
  
  if (item.trialDays > 0 && !item.subscription) {
    try {
      const res = await adminFetch('/api/marketplace/activate-trial', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ moduleKey })
      });
      const data = await res.json();
      if (data.success) {
        closeMpDetail();
        showNotification(`Prova gratuita di ${item.trialDays} giorni attivata per ${item.name}!`, 'success');
        loadMarketplace();
      } else {
        showNotification(data.error || 'Errore nell\'attivazione della prova', 'error');
      }
    } catch (err) { console.error('Trial error:', err); showNotification('Errore nell\'attivazione della prova', 'error'); }
    return;
  }

  const plan = document.querySelector('.mp-modal-price-selected')?.dataset?.plan || 'monthly';
  try {
    const res = await adminFetch('/api/marketplace/purchase', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ moduleKey, billingPeriod: plan })
    });
    const data = await res.json();
    if (data.success) {
      closeMpDetail();
      showNotification(data.message || 'Acquisto completato con successo!', 'success');
      loadMarketplace();
    } else {
      showNotification(data.error || 'Errore durante l\'acquisto', 'error');
    }
  } catch (err) { console.error('Purchase error:', err); showNotification('Errore durante l\'acquisto', 'error'); }
}

async function loadMyPurchases() {
  try {
    const res = await adminFetch('/api/marketplace/my-purchases-detailed');
    const data = await res.json();
    const container = document.getElementById('mp-purchases-section');
    
    if (data.subscriptions.length === 0 && data.payments.length === 0) {
      container.innerHTML = `<div class="mp-empty-state" style="padding:80px 20px;"><svg width="56" height="56" viewBox="0 0 24 24" fill="none" stroke="#cbd5e1" stroke-width="1.5"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 0 1-8 0"/></svg><h3>Nessun acquisto</h3><p>Non hai ancora acquistato nessun modulo o servizio.</p><button class="mp-card-btn mp-card-btn-buy" onclick="loadMarketplace()" style="margin-top:16px;padding:10px 24px;">Esplora il Marketplace</button></div>`;
      return;
    }
    
    let html = '<div class="mpa-wrapper">';
    html += '<div class="mpa-header"><button class="mp-back-btn" onclick="loadMarketplace()"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg> Torna al Marketplace</button><h2>I Miei Acquisti</h2></div>';

    const activeSubs = data.subscriptions.filter(s => s.status === 'active' || s.status === 'trialing');
    const otherSubs = data.subscriptions.filter(s => s.status !== 'active' && s.status !== 'trialing');

    // Stats summary
    const totalActive = activeSubs.length;
    const totalTrialing = data.subscriptions.filter(s => s.status === 'trialing').length;
    const totalSpent = data.payments.filter(p => p.status === 'succeeded').reduce((s, p) => s + p.amount, 0);
    html += `<div class="mpa-stats">
      <div class="mpa-stat"><div class="mpa-stat-num">${totalActive}</div><div class="mpa-stat-lbl">Moduli Attivi</div></div>
      <div class="mpa-stat"><div class="mpa-stat-num">${totalTrialing}</div><div class="mpa-stat-lbl">Trial Attivi</div></div>
      <div class="mpa-stat"><div class="mpa-stat-num">${formatMpPrice(totalSpent)}&euro;</div><div class="mpa-stat-lbl">Spesa Totale</div></div>
      <div class="mpa-stat"><div class="mpa-stat-num">${data.payments.length}</div><div class="mpa-stat-lbl">Transazioni</div></div>
    </div>`;

    // Active subscriptions
    if (activeSubs.length > 0) {
      html += '<div class="mpa-section"><h3><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#00A651" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg> Abbonamenti Attivi</h3><div class="mpa-cards">';
      activeSubs.forEach(sub => {
        const mod = sub.module;
        const cat = MP_CATEGORY_COLORS[mod?.category || 'modulo'] || MP_CATEGORY_COLORS.modulo;
        const isTrial = sub.status === 'trialing';
        const daysLeft = sub.daysRemaining;
        const periodEnd = sub.currentPeriodEnd ? new Date(sub.currentPeriodEnd).toLocaleDateString('it-IT') : '-';
        const trialEnd = sub.trialEnd ? new Date(sub.trialEnd).toLocaleDateString('it-IT') : '-';
        
        html += `<div class="mpa-card">
          <div class="mpa-card-top" style="border-left:4px solid ${cat.text}">
            <div class="mpa-card-icon" style="background:${cat.bg};color:${cat.text}">${getFeatherIcon(mod?.icon || 'package')}</div>
            <div class="mpa-card-info">
              <h4>${mod?.name || sub.moduleKey}</h4>
              <span class="mpa-badge ${isTrial ? 'mpa-badge-trial' : 'mpa-badge-active'}">${isTrial ? 'PROVA GRATUITA' : 'ATTIVO'}</span>
            </div>
          </div>`;
        
        if (isTrial && daysLeft !== null) {
          const pct = sub.module?.trialDays ? Math.max(0, Math.min(100, (daysLeft / sub.module.trialDays) * 100)) : 50;
          const barColor = daysLeft <= 3 ? '#ef4444' : daysLeft <= 7 ? '#f59e0b' : '#00A651';
          html += `<div class="mpa-trial-countdown">
            <div class="mpa-trial-bar"><div class="mpa-trial-fill" style="width:${pct}%;background:${barColor}"></div></div>
            <div class="mpa-trial-info"><span>${daysLeft} giorn${daysLeft === 1 ? 'o' : 'i'} rimanent${daysLeft === 1 ? 'e' : 'i'}</span><span>Scade: ${trialEnd}</span></div>
          </div>`;
        } else {
          html += `<div class="mpa-card-details"><span>Piano: ${sub.billingPeriod === 'yearly' ? 'Annuale' : 'Mensile'}</span><span>Rinnovo: ${periodEnd}</span>${sub.amount ? `<span>Importo: ${formatMpPrice(sub.amount)}&euro;/${sub.billingPeriod === 'yearly' ? 'anno' : 'mese'}</span>` : ''}</div>`;
        }

        html += `<div class="mpa-card-actions">`;
        if (isTrial) {
          html += `<button class="mpa-btn mpa-btn-upgrade" onclick="upgradeTrial('${sub.moduleKey}')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="17 11 12 6 7 11"/><line x1="12" y1="18" x2="12" y2="6"/></svg> Passa al Piano Completo</button>`;
        }
        html += `<button class="mpa-btn mpa-btn-cancel" onclick="cancelSubscription('${sub.id}', '${mod?.name || sub.moduleKey}')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg> ${isTrial ? 'Termina Prova' : 'Cancella'}</button>`;
        html += '</div></div>';
      });
      html += '</div></div>';
    }

    // Cancelled/expired
    if (otherSubs.length > 0) {
      html += '<div class="mpa-section"><h3><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#94a3b8" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg> Storico Abbonamenti</h3><div class="mpa-history-list">';
      otherSubs.forEach(sub => {
        const statusMap = { cancelled: 'Cancellato', trial_expired: 'Trial Scaduto', past_due: 'Scaduto' };
        const statusLabel = statusMap[sub.status] || sub.status;
        const date = new Date(sub.updatedAt || sub.createdAt).toLocaleDateString('it-IT');
        html += `<div class="mpa-history-row"><div class="mpa-history-info"><strong>${sub.moduleName || sub.moduleKey}</strong><span>${date}</span></div><span class="mpa-badge mpa-badge-inactive">${statusLabel}</span></div>`;
      });
      html += '</div></div>';
    }

    // Payment history with invoice download
    if (data.payments.length > 0) {
      html += '<div class="mpa-section"><h3><svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#0066CC" stroke-width="2"><rect x="1" y="4" width="22" height="16" rx="2" ry="2"/><line x1="1" y1="10" x2="23" y2="10"/></svg> Storico Pagamenti</h3>';
      html += '<div class="mpa-payments-table"><div class="mpa-pay-header"><span>Descrizione</span><span>Data</span><span>Importo</span><span>Stato</span><span>Fattura</span></div>';
      data.payments.forEach(p => {
        const date = new Date(p.createdAt).toLocaleDateString('it-IT');
        const statusClass = p.status === 'succeeded' ? 'active' : (p.status === 'refunded' ? 'inactive' : 'trial');
        const statusLabel = { succeeded: 'Pagato', failed: 'Fallito', pending: 'In attesa', refunded: 'Rimborsato' }[p.status] || p.status;
        html += `<div class="mpa-pay-row">
          <span class="mpa-pay-desc">${p.description || p.moduleName || p.moduleKey || '-'}</span>
          <span>${date}</span>
          <span class="mpa-pay-amount">${formatMpPrice(p.amount)}&euro;</span>
          <span><span class="mpa-badge mpa-badge-${statusClass}">${statusLabel}</span></span>
          <span>${p.status === 'succeeded' ? `<button class="mpa-invoice-btn" onclick="downloadInvoice('${p.id}')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> PDF</button>` : '-'}</span>
        </div>`;
      });
      html += '</div></div>';
    }
    
    html += '</div>';
    container.innerHTML = html;
  } catch (err) { console.error('Error loading purchases:', err); }
}

async function cancelSubscription(subId, name) {
  if (!confirm(`Sei sicuro di voler cancellare "${name}"? Il modulo verra disattivato.`)) return;
  try {
    const res = await adminFetch('/api/marketplace/cancel-subscription', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ subscriptionId: subId })
    });
    const data = await res.json();
    if (data.success) {
      showNotification('Abbonamento cancellato con successo', 'success');
      loadMyPurchases();
    } else {
      showNotification(data.error || 'Errore nella cancellazione', 'error');
    }
  } catch (err) { showNotification('Errore nella cancellazione', 'error'); }
}

async function upgradeTrial(moduleKey) {
  const item = _marketplaceItems.find(i => i.moduleKey === moduleKey);
  if (item) openMarketplaceDetail(item.id);
}

function downloadInvoice(paymentId) {
  window.open('/api/marketplace/invoice/' + paymentId, '_blank');
}




// ============================================================================
// MARKETPLACE ANALYTICS (Super Admin)
// ============================================================================

let _mktRevenueChart = null;
let _mktSubsChart = null;
let _mktCatChart = null;
let _mktTopChart = null;

async function loadMarketplaceAnalytics() {
  const container = document.getElementById('mkt-analytics-content');
  if (!container) return;
  container.innerHTML = '<div style="text-align:center;padding:60px 20px;color:var(--text-secondary);">Caricamento analytics...</div>';
  
  try {
    const res = await adminFetch('/api/saas/marketplace-analytics');
    const data = await res.json();
    const s = data.summary;
    
    const growthClass = s.revenueGrowth > 0 ? 'pos' : (s.revenueGrowth < 0 ? 'neg' : 'neu');
    const growthSign = s.revenueGrowth > 0 ? '+' : '';
    
    let html = `
      <div class="mkt-a-stats">
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${formatMpPrice(s.totalRevenue)}&euro;</div>
          <div class="mkt-a-stat-lbl">Revenue Totale</div>
          <span class="mkt-a-stat-chg ${growthClass}">${growthSign}${s.revenueGrowth}% vs mese prec.</span>
        </div>
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${formatMpPrice(s.mrr)}&euro;</div>
          <div class="mkt-a-stat-lbl">MRR (Monthly Recurring)</div>
          <span class="mkt-a-stat-chg neu">ARR: ${formatMpPrice(s.arr)}&euro;</span>
        </div>
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${s.activeSubscriptions}</div>
          <div class="mkt-a-stat-lbl">Abbonamenti Attivi</div>
          <span class="mkt-a-stat-chg neu">${s.trialSubscriptions} trial attivi</span>
        </div>
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${s.trialConversionRate}%</div>
          <div class="mkt-a-stat-lbl">Conversione Trial</div>
          <span class="mkt-a-stat-chg ${s.trialConversionRate >= 50 ? 'pos' : (s.trialConversionRate >= 25 ? 'neu' : 'neg')}">${s.payingOrganizations}/${s.totalOrganizations} org paganti</span>
        </div>
      </div>
      
      <div class="mkt-a-stats" style="grid-template-columns: repeat(3, 1fr);">
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${formatMpPrice(s.revenueThisMonth)}&euro;</div>
          <div class="mkt-a-stat-lbl">Revenue Questo Mese</div>
        </div>
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${s.totalItems}</div>
          <div class="mkt-a-stat-lbl">Elementi Catalogo</div>
          <span class="mkt-a-stat-chg neu">${s.activeItems} attivi</span>
        </div>
        <div class="mkt-a-stat">
          <div class="mkt-a-stat-val">${s.cancelledSubscriptions}</div>
          <div class="mkt-a-stat-lbl">Cancellati</div>
          <span class="mkt-a-stat-chg ${s.cancelledSubscriptions === 0 ? 'pos' : 'neg'}">churn</span>
        </div>
      </div>
      
      <div class="mkt-a-charts">
        <div class="mkt-a-chart-card"><h4>Revenue Mensile</h4><canvas id="mkt-revenue-chart"></canvas></div>
        <div class="mkt-a-chart-card"><h4>Nuovi Abbonamenti per Mese</h4><canvas id="mkt-subs-chart"></canvas></div>
        <div class="mkt-a-chart-card"><h4>Revenue per Categoria</h4><canvas id="mkt-cat-chart"></canvas></div>
        <div class="mkt-a-chart-card"><h4>Moduli Piu Venduti</h4><canvas id="mkt-top-chart"></canvas></div>
      </div>`;
    
    // Recent payments table
    if (data.recentPayments && data.recentPayments.length > 0) {
      html += `<div class="mkt-a-table-wrap"><h4>Ultimi Pagamenti</h4><table class="mkt-a-tbl"><thead><tr><th>Organizzazione</th><th>Modulo</th><th>Importo</th><th>Stato</th><th>Data</th><th>Fattura</th></tr></thead><tbody>`;
      data.recentPayments.forEach(p => {
        const date = new Date(p.createdAt).toLocaleDateString('it-IT');
        html += `<tr><td>${p.orgName || '-'}</td><td>${p.moduleName || p.moduleKey || '-'}</td><td><strong>${formatMpPrice(p.amount)}&euro;</strong></td><td><span class="mpa-badge ${p.status === 'succeeded' ? 'mpa-badge-active' : 'mpa-badge-inactive'}">${p.status === 'succeeded' ? 'Pagato' : p.status}</span></td><td>${date}</td><td>${p.status === 'succeeded' ? `<button class="mpa-invoice-btn" onclick="downloadInvoice('${p.id}')"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> PDF</button>` : '-'}</td></tr>`;
      });
      html += '</tbody></table></div>';
    }
    
    container.innerHTML = html;
    
    // Render charts
    renderMktCharts(data);
  } catch (err) {
    console.error('Error loading analytics:', err);
    container.innerHTML = '<div style="text-align:center;padding:60px 20px;color:#ef4444;">Errore nel caricamento delle analytics</div>';
  }
}

function renderMktCharts(data) {
  const catColors = { modulo: '#0066CC', servizio: '#00A651', licenza: '#f59e0b', addon: '#8b5cf6', pacchetto: '#ef4444' };
  const catLabels = { modulo: 'Moduli', servizio: 'Servizi', licenza: 'Licenze', addon: 'Add-on', pacchetto: 'Pacchetti' };
  
  if (_mktRevenueChart) _mktRevenueChart.destroy();
  if (_mktSubsChart) _mktSubsChart.destroy();
  if (_mktCatChart) _mktCatChart.destroy();
  if (_mktTopChart) _mktTopChart.destroy();

  const revenueMonths = Object.keys(data.charts.revenueByMonth).sort();
  const revenueValues = revenueMonths.map(m => (data.charts.revenueByMonth[m] / 100).toFixed(2));
  const monthLabels = revenueMonths.map(m => {
    const [y, mo] = m.split('-');
    const months = ['Gen','Feb','Mar','Apr','Mag','Giu','Lug','Ago','Set','Ott','Nov','Dic'];
    return months[parseInt(mo)-1] + ' ' + y.slice(2);
  });

  const ctx1 = document.getElementById('mkt-revenue-chart');
  if (ctx1) {
    _mktRevenueChart = new Chart(ctx1, {
      type: 'bar',
      data: {
        labels: monthLabels.length ? monthLabels : ['Nessun dato'],
        datasets: [{
          label: 'Revenue',
          data: revenueValues.length ? revenueValues : [0],
          backgroundColor: 'rgba(0,102,204,0.7)',
          borderRadius: 6,
          borderSkipped: false,
        }]
      },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { callback: v => v + ' EUR' } } } }
    });
  }

  const subsMonths = Object.keys(data.charts.subsByMonth).sort();
  const subsValues = subsMonths.map(m => data.charts.subsByMonth[m]);
  const subsLabels = subsMonths.map(m => {
    const [y, mo] = m.split('-');
    const months = ['Gen','Feb','Mar','Apr','Mag','Giu','Lug','Ago','Set','Ott','Nov','Dic'];
    return months[parseInt(mo)-1] + ' ' + y.slice(2);
  });

  const ctx2 = document.getElementById('mkt-subs-chart');
  if (ctx2) {
    _mktSubsChart = new Chart(ctx2, {
      type: 'line',
      data: {
        labels: subsLabels.length ? subsLabels : ['Nessun dato'],
        datasets: [{
          label: 'Nuovi Abbonamenti',
          data: subsValues.length ? subsValues : [0],
          borderColor: '#00A651',
          backgroundColor: 'rgba(0,166,81,0.1)',
          fill: true,
          tension: 0.3,
          pointRadius: 4,
          pointBackgroundColor: '#00A651',
        }]
      },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { stepSize: 1 } } } }
    });
  }

  const catKeys = Object.keys(data.charts.revenueByCategory);
  const catValues = catKeys.map(k => (data.charts.revenueByCategory[k] / 100).toFixed(2));
  const catBgColors = catKeys.map(k => catColors[k] || '#94a3b8');
  const catLabelNames = catKeys.map(k => catLabels[k] || k);

  const ctx3 = document.getElementById('mkt-cat-chart');
  if (ctx3) {
    _mktCatChart = new Chart(ctx3, {
      type: 'doughnut',
      data: {
        labels: catLabelNames.length ? catLabelNames : ['Nessun dato'],
        datasets: [{
          data: catValues.length ? catValues : [1],
          backgroundColor: catBgColors.length ? catBgColors : ['#e2e8f0'],
          borderWidth: 2,
          borderColor: '#fff',
        }]
      },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { boxWidth: 12, padding: 12, font: { size: 11 } } } } }
    });
  }

  const topModules = data.charts.topModules || [];
  const ctx4 = document.getElementById('mkt-top-chart');
  if (ctx4) {
    _mktTopChart = new Chart(ctx4, {
      type: 'bar',
      data: {
        labels: topModules.length ? topModules.map(m => m.name) : ['Nessun dato'],
        datasets: [{
          label: 'Abbonamenti',
          data: topModules.length ? topModules.map(m => m.count) : [0],
          backgroundColor: topModules.map(m => catColors[m.category] || '#94a3b8'),
          borderRadius: 6,
          borderSkipped: false,
        }]
      },
      options: {
        responsive: true, maintainAspectRatio: false, indexAxis: 'y',
        plugins: { legend: { display: false } },
        scales: { x: { beginAtZero: true, ticks: { stepSize: 1 } } }
      }
    });
  }
}
// ============================================================================
// MARKETPLACE MANAGEMENT (Super Admin)
// ============================================================================

let _mpmItems = [];

async function loadMarketplaceManage() {
  try {
    const [itemsRes, statsRes] = await Promise.all([
      adminFetch('/api/saas/marketplace-items'),
      adminFetch('/api/saas/marketplace-stats')
    ]);
    _mpmItems = await itemsRes.json();
    const stats = await statsRes.json();
    
    // Stats row
    const statsRow = document.getElementById('mpm-stats-row');
    statsRow.innerHTML = `
      <div class="mpm-stat-card">
        <div class="mpm-stat-value">${stats.totalItems}</div>
        <div class="mpm-stat-label">Elementi Totali</div>
      </div>
      <div class="mpm-stat-card">
        <div class="mpm-stat-value">${stats.activeItems}</div>
        <div class="mpm-stat-label">Attivi</div>
      </div>
      <div class="mpm-stat-card">
        <div class="mpm-stat-value">${stats.activeSubscriptions}</div>
        <div class="mpm-stat-label">Abbonamenti Attivi</div>
      </div>
      <div class="mpm-stat-card">
        <div class="mpm-stat-value">${(stats.totalRevenue / 100).toFixed(0)}&euro;</div>
        <div class="mpm-stat-label">Ricavi Totali</div>
      </div>
      <div class="mpm-stat-card">
        <div class="mpm-stat-value">${Object.keys(stats.categories).length}</div>
        <div class="mpm-stat-label">Categorie</div>
      </div>
    `;
    
    // Filter
    const catFilter = document.getElementById('mpm-cat-filter')?.value || '';
    const statusFilter = document.getElementById('mpm-status-filter')?.value || '';
    let filtered = _mpmItems;
    if (catFilter) filtered = filtered.filter(i => i.category === catFilter);
    if (statusFilter === 'active') filtered = filtered.filter(i => i.isActive);
    if (statusFilter === 'inactive') filtered = filtered.filter(i => !i.isActive);
    if (statusFilter === 'featured') filtered = filtered.filter(i => i.isFeatured);
    
    // Table
    const table = document.getElementById('mpm-items-table');
    table.innerHTML = `
      <table class="mpm-table">
        <thead>
          <tr>
            <th>Elemento</th>
            <th>Categoria</th>
            <th>Prezzo</th>
            <th>Tipo</th>
            <th>Stato</th>
            <th>Ordine</th>
            <th>Azioni</th>
          </tr>
        </thead>
        <tbody>
          ${filtered.map(item => {
            const cat = MP_CATEGORY_COLORS[item.category] || MP_CATEGORY_COLORS.modulo;
            let priceStr = '';
            if (item.billingType === 'one_time') {
              priceStr = `${(item.priceOneTime / 100).toFixed(0)}&euro; (una tantum)`;
            } else {
              priceStr = `${(item.priceMonthly / 100).toFixed(0)}&euro;/mese`;
            }
            return `
              <tr>
                <td>
                  <div class="mpm-item-name">
                    <div class="mpm-item-icon" style="background:${cat.bg};color:${cat.text}">
                      ${getFeatherIcon(item.icon)}
                    </div>
                    <div>
                      <div style="font-weight:600;">${item.name}</div>
                      <div style="font-size:11px;color:var(--text-secondary);">${item.moduleKey}</div>
                    </div>
                  </div>
                </td>
                <td><span class="mpm-cat-badge" style="background:${cat.bg};color:${cat.text}">${cat.label}</span></td>
                <td>${priceStr}</td>
                <td style="font-size:12px;">${item.billingType === 'recurring' ? 'Ricorrente' : item.billingType === 'one_time' ? 'Una tantum' : 'Custom'}</td>
                <td>
                  <span class="mpm-status-dot" style="background:${item.isActive ? '#00A651' : '#dc2626'}"></span>
                  ${item.isActive ? 'Attivo' : 'Disattivo'}
                  ${item.isFeatured ? ' <span style="color:#f59e0b;font-size:11px;font-weight:600;">IN EVIDENZA</span>' : ''}
                </td>
                <td>${item.sortOrder}</td>
                <td>
                  <div class="mpm-actions">
                    <button class="mpm-action-btn" onclick="openMarketplaceItemModal('${item.id}')" title="Modifica">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
                    </button>
                    <button class="mpm-action-btn" onclick="toggleMarketplaceItem('${item.id}', ${!item.isActive})" title="${item.isActive ? 'Disattiva' : 'Attiva'}">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">${item.isActive ? '<path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/>' : '<circle cx="12" cy="12" r="10"/><polyline points="16 12 12 8 8 12"/><line x1="12" y1="16" x2="12" y2="8"/>'}</svg>
                    </button>
                    <button class="mpm-action-btn delete" onclick="deleteMarketplaceItem('${item.id}', '${item.name}')" title="Elimina">
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg>
                    </button>
                  </div>
                </td>
              </tr>
            `;
          }).join('')}
        </tbody>
      </table>
    `;
  } catch (err) {
    console.error('Error loading marketplace manage:', err);
  }
}

