      var orgStatusLabel = org.violationCount === 0 ? 'OK' : org.violationCount <= 3 ? 'WARN' : 'CRIT';
      var orgStatusBg = org.violationCount === 0 ? '#ECFDF5' : org.violationCount <= 3 ? '#FFFBEB' : '#FEF2F2';
      
      html += '<tr style="background:' + rowBg + ';border-bottom:1px solid #F1F5F9;">';
